import type { Challenge } from "../types";

// Department-specific role-play scenarios. Kept in a separate module from the
// general seed library for clarity. Concatenated into CHALLENGES in challenges.ts.

export const DEPARTMENT_CHALLENGES: Challenge[] = [
  // ---------------- Finance ----------------
  {"id":"FIN-1","type":"situational","category":"professional_communication","department":"finance","difficulty":2,"media":{"scene":"office_1on1","alt":{"en":"A CFO sits across a desk reviewing a forecast variance report.","de":"Ein CFO sitzt am Schreibtisch und prüft einen Bericht zur Prognoseabweichung.","es-ES":"Un director financiero revisa en su escritorio un informe de desviación del pronóstico."}},"roleCaption":{"en":"You report to the CFO","de":"Sie berichten an den CFO","es-ES":"Reportas al director financiero"},"scenario":{"en":"Your CFO calls you in. Q2 revenue came in 6% under the forecast you submitted, and she wants an answer before the leadership sync in an hour. She looks up and says: 'Walk me through what happened, and tell me whether I should trust your Q3 number.' You have 60 seconds to explain the miss without excuses and show you have it under control.","de":"Ihr CFO ruft Sie herein. Der Umsatz im Q2 lag 6 % unter Ihrer Prognose, und sie will vor dem Leitungs-Meeting in einer Stunde eine Antwort. Sie blickt auf und sagt: 'Erklären Sie mir, was passiert ist, und ob ich Ihrer Q3-Zahl trauen kann.' Sie haben 60 Sekunden, die Abweichung ohne Ausreden zu erklären und zu zeigen, dass Sie es im Griff haben.","es-ES":"Tu director financiero te llama. Los ingresos del Q2 quedaron un 6% por debajo del pronóstico que entregaste y quiere una respuesta antes de la reunión de dirección dentro de una hora. Levanta la vista y dice: 'Explícame qué pasó y dime si puedo confiar en tu cifra del Q3.' Tienes 60 segundos para explicar la desviación sin excusas y demostrar que lo tienes controlado."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Name the root cause specifically, not vaguely","de":"Die Ursache konkret benennen, nicht vage","es-ES":"Nombrar la causa raíz de forma concreta, no vaga"},{"en":"Quantify the miss and what was controllable","de":"Abweichung beziffern und das Steuerbare benennen","es-ES":"Cuantificar la desviación y lo que era controlable"},{"en":"Take ownership without making excuses","de":"Verantwortung übernehmen ohne Ausreden","es-ES":"Asumir responsabilidad sin excusas"},{"en":"Show a corrective action for Q3","de":"Korrekturmaßnahme für Q3 aufzeigen","es-ES":"Mostrar una acción correctiva para el Q3"},{"en":"State your revised confidence level clearly","de":"Das überarbeitete Vertrauensniveau klar nennen","es-ES":"Indicar tu nivel de confianza revisado con claridad"}],"rubric":{"content":{"strong":"Pinpoints a specific root cause, quantifies controllable vs. external factors, owns the miss, and gives a concrete Q3 correction with a credible confidence statement.","adequate":"Explains the miss and offers a fix but is vague on root cause or confidence level.","weak":"Deflects blame, gives no quantification, or offers no corrective action."},"delivery":{"strong":"Calm, steady, and direct; sounds accountable and in control under pressure.","adequate":"Mostly composed but occasionally hesitant or defensive.","weak":"Defensive, rambling, or visibly rattled."},"time":{"strong":"Lands the full answer within 55-65 seconds with a clear arc.","adequate":"Slightly over or under but covers the essentials.","weak":"Runs far over or stops well short, leaving the answer incomplete."}},"modelAnswer":{"en":"The miss was 6%, and four of those points came from two enterprise deals that slipped, not lost, into Q3 after procurement delays. The other two were on me: I weighted late-funnel optimism too heavily. I've already re-anchored Q3 on signed contracts plus a 20% haircut on anything still in negotiation. So yes, you can trust the Q3 number, it's deliberately conservative, and I'll flag any slippage weekly rather than at quarter-end.","de":"Die Abweichung lag bei 6 %, vier Punkte davon aus zwei Großkundengeschäften, die sich nach Beschaffungsverzögerungen ins Q3 verschoben, nicht verloren gingen. Die anderen zwei gehen auf mich: Ich habe Optimismus im späten Funnel zu stark gewichtet. Ich habe Q3 bereits auf unterschriebene Verträge plus 20 % Abschlag auf alles in Verhandlung neu verankert. Sie können der Q3-Zahl also trauen, sie ist bewusst konservativ, und ich melde jede Verschiebung wöchentlich statt erst zum Quartalsende.","es-ES":"La desviación fue del 6%, y cuatro de esos puntos vienen de dos contratos corporativos que se aplazaron al Q3 por retrasos de compras, no se perdieron. Los otros dos son responsabilidad mía: ponderé demasiado el optimismo del final del embudo. Ya he reanclado el Q3 en contratos firmados más un recorte del 20% sobre todo lo que sigue en negociación. Así que sí, puedes confiar en la cifra del Q3, es deliberadamente conservadora, y avisaré de cualquier desliz cada semana, no al cierre del trimestre."}},
  {"id":"FIN-2","type":"conflict","category":"conflict_resolution","department":"finance","difficulty":3,"media":{"scene":"exec_committee","alt":{"en":"Executives around a table debating a proposed cost-cutting target.","de":"Führungskräfte am Tisch diskutieren ein vorgeschlagenes Sparziel.","es-ES":"Directivos en torno a una mesa debaten un objetivo de recorte de costes propuesto."}},"roleCaption":{"en":"You are the Finance lead pushing back","de":"Sie sind die Finanzleitung, die Widerspruch einlegt","es-ES":"Eres el responsable de Finanzas que objeta"},"scenario":{"en":"In the exec committee, the COO demands an across-the-board 15% cost cut by next quarter, including a hiring freeze that would gut your planned systems migration. You believe a flat cut will destroy more value than it saves. The COO turns to you: 'Finance signs off on this, right?' All eyes are on you. You have 60 seconds to push back without sounding obstructive and offer a smarter path.","de":"Im Vorstandsausschuss fordert der COO eine pauschale Kostensenkung von 15 % bis zum nächsten Quartal, inklusive eines Einstellungsstopps, der Ihre geplante Systemmigration ausbremsen würde. Sie glauben, ein pauschaler Schnitt zerstört mehr Wert, als er spart. Der COO wendet sich an Sie: 'Finance stimmt dem doch zu, oder?' Alle schauen Sie an. Sie haben 60 Sekunden, um Widerspruch einzulegen, ohne blockierend zu wirken, und einen klügeren Weg aufzuzeigen.","es-ES":"En el comité ejecutivo, el director de operaciones exige un recorte de costes generalizado del 15% para el próximo trimestre, incluida una congelación de contrataciones que paralizaría tu migración de sistemas planificada. Crees que un recorte lineal destruirá más valor del que ahorra. El director de operaciones se gira hacia ti: 'Finanzas lo aprueba, ¿verdad?' Todas las miradas están en ti. Tienes 60 segundos para objetar sin parecer obstruccionista y ofrecer un camino más inteligente."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Acknowledge the goal before challenging the method","de":"Das Ziel anerkennen, bevor die Methode infrage gestellt wird","es-ES":"Reconocer el objetivo antes de cuestionar el método"},{"en":"Show where a flat cut destroys value","de":"Zeigen, wo ein pauschaler Schnitt Wert zerstört","es-ES":"Mostrar dónde un recorte lineal destruye valor"},{"en":"Propose a targeted, prioritized alternative","de":"Eine gezielte, priorisierte Alternative vorschlagen","es-ES":"Proponer una alternativa específica y priorizada"},{"en":"Quantify savings the alternative still delivers","de":"Die Einsparungen der Alternative beziffern","es-ES":"Cuantificar el ahorro que la alternativa aún logra"},{"en":"Commit to a deadline and accountability","de":"Zu Frist und Verantwortung verpflichten","es-ES":"Comprometerse con un plazo y la rendición de cuentas"}],"rubric":{"content":{"strong":"Validates the cost target, shows specifically how a flat cut harms value, proposes a prioritized alternative that still hits comparable savings, and commits to a timeline.","adequate":"Pushes back with a reasonable alternative but is light on quantification or on protecting the savings goal.","weak":"Simply refuses, offers no alternative, or capitulates without addressing the value destruction."},"delivery":{"strong":"Confident and collaborative; firm on substance, never combative, holds the room.","adequate":"Reasonably steady but slips into either deference or defensiveness at times.","weak":"Either confrontational and political or meek and easily steamrolled."},"time":{"strong":"Delivers a complete, structured case in 55-65 seconds.","adequate":"Slightly off pace but covers the core argument.","weak":"Overruns badly or stops short of proposing the alternative."}},"modelAnswer":{"en":"I'm fully behind taking 15% out, the target's right. What I'd push back on is the flat, across-the-board version. A blanket freeze stalls the systems migration that's set to save us 8% in run-rate next year, so we'd be cutting tomorrow's savings to hit today's. Instead, let me come back in 72 hours with a ranked list: protect the migration and revenue roles, take deeper cuts in discretionary spend and low-ROI vendors. I'm confident we still land 13-15%, just without breaking what compounds.","de":"Ich stehe voll hinter den 15 %, das Ziel stimmt. Wogegen ich Einspruch erhebe, ist die pauschale Variante. Ein kompletter Stopp bremst die Systemmigration aus, die uns nächstes Jahr 8 % laufende Kosten spart, wir würden also die Einsparungen von morgen für heute opfern. Stattdessen liefere ich in 72 Stunden eine priorisierte Liste: Migration und umsatzrelevante Stellen schützen, dafür tiefer bei diskretionären Ausgaben und Lieferanten mit niedrigem ROI schneiden. Ich bin sicher, wir erreichen trotzdem 13-15 %, nur ohne das zu zerstören, was sich verzinst.","es-ES":"Apoyo totalmente recortar el 15%, el objetivo es correcto. Lo que objeto es la versión lineal y generalizada. Una congelación total frena la migración de sistemas que el año que viene nos ahorrará un 8% en costes recurrentes, estaríamos sacrificando el ahorro de mañana por el de hoy. En su lugar, déjame volver en 72 horas con una lista priorizada: proteger la migración y los puestos de ingresos, y recortar más a fondo en gasto discrecional y proveedores de bajo retorno. Estoy seguro de que aun así llegamos al 13-15%, pero sin romper lo que se acumula."}},
  {"id":"FIN-3","type":"situational","category":"strategic_thinking","department":"finance","difficulty":4,"media":{"scene":"boardroom","alt":{"en":"A skeptical board and investors facing a presenter at the head of the table.","de":"Ein skeptisches Gremium und Investoren gegenüber einem Vortragenden am Kopfende.","es-ES":"Un consejo escéptico e inversores frente a un ponente en la cabecera de la mesa."}},"roleCaption":{"en":"You present results to the board","de":"Sie präsentieren dem Vorstand die Ergebnisse","es-ES":"Presentas los resultados al consejo"},"scenario":{"en":"It's the board meeting. You're presenting Q3 results: revenue flat, margin down 4 points, and you burned more cash than planned. A lead investor cuts in before you finish slide two: 'This is the third quarter you've missed. Why should we keep funding this plan instead of replacing the team?' The room goes quiet. You have 60 seconds to hold the room, own the reality, and make the case for staying the course.","de":"Es ist die Vorstandssitzung. Sie präsentieren die Q3-Zahlen: Umsatz stagniert, Marge um 4 Punkte gesunken, und Sie haben mehr Cash verbrannt als geplant. Ein Leitinvestor unterbricht bei Folie zwei: 'Das ist das dritte Quartal, das Sie verfehlen. Warum sollten wir diesen Plan weiter finanzieren, statt das Team auszutauschen?' Es wird still. Sie haben 60 Sekunden, den Raum zu halten, die Realität anzuerkennen und für das Festhalten am Kurs zu argumentieren.","es-ES":"Es la reunión del consejo. Presentas los resultados del Q3: ingresos planos, margen 4 puntos abajo y quemaste más caja de la prevista. Un inversor principal interrumpe antes de que termines la segunda diapositiva: 'Es el tercer trimestre que incumples. ¿Por qué deberíamos seguir financiando este plan en lugar de reemplazar al equipo?' La sala se queda en silencio. Tienes 60 segundos para dominar la sala, asumir la realidad y defender mantener el rumbo."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Acknowledge the pattern honestly, no spin","de":"Das Muster ehrlich anerkennen, ohne Beschönigung","es-ES":"Reconocer el patrón con honestidad, sin maquillaje"},{"en":"Separate what changed from what is working","de":"Trennen, was sich änderte, von dem, was funktioniert","es-ES":"Separar lo que cambió de lo que sí funciona"},{"en":"Point to one leading indicator that's turning","de":"Auf einen Frühindikator verweisen, der dreht","es-ES":"Señalar un indicador adelantado que está cambiando"},{"en":"Offer a concrete checkpoint and exit condition","de":"Konkreten Meilenstein und Ausstiegsbedingung anbieten","es-ES":"Ofrecer un hito concreto y una condición de salida"},{"en":"Project conviction without arrogance","de":"Überzeugung zeigen ohne Arroganz","es-ES":"Transmitir convicción sin arrogancia"}],"rubric":{"content":{"strong":"Owns the three-quarter pattern without spin, isolates the specific cause, cites a credible leading indicator that's turning, and offers a concrete checkpoint with a stated exit condition.","adequate":"Acknowledges the miss and gives some forward case but lacks a hard metric or accountability mechanism.","weak":"Spins the numbers, blames externals, or pleads for trust with no evidence or checkpoint."},"delivery":{"strong":"Composed and credible under direct attack; conviction without defensiveness, commands the room.","adequate":"Holds together but shows strain, defensiveness, or fading energy.","weak":"Rattled, evasive, or combative; loses the room."},"time":{"strong":"Delivers a tight, complete case in 55-65 seconds despite the interruption.","adequate":"Slightly off pace but covers ownership and forward case.","weak":"Overruns or collapses before making the case to stay the course."}},"modelAnswer":{"en":"You're right, three quarters, and I won't dress it up. Two of those misses traced to the same cause: we under-priced the enterprise tier. We fixed that in August. Here's what's turning: net new ARR from accounts on the new pricing is up 30% month over month, and gross margin on those cohorts is back to 71%. I'm not asking for blind faith. Give me one quarter. If new-pricing ARR doesn't clear 4 million by Q4 close, you have my full support to change course.","de":"Sie haben recht, drei Quartale, und ich beschönige nichts. Zwei dieser Verfehlungen hatten dieselbe Ursache: Wir haben das Enterprise-Segment zu niedrig bepreist. Das haben wir im August korrigiert. Was sich dreht: Neues ARR aus Kunden mit neuer Preisgestaltung wächst 30 % Monat für Monat, und die Bruttomarge dieser Kohorten liegt wieder bei 71 %. Ich bitte nicht um blindes Vertrauen. Geben Sie mir ein Quartal. Wenn das ARR aus der neuen Preisgestaltung bis Q4-Ende keine 4 Millionen erreicht, haben Sie meine volle Unterstützung für einen Kurswechsel.","es-ES":"Tiene razón, tres trimestres, y no lo voy a maquillar. Dos de esos incumplimientos vienen de la misma causa: fijamos un precio demasiado bajo en el segmento corporativo. Lo corregimos en agosto. Esto es lo que está cambiando: el ARR nuevo neto de las cuentas con el nuevo precio sube un 30% mes a mes, y el margen bruto de esas cohortes vuelve a estar en el 71%. No pido fe ciega. Denme un trimestre. Si el ARR del nuevo precio no supera los 4 millones al cierre del Q4, tendrán todo mi apoyo para cambiar de rumbo."}},
  {"id":"TEC-1","type":"situational","category":"professional_communication","department":"technology","difficulty":3,"media":{"scene":"exec_committee","alt":{"en":"A CTO addressing the executive committee about a production outage","de":"Ein CTO informiert das Führungsgremium über einen Produktionsausfall","es-ES":"Un CTO se dirige al comité ejecutivo sobre una caída de producción"}},"roleCaption":{"en":"You are the CTO updating the exec committee after a major outage.","de":"Sie sind der CTO und informieren das Führungsgremium nach einem großen Ausfall.","es-ES":"Eres el CTO informando al comité ejecutivo tras una caída importante."},"scenario":{"en":"Your payment platform was down for 47 minutes this morning during peak traffic. Thousands of checkouts failed and support is flooded. The exec committee has pulled you into the room. The CEO leans forward and asks: 'What happened, what's the customer impact, and how do we make sure this never happens again?' You have 60 seconds to answer out loud.","de":"Ihre Zahlungsplattform war heute Morgen während der Stoßzeit 47 Minuten lang ausgefallen. Tausende Bezahlvorgänge schlugen fehl und der Support ist überlastet. Das Führungsgremium hat Sie hereingerufen. Der CEO beugt sich vor und fragt: 'Was ist passiert, wie sind die Kunden betroffen und wie stellen wir sicher, dass das nie wieder vorkommt?' Sie haben 60 Sekunden für Ihre Antwort.","es-ES":"Tu plataforma de pagos estuvo caída 47 minutos esta mañana en hora punta. Miles de pagos fallaron y el soporte está saturado. El comité ejecutivo te ha llamado. El CEO se inclina y pregunta: '¿Qué pasó, cuál es el impacto en clientes y cómo evitamos que vuelva a ocurrir?' Tienes 60 segundos para responder en voz alta."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"State the root cause plainly without jargon or blame","de":"Nennen Sie die Ursache klar, ohne Fachjargon oder Schuldzuweisung","es-ES":"Expón la causa raíz con claridad, sin jerga ni culpas"},{"en":"Quantify customer and revenue impact honestly","de":"Beziffern Sie die Kunden- und Umsatzauswirkung ehrlich","es-ES":"Cuantifica el impacto en clientes e ingresos con honestidad"},{"en":"Confirm service is restored and stable now","de":"Bestätigen Sie, dass der Dienst wiederhergestellt und stabil ist","es-ES":"Confirma que el servicio ya está restablecido y estable"},{"en":"Give concrete prevention steps with owners and dates","de":"Nennen Sie konkrete Präventionsschritte mit Verantwortlichen und Terminen","es-ES":"Da medidas concretas de prevención con responsables y fechas"},{"en":"Project calm ownership, not defensiveness","de":"Strahlen Sie ruhige Verantwortung aus, keine Abwehrhaltung","es-ES":"Transmite responsabilidad serena, no actitud defensiva"}],"rubric":{"content":{"strong":"Clear root cause, honest impact numbers, restoration confirmed, and a credible prevention plan with owners and timing.","adequate":"Covers cause and impact but prevention plan is vague or missing owners/dates.","weak":"Deflects blame, omits impact, or offers no concrete path to prevention."},"delivery":{"strong":"Calm, authoritative, steady pace; owns the issue without panic or defensiveness.","adequate":"Mostly composed but some hesitation or hedging under pressure.","weak":"Anxious, defensive, or rambling; erodes executive confidence."},"time":{"strong":"Lands a complete answer within 55-60 seconds.","adequate":"Slightly over or under, covers most points.","weak":"Runs far over or stops well short, leaving key questions unanswered."}},"modelAnswer":{"en":"At 9:14 a database failover didn't trigger automatically, so payments queued and timed out for 47 minutes. Roughly 8,000 checkouts failed; we estimate 120,000 in delayed revenue, most recoverable. Service is fully restored and stable as of 10:01. Three actions: we're fixing the failover automation by Friday, adding synthetic payment alerts this week, and I'll run a blameless post-mortem and share it Monday. I own this, and customers affected are being proactively credited.","de":"Um 9:14 Uhr wurde ein Datenbank-Failover nicht automatisch ausgelöst, sodass Zahlungen 47 Minuten lang fehlschlugen. Rund 8.000 Bezahlvorgänge scheiterten; wir schätzen 120.000 an verzögertem Umsatz, größtenteils zurückholbar. Der Dienst läuft seit 10:01 Uhr wieder stabil. Drei Maßnahmen: Wir reparieren die Failover-Automatik bis Freitag, ergänzen diese Woche synthetische Zahlungsalarme, und ich führe eine schuldfreie Nachbesprechung durch und teile sie Montag. Ich übernehme die Verantwortung, betroffene Kunden werden proaktiv entschädigt.","es-ES":"A las 9:14 un failover de base de datos no se activó automáticamente, así que los pagos fallaron durante 47 minutos. Unos 8.000 pagos fallaron; estimamos 120.000 en ingresos retrasados, casi todos recuperables. El servicio está restablecido y estable desde las 10:01. Tres acciones: arreglamos la automatización del failover para el viernes, añadimos alertas sintéticas de pago esta semana, y haré un post-mortem sin culpas que comparto el lunes. Asumo la responsabilidad y compensaremos proactivamente a los clientes afectados."}},
  {"id":"TEC-2","type":"conflict","category":"conflict_resolution","department":"technology","difficulty":2,"media":{"scene":"client_meeting","alt":{"en":"An engineering leader telling sales a feature won't ship on time","de":"Eine Engineering-Leitung teilt dem Vertrieb mit, dass ein Feature nicht rechtzeitig kommt","es-ES":"Un líder de ingeniería dice a ventas que una función no llegará a tiempo"}},"roleCaption":{"en":"You are the engineering lead pushing back on an over-promised feature.","de":"Sie sind die Engineering-Leitung und widersprechen einem zu früh versprochenen Feature.","es-ES":"Eres el líder de ingeniería rechazando una función prometida en exceso."},"scenario":{"en":"Sales promised a flagship client real-time analytics dashboards 'in three weeks' to close a big deal. The work is genuinely six to eight weeks. You're now in a meeting with the VP of Sales, who says: 'The contract is signed, the client expects it. Make it happen.' All eyes turn to you. You have 60 seconds to respond out loud.","de":"Der Vertrieb hat einem wichtigen Kunden Echtzeit-Analyse-Dashboards 'in drei Wochen' versprochen, um einen großen Deal abzuschließen. Die Arbeit dauert realistisch sechs bis acht Wochen. Sie sitzen nun mit dem Vertriebs-VP zusammen, der sagt: 'Der Vertrag ist unterschrieben, der Kunde erwartet es. Machen Sie es möglich.' Alle blicken Sie an. Sie haben 60 Sekunden zu antworten.","es-ES":"Ventas prometió a un cliente clave paneles de analítica en tiempo real 'en tres semanas' para cerrar un gran acuerdo. El trabajo real es de seis a ocho semanas. Estás en una reunión con el VP de Ventas, que dice: 'El contrato está firmado, el cliente lo espera. Hazlo posible.' Todos te miran. Tienes 60 segundos para responder en voz alta."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Acknowledge the business pressure and shared goal","de":"Erkennen Sie den geschäftlichen Druck und das gemeinsame Ziel an","es-ES":"Reconoce la presión comercial y el objetivo común"},{"en":"State the real timeline with the reason behind it","de":"Nennen Sie die realistische Frist mit Begründung","es-ES":"Indica el plazo real con su justificación"},{"en":"Offer a phased delivery or MVP to bridge the gap","de":"Bieten Sie eine stufenweise Lieferung oder ein MVP an","es-ES":"Ofrece una entrega por fases o un MVP para cubrir la diferencia"},{"en":"Protect quality without sounding obstructive","de":"Schützen Sie die Qualität, ohne blockierend zu wirken","es-ES":"Protege la calidad sin parecer un obstáculo"},{"en":"Propose a joint conversation with the client","de":"Schlagen Sie ein gemeinsames Gespräch mit dem Kunden vor","es-ES":"Propón una conversación conjunta con el cliente"}],"rubric":{"content":{"strong":"Validates the goal, gives an honest timeline with rationale, and offers a concrete phased path plus a client-facing plan.","adequate":"States the timeline issue and offers some alternative but lacks a clear phased plan or client strategy.","weak":"Simply says no, or capitulates to the impossible date, setting up a worse failure."},"delivery":{"strong":"Collaborative and confident; firm on facts without being combative.","adequate":"Reasonable tone but slightly defensive or tentative.","weak":"Either aggressive and dismissive or passive and conceding."},"time":{"strong":"Complete, well-paced answer within 55-60 seconds.","adequate":"Slightly off target but covers the core.","weak":"Overruns badly or finishes abruptly without a solution."}},"modelAnswer":{"en":"I want this client to win as much as you do. The full real-time dashboard is a six-to-eight-week build because of the data pipeline, and shipping it broken in three weeks would damage the relationship more than a date change. Here's my proposal: in three weeks we deliver core dashboards on near-real-time data, then layer in true streaming by week eight. Let's get on a call together with the client this week, frame it as a phased rollout, and set expectations honestly. I'll have the plan to you by tomorrow.","de":"Ich will den Erfolg dieses Kunden genauso wie Sie. Das vollständige Echtzeit-Dashboard ist wegen der Datenpipeline ein Sechs-bis-Acht-Wochen-Projekt, und es in drei Wochen kaputt auszuliefern würde der Beziehung mehr schaden als eine Terminänderung. Mein Vorschlag: In drei Wochen liefern wir Kern-Dashboards auf Nah-Echtzeit-Daten, dann ergänzen wir echtes Streaming bis Woche acht. Lassen Sie uns diese Woche gemeinsam mit dem Kunden telefonieren, es als stufenweise Einführung darstellen und die Erwartungen ehrlich setzen. Den Plan habe ich morgen für Sie.","es-ES":"Quiero que este cliente gane tanto como tú. El panel completo en tiempo real es un proyecto de seis a ocho semanas por el pipeline de datos, y entregarlo roto en tres semanas dañaría la relación más que cambiar la fecha. Mi propuesta: en tres semanas entregamos los paneles principales con datos casi en tiempo real, y añadimos el streaming real para la semana ocho. Hagamos una llamada juntos con el cliente esta semana, planteémoslo como un despliegue por fases y fijemos expectativas con honestidad. Te paso el plan mañana."}},
  {"id":"TEC-3","type":"behavioral","category":"strategic_thinking","department":"technology","difficulty":4,"media":{"scene":"boardroom","alt":{"en":"A technology leader defending a re-platforming investment to the board","de":"Eine Technologieführung verteidigt eine Re-Platforming-Investition vor dem Vorstand","es-ES":"Un líder tecnológico defiende una inversión de re-plataforma ante el consejo"}},"roleCaption":{"en":"You are the CTO justifying a major re-platforming spend to the board.","de":"Sie sind der CTO und rechtfertigen eine große Re-Platforming-Ausgabe vor dem Vorstand.","es-ES":"Eres el CTO justificando un gran gasto de re-plataforma ante el consejo."},"scenario":{"en":"You're asking the board for 4.2 million and four quarters to re-platform a legacy monolith that's slowing every release and causing recurring incidents. A skeptical board member cuts in: 'Customers don't see any of this. Why should we spend millions and a year on plumbing instead of features that grow revenue?' The room waits. You have 60 seconds to answer out loud.","de":"Sie bitten den Vorstand um 4,2 Millionen und vier Quartale, um einen veralteten Monolithen neu aufzubauen, der jedes Release verlangsamt und wiederkehrende Störungen verursacht. Ein skeptisches Vorstandsmitglied unterbricht: 'Die Kunden sehen davon nichts. Warum sollten wir Millionen und ein Jahr in Infrastruktur stecken statt in umsatzsteigernde Features?' Der Raum wartet. Sie haben 60 Sekunden zu antworten.","es-ES":"Pides al consejo 4,2 millones y cuatro trimestres para re-plataformar un monolito heredado que ralentiza cada lanzamiento y causa incidentes recurrentes. Un consejero escéptico interrumpe: 'Los clientes no ven nada de esto. ¿Por qué gastar millones y un año en infraestructura en vez de funciones que aumentan ingresos?' La sala espera. Tienes 60 segundos para responder en voz alta."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Reframe re-platforming as a revenue and speed enabler","de":"Stellen Sie das Re-Platforming als Umsatz- und Tempo-Hebel dar","es-ES":"Replantea la re-plataforma como motor de ingresos y velocidad"},{"en":"Quantify the cost of doing nothing (incidents, slow releases)","de":"Beziffern Sie die Kosten des Nichtstuns (Störungen, langsame Releases)","es-ES":"Cuantifica el coste de no hacer nada (incidentes, lentitud)"},{"en":"Tie the investment to concrete business outcomes","de":"Verknüpfen Sie die Investition mit konkreten Geschäftsergebnissen","es-ES":"Vincula la inversión a resultados de negocio concretos"},{"en":"Show a phased, de-risked plan with checkpoints","de":"Zeigen Sie einen stufenweisen, risikoarmen Plan mit Kontrollpunkten","es-ES":"Muestra un plan por fases y con menos riesgo y puntos de control"},{"en":"Acknowledge the trade-off honestly, then justify it","de":"Erkennen Sie den Kompromiss ehrlich an und rechtfertigen Sie ihn","es-ES":"Reconoce el compromiso con honestidad y justifícalo"}],"rubric":{"content":{"strong":"Reframes as revenue/velocity, quantifies cost of inaction, ties spend to outcomes, and presents a phased de-risked plan.","adequate":"Makes a business case but light on numbers or lacks a staged, checkpointed plan.","weak":"Defends on purely technical grounds, no business framing or evidence of ROI."},"delivery":{"strong":"Composed, persuasive, executive-level framing; handles skepticism with confidence.","adequate":"Solid but occasionally slips into technical detail or hedges.","weak":"Defensive, jargon-heavy, or flustered by the challenge."},"time":{"strong":"Persuasive complete answer within 55-60 seconds.","adequate":"Slightly long or short but lands the case.","weak":"Rambles past time or stops without making the argument."}},"modelAnswer":{"en":"Fair challenge. Customers don't see the platform, but they feel it: our release cycle is three times slower than competitors, and incidents cost us roughly 1.5 million a year in lost transactions and engineering firefighting. This isn't plumbing, it's velocity. Post-migration we ship features twice as fast, which directly accelerates the revenue roadmap you care about. I'm not asking for a blank check: it's phased across four quarters, with a go/no-go checkpoint after the first, and we keep shipping customer features throughout. The cost of waiting is higher than the cost of acting.","de":"Berechtigter Einwand. Kunden sehen die Plattform nicht, aber sie spüren sie: Unser Release-Zyklus ist dreimal langsamer als bei Wettbewerbern, und Störungen kosten uns rund 1,5 Millionen pro Jahr durch verlorene Transaktionen und Krisenbewältigung. Das ist keine Infrastruktur, das ist Tempo. Nach der Migration liefern wir Features doppelt so schnell, was direkt die Umsatz-Roadmap beschleunigt, die Ihnen wichtig ist. Ich bitte nicht um einen Blankoscheck: Es läuft über vier Quartale, mit einem Go/No-Go-Punkt nach dem ersten, und wir liefern durchgehend Kundenfeatures. Warten kostet mehr als Handeln.","es-ES":"Objeción justa. Los clientes no ven la plataforma, pero la sienten: nuestro ciclo de lanzamiento es tres veces más lento que el de la competencia, y los incidentes nos cuestan unos 1,5 millones al año en transacciones perdidas y apagar fuegos. Esto no es infraestructura, es velocidad. Tras la migración lanzamos funciones el doble de rápido, lo que acelera directamente la hoja de ruta de ingresos que te importa. No pido un cheque en blanco: va por fases en cuatro trimestres, con un punto de decisión tras el primero, y seguimos entregando funciones para clientes todo el tiempo. Esperar cuesta más que actuar."}},
  {"id":"COM-1","type":"situational","category":"professional_communication","department":"commercial","difficulty":2,"media":{"scene":"client_meeting","alt":{"en":"A buyer leans back, arms crossed, across a meeting-room table during a pricing discussion.","de":"Ein Einkäufer lehnt sich mit verschränkten Armen am Besprechungstisch zurück, während über den Preis gesprochen wird.","es-ES":"Un comprador se recuesta con los brazos cruzados al otro lado de la mesa durante una conversación sobre precios."}},"roleCaption":{"en":"You're the account executive facing a price objection.","de":"Sie sind der Account Executive und stehen einem Preiseinwand gegenüber.","es-ES":"Eres el ejecutivo de cuenta que se enfrenta a una objeción de precio."},"scenario":{"en":"You're across the table from a buyer ready to sign. Then she says: 'Honestly, your competitor quoted us 20% less for basically the same thing. Give me one reason I shouldn't go with them.' She's not bluffing, and she's watching you. You have 60 seconds to respond out loud and keep this deal alive without simply slashing your price.","de":"Sie sitzen einer unterschriftsbereiten Einkäuferin gegenüber. Dann sagt sie: 'Ehrlich gesagt hat Ihr Wettbewerber uns 20 % weniger für praktisch dasselbe angeboten. Nennen Sie mir einen Grund, warum ich nicht zu denen gehen sollte.' Sie blufft nicht und beobachtet Sie. Sie haben 60 Sekunden, um laut zu antworten und diesen Deal am Leben zu halten, ohne einfach den Preis zu senken.","es-ES":"Estás frente a una compradora lista para firmar. Entonces dice: 'Sinceramente, tu competidor nos cotizó un 20 % menos por básicamente lo mismo. Dame una razón para no irme con ellos.' No está faroleando y te observa. Tienes 60 segundos para responder en voz alta y mantener vivo el trato sin limitarte a bajar el precio."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Stay calm and acknowledge the price gap without getting defensive.","de":"Bleiben Sie ruhig und erkennen Sie die Preisdifferenz an, ohne defensiv zu werden.","es-ES":"Mantén la calma y reconoce la diferencia de precio sin ponerte a la defensiva."},{"en":"Reframe from price to value, total cost of ownership, or risk.","de":"Verlagern Sie den Fokus vom Preis auf Wert, Gesamtkosten oder Risiko.","es-ES":"Reorienta el foco del precio hacia el valor, el coste total o el riesgo."},{"en":"Name a concrete differentiator the competitor can't match.","de":"Nennen Sie ein konkretes Unterscheidungsmerkmal, das der Wettbewerber nicht bietet.","es-ES":"Menciona un diferenciador concreto que el competidor no pueda igualar."},{"en":"Ask a question to understand what 'the same thing' really means to her.","de":"Stellen Sie eine Frage, um zu verstehen, was 'dasselbe' für sie wirklich bedeutet.","es-ES":"Haz una pregunta para entender qué significa realmente 'lo mismo' para ella."},{"en":"Hold your price with confidence and propose a clear next step.","de":"Halten Sie selbstbewusst an Ihrem Preis fest und schlagen Sie einen klaren nächsten Schritt vor.","es-ES":"Defiende tu precio con seguridad y propón un siguiente paso claro."}],"rubric":{"content":{"strong":"Acknowledges the gap, reframes to value with a specific differentiator, asks a smart question, and holds price.","adequate":"Defends value generally but leans on vague claims or partially concedes on price.","weak":"Caves immediately on price, gets defensive, or attacks the competitor without substance."},"delivery":{"strong":"Composed, confident tone; steady pace; no defensiveness or filler under pressure.","adequate":"Mostly steady but some hesitation, rushing, or audible nerves.","weak":"Flustered, apologetic, or rambling; tone undermines the message."},"time":{"strong":"Lands a complete answer within 55-65 seconds.","adequate":"Slightly over or under; answer feels rushed or padded.","weak":"Far too short to persuade or runs well past time."}},"modelAnswer":{"en":"I get it, 20% is real money, and I won't pretend it isn't. But before we compare on price, can I ask what 'the same thing' includes for them, onboarding, support response times, the integration work? Where we consistently win is total cost: clients switching to us cut downtime by a third in year one. That gap pays for itself fast. I'd rather earn this on value than discount my way in. Let me put the side-by-side in writing so you can decide with full numbers.","de":"Ich verstehe das, 20 % sind echtes Geld, und das will ich nicht kleinreden. Aber bevor wir über den Preis vergleichen: Was umfasst 'dasselbe' bei denen, Onboarding, Reaktionszeiten im Support, die Integration? Wo wir regelmäßig gewinnen, sind die Gesamtkosten: Kunden, die zu uns wechseln, senken Ausfallzeiten im ersten Jahr um ein Drittel. Diese Differenz amortisiert sich schnell. Ich gewinne Sie lieber über Wert als über Rabatt. Ich schicke Ihnen den direkten Vergleich schriftlich, damit Sie mit allen Zahlen entscheiden können.","es-ES":"Lo entiendo, un 20 % es dinero de verdad y no voy a fingir lo contrario. Pero antes de comparar por precio, ¿puedo preguntar qué incluye 'lo mismo' en su caso, la implantación, los tiempos de respuesta, la integración? Donde ganamos siempre es en coste total: los clientes que se pasan a nosotros reducen las paradas un tercio el primer año. Esa diferencia se paga sola. Prefiero ganarme esto por valor que a base de descuento. Te envío la comparativa por escrito para que decidas con todas las cifras."}},
  {"id":"COM-2","type":"conflict","category":"conflict_resolution","department":"commercial","difficulty":3,"media":{"scene":"video_call","alt":{"en":"A frustrated key-account client appears on a video call, frowning at the camera.","de":"Ein verärgerter Großkunde erscheint im Videocall und blickt mit gerunzelter Stirn in die Kamera.","es-ES":"Un cliente clave frustrado aparece en una videollamada, frunciendo el ceño ante la cámara."}},"roleCaption":{"en":"You're the account manager trying to save a churning client.","de":"Sie sind der Account Manager und versuchen, einen abwandernden Kunden zu halten.","es-ES":"Eres el gestor de cuenta que intenta salvar a un cliente que se va."},"scenario":{"en":"Your biggest account, 30% of your region's revenue, just emailed that they're 'exploring other vendors.' You get them on a video call. The client opens cold: 'We've had three missed deadlines this quarter and nobody warned us. We feel like an afterthought. Convince me we should stay.' You have 60 seconds to own it and reset the relationship out loud.","de":"Ihr größter Kunde, 30 % des Umsatzes Ihrer Region, hat gerade gemailt, dass er 'andere Anbieter prüft'. Sie bekommen ihn in einen Videocall. Der Kunde beginnt kühl: 'Wir hatten dieses Quartal drei verpasste Termine und niemand hat uns gewarnt. Wir fühlen uns wie eine Randnotiz. Überzeugen Sie mich, dass wir bleiben sollten.' Sie haben 60 Sekunden, um Verantwortung zu übernehmen und die Beziehung laut neu aufzusetzen.","es-ES":"Tu mayor cuenta, el 30 % de los ingresos de tu región, acaba de escribir que está 'explorando otros proveedores'. Los pones en una videollamada. El cliente abre frío: 'Hemos tenido tres plazos incumplidos este trimestre y nadie nos avisó. Nos sentimos como algo secundario. Convénceme de que debemos quedarnos.' Tienes 60 segundos para asumirlo y reconstruir la relación en voz alta."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Take genuine ownership without excuses or blaming other teams.","de":"Übernehmen Sie echte Verantwortung, ohne Ausreden oder Schuldzuweisungen an andere Teams.","es-ES":"Asume responsabilidad real sin excusas ni culpar a otros equipos."},{"en":"Acknowledge the emotional impact: they felt ignored, not just delayed.","de":"Erkennen Sie die emotionale Wirkung an: Sie fühlten sich ignoriert, nicht nur vertröstet.","es-ES":"Reconoce el impacto emocional: se sintieron ignorados, no solo retrasados."},{"en":"Offer a concrete, specific corrective action and a single point of contact.","de":"Bieten Sie eine konkrete Korrekturmaßnahme und einen festen Ansprechpartner an.","es-ES":"Ofrece una acción correctiva concreta y un único punto de contacto."},{"en":"Commit to proactive communication so this never recurs silently.","de":"Verpflichten Sie sich zu proaktiver Kommunikation, damit das nie wieder lautlos passiert.","es-ES":"Comprométete a una comunicación proactiva para que no se repita en silencio."},{"en":"Ask for a chance to prove it with a clear follow-up checkpoint.","de":"Bitten Sie um die Chance, es zu beweisen, mit einem klaren Folgetermin.","es-ES":"Pide la oportunidad de demostrarlo con un punto de seguimiento claro."}],"rubric":{"content":{"strong":"Owns the failure, validates the emotional impact, gives a specific fix and owner, and asks for a measured next checkpoint.","adequate":"Apologizes and promises improvement but stays vague on accountability or next steps.","weak":"Deflects blame, over-apologizes without a plan, or jumps to discounts as a fix."},"delivery":{"strong":"Sincere, grounded, and steady; conveys accountability without groveling.","adequate":"Sincere but uneven; some defensiveness or nervous over-talking.","weak":"Defensive, panicked, or hollow; tone signals damage control over care."},"time":{"strong":"Complete, well-paced answer within 55-65 seconds.","adequate":"Slightly off time; rushed close or padded middle.","weak":"Too brief to rebuild trust or runs far over."}},"modelAnswer":{"en":"You're right, and I'm not going to dress it up. Three missed deadlines with no heads-up is on us, and feeling like an afterthought is the part I most want to fix. Here's what changes today: I'm your single point of contact, and you'll get a status note every Friday whether the news is good or bad. For the open deliverables, I'll send a recovery plan with dates by tomorrow morning. Give me the next 30 days to prove it, and let's book a check-in then to judge me on results.","de":"Sie haben recht, und ich werde es nicht beschönigen. Drei verpasste Termine ohne Vorwarnung gehen auf uns, und das Gefühl, zweitrangig zu sein, will ich am dringendsten beheben. Das ändert sich ab heute: Ich bin Ihr fester Ansprechpartner, und Sie erhalten jeden Freitag ein Status-Update, egal ob die Nachricht gut oder schlecht ist. Für die offenen Punkte schicke ich bis morgen früh einen Plan mit Terminen. Geben Sie mir die nächsten 30 Tage, und lassen Sie uns dann einen Termin setzen, um mich an Ergebnissen zu messen.","es-ES":"Tienes razón y no voy a maquillarlo. Tres plazos incumplidos sin avisar son cosa nuestra, y lo que más quiero corregir es esa sensación de ser algo secundario. Esto cambia hoy: soy tu único punto de contacto y recibirás un estado cada viernes, sean buenas o malas noticias. Para lo pendiente, te envío un plan de recuperación con fechas mañana por la mañana. Dame los próximos 30 días para demostrarlo y agendemos una revisión para juzgarme por resultados."}},
  {"id":"COM-3","type":"behavioral","category":"strategic_thinking","department":"commercial","difficulty":4,"media":{"scene":"exec_committee","alt":{"en":"A skeptical executive committee sits around a long table awaiting your budget request.","de":"Ein skeptisches Führungsgremium sitzt am langen Tisch und erwartet Ihren Budgetantrag.","es-ES":"Un comité ejecutivo escéptico espera tu solicitud de presupuesto alrededor de una mesa larga."}},"roleCaption":{"en":"You're the marketing lead defending an underperforming campaign and asking for more budget.","de":"Sie sind die Marketingleitung, verteidigen eine schwache Kampagne und bitten um mehr Budget.","es-ES":"Eres el responsable de marketing que defiende una campaña floja y pide más presupuesto."},"scenario":{"en":"You're in front of the exec committee. The campaign you championed missed its lead target by 40% in Q1, and now you're asking for a 25% budget increase to double down. The CFO cuts in: 'You overspent and underdelivered. Why would we give you more money instead of cutting this?' Every face is skeptical. You have 60 seconds to make the strategic case out loud.","de":"Sie stehen vor dem Führungsgremium. Die von Ihnen verantwortete Kampagne hat ihr Lead-Ziel in Q1 um 40 % verfehlt, und nun bitten Sie um 25 % mehr Budget, um nachzulegen. Der CFO unterbricht: 'Sie haben zu viel ausgegeben und zu wenig geliefert. Warum sollten wir mehr Geld geben, statt das zu streichen?' Alle Mienen sind skeptisch. Sie haben 60 Sekunden, um die strategische Begründung laut vorzutragen.","es-ES":"Estás ante el comité ejecutivo. La campaña que impulsaste no alcanzó su objetivo de leads en un 40 % en el primer trimestre, y ahora pides un 25 % más de presupuesto para redoblar la apuesta. El director financiero interrumpe: 'Gastaste de más y entregaste de menos. ¿Por qué te daríamos más dinero en vez de recortar esto?' Todas las caras son escépticas. Tienes 60 segundos para exponer el argumento estratégico en voz alta."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Own the miss honestly before pivoting to the case for investment.","de":"Stehen Sie ehrlich zum Fehlschlag, bevor Sie zum Investitionsargument wechseln.","es-ES":"Asume el fallo con honestidad antes de pasar al argumento de inversión."},{"en":"Show what the data revealed and what you'd change, not just spend more.","de":"Zeigen Sie, was die Daten ergaben und was Sie ändern würden, nicht nur mehr ausgeben.","es-ES":"Muestra qué reveló el dato y qué cambiarías, no solo gastar más."},{"en":"Tie the ask to a concrete, measurable business outcome or ROI.","de":"Knüpfen Sie die Forderung an ein konkretes, messbares Geschäftsergebnis oder ROI.","es-ES":"Vincula la petición a un resultado de negocio concreto y medible."},{"en":"Address the CFO's risk directly: define a kill-switch or milestone.","de":"Adressieren Sie das Risiko des CFO direkt: definieren Sie einen Abbruchpunkt oder Meilenstein.","es-ES":"Aborda el riesgo del CFO directamente: define un punto de corte o hito."},{"en":"Project calm conviction, not defensiveness, under hostile questioning.","de":"Strahlen Sie ruhige Überzeugung aus, keine Abwehr, unter feindseligen Fragen.","es-ES":"Proyecta convicción serena, no actitud defensiva, ante preguntas hostiles."}],"rubric":{"content":{"strong":"Owns the miss, shows data-driven learning, ties the ask to clear ROI, and de-risks it with a milestone or kill-switch.","adequate":"Makes a reasonable case but light on data, ROI specifics, or risk controls.","weak":"Defends ego over evidence, asks for money without a changed plan, or ignores the CFO's risk."},"delivery":{"strong":"Calm, credible, executive presence; absorbs the challenge without rattling.","adequate":"Mostly composed but some defensiveness, hedging, or nerves.","weak":"Defensive, flustered, or over-apologetic; loses the room's confidence."},"time":{"strong":"Tight, complete argument within 55-65 seconds.","adequate":"Slightly off time; rushed evidence or padded framing.","weak":"Too thin to persuade or runs well over."}},"modelAnswer":{"en":"Fair challenge, and I own the 40% miss. But the data tells a sharper story: two of our five channels hit cost-per-lead targets and the other three drained 60% of spend. I'm not asking to repeat Q1, I'm asking to reallocate into what worked and kill what didn't. The 25% funds scaling the two winning channels, where pipeline is already converting at twice the rate. Tie it to a 90-day milestone: if cost-per-lead doesn't drop 30%, we cut it, no debate. That's a controlled bet, not a doubling-down on a mistake.","de":"Berechtigter Einwand, und ich stehe zu den 40 % Verfehlung. Aber die Daten erzählen mehr: Zwei unserer fünf Kanäle erreichten die Cost-per-Lead-Ziele, die anderen drei verschlangen 60 % des Budgets. Ich will Q1 nicht wiederholen, sondern umschichten in das, was funktioniert, und den Rest streichen. Die 25 % finanzieren die Skalierung der beiden starken Kanäle, deren Pipeline doppelt so gut konvertiert. Gebunden an einen 90-Tage-Meilenstein: Sinkt der Cost-per-Lead nicht um 30 %, streichen wir es, ohne Diskussion. Das ist eine kontrollierte Wette, kein Beharren auf einem Fehler.","es-ES":"Reto justo, y asumo el desvío del 40 %. Pero el dato cuenta algo más afinado: dos de nuestros cinco canales cumplieron el coste por lead y los otros tres consumieron el 60 % del gasto. No pido repetir el primer trimestre, pido reasignar a lo que funcionó y eliminar lo que no. El 25 % financia escalar los dos canales ganadores, cuyo pipeline ya convierte al doble. Atado a un hito de 90 días: si el coste por lead no baja un 30 %, lo cortamos, sin debate. Es una apuesta controlada, no insistir en un error."}},
  {"id":"HR-1","type":"conflict","category":"conflict_resolution","department":"people","difficulty":2,"media":{"scene":"coaching_room","alt":{"en":"Two employees seated across from a mediator in a quiet room","de":"Zwei Mitarbeitende sitzen einem Mediator in einem ruhigen Raum gegenüber","es-ES":"Dos empleados sentados frente a un mediador en una sala tranquila"}},"roleCaption":{"en":"You are mediating a conflict between two team members","de":"Du moderierst einen Konflikt zwischen zwei Teammitgliedern","es-ES":"Estás mediando un conflicto entre dos miembros del equipo"},"scenario":{"en":"Two of your best engineers, Sara and Tom, haven't spoken in two weeks. Sara says Tom takes credit for shared work; Tom says Sara excludes him from decisions. Both now sit across from you, arms folded, watching each other. The project ships Friday. You open the meeting. What do you say in the next 60 seconds to de-escalate and get them working together again?","de":"Zwei deiner besten Ingenieure, Sara und Tom, sprechen seit zwei Wochen nicht miteinander. Sara sagt, Tom nehme gemeinsame Arbeit für sich in Anspruch; Tom sagt, Sara schließe ihn von Entscheidungen aus. Beide sitzen dir nun mit verschränkten Armen gegenüber. Das Projekt geht Freitag live. Du eröffnest das Gespräch. Was sagst du in den nächsten 60 Sekunden, um zu deeskalieren?","es-ES":"Dos de tus mejores ingenieros, Sara y Tom, no se hablan desde hace dos semanas. Sara dice que Tom se atribuye el trabajo compartido; Tom dice que Sara lo excluye de las decisiones. Ambos están frente a ti, con los brazos cruzados. El proyecto se lanza el viernes. Abres la reunión. ¿Qué dices en los próximos 60 segundos para calmar la situación?"},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Set a neutral, respectful tone and shared goal","de":"Einen neutralen, respektvollen Ton und ein gemeinsames Ziel setzen","es-ES":"Establece un tono neutral, respetuoso y una meta común"},{"en":"Acknowledge both perspectives without taking sides","de":"Beide Sichtweisen anerkennen, ohne Partei zu ergreifen","es-ES":"Reconoce ambas perspectivas sin tomar partido"},{"en":"Focus on behaviors and the future, not blame","de":"Auf Verhalten und die Zukunft fokussieren, nicht auf Schuld","es-ES":"Céntrate en conductas y el futuro, no en la culpa"},{"en":"Propose a concrete next step before Friday","de":"Einen konkreten nächsten Schritt vor Freitag vorschlagen","es-ES":"Propón un paso concreto antes del viernes"}],"rubric":{"content":{"strong":"Stays neutral, names the shared goal, surfaces both views and ends with a concrete agreement","adequate":"Calms tension and invites both to speak but offers a vague next step","weak":"Takes a side, assigns blame, or ignores the deadline"},"delivery":{"strong":"Calm, steady, warm tone that lowers tension and signals fairness","adequate":"Composed but slightly tense or uneven pacing","weak":"Sounds frustrated, rushed, or visibly partial"},"time":{"strong":"Uses near the full 60s with clear structure","adequate":"Noticeably short or slightly over","weak":"Far too short or rambles past time"}},"modelAnswer":{"en":"Thanks for being here. I know this has been tense, and I respect that you both care enough to be frustrated. I'm not here to decide who's right. Sara, I hear that recognition matters to you. Tom, I hear you want to be included in decisions. Both are fair. Friday we ship together, so let's agree on one thing now: a quick daily check-in where we name who owns what. Can we try that?","de":"Danke, dass ihr hier seid. Ich weiß, es war angespannt, und ich respektiere, dass euch das wichtig ist. Ich entscheide nicht, wer recht hat. Sara, Anerkennung ist dir wichtig. Tom, du willst bei Entscheidungen einbezogen werden. Beides ist fair. Freitag liefern wir gemeinsam, also vereinbaren wir eins: ein kurzes tägliches Check-in, in dem wir klären, wer was verantwortet. Versuchen wir das?","es-ES":"Gracias por estar aquí. Sé que ha sido tenso, y respeto que os importe lo suficiente como para frustraros. No vengo a decidir quién tiene razón. Sara, oigo que el reconocimiento te importa. Tom, oigo que quieres participar en las decisiones. Ambos es justo. El viernes lanzamos juntos, así que acordemos algo ahora: una reunión diaria breve donde nombremos quién es responsable de qué. ¿Lo intentamos?"}},
  {"id":"HR-2","type":"feedback360","category":"feedback_difficult_conversations","department":"people","difficulty":3,"media":{"scene":"office_1on1","alt":{"en":"A manager and an employee in a private one-on-one meeting","de":"Eine Führungskraft und ein Mitarbeiter in einem privaten Einzelgespräch","es-ES":"Un gerente y un empleado en una reunión individual privada"}},"roleCaption":{"en":"You must tell a top performer there is no promotion this cycle","de":"Du musst einem Top-Performer sagen, dass es diese Runde keine Beförderung gibt","es-ES":"Debes decirle a un alto rendidor que no hay ascenso este ciclo"},"scenario":{"en":"Priya is your strongest individual contributor. For a year she's been told a promotion to lead was 'close.' Budget got frozen and the role was cut. She walks in expecting good news, smiling. You can see the hope on her face. She's already had two offers from competitors. You have 60 seconds to tell her the truth, keep her trust, and keep her on the team. Speak.","de":"Priya ist deine stärkste Mitarbeiterin. Ein Jahr lang hieß es, eine Beförderung zur Teamleitung sei 'nah'. Das Budget wurde eingefroren und die Stelle gestrichen. Sie kommt lächelnd herein und erwartet gute Nachrichten. Sie hat bereits zwei Angebote von Wettbewerbern. Du hast 60 Sekunden, ihr die Wahrheit zu sagen, ihr Vertrauen und sie im Team zu halten. Sprich.","es-ES":"Priya es tu colaboradora más fuerte. Durante un año le dijeron que un ascenso a líder estaba 'cerca'. El presupuesto se congeló y el puesto se eliminó. Entra sonriendo, esperando buenas noticias. Ya tiene dos ofertas de la competencia. Tienes 60 segundos para decirle la verdad, conservar su confianza y mantenerla en el equipo. Habla."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Be honest and direct about the cut, no false hope","de":"Ehrlich und direkt über die Streichung, keine falschen Hoffnungen","es-ES":"Sé honesto y directo sobre la eliminación, sin falsas esperanzas"},{"en":"Acknowledge her value and the broken expectation","de":"Ihren Wert und die enttäuschte Erwartung anerkennen","es-ES":"Reconoce su valor y la expectativa rota"},{"en":"Take ownership rather than blaming 'the company'","de":"Verantwortung übernehmen statt 'die Firma' zu beschuldigen","es-ES":"Asume responsabilidad en vez de culpar a 'la empresa'"},{"en":"Offer a concrete, credible path forward","de":"Einen konkreten, glaubwürdigen Weg nach vorn anbieten","es-ES":"Ofrece un camino concreto y creíble hacia adelante"},{"en":"Invite her honest reaction and questions","de":"Ihre ehrliche Reaktion und Fragen einladen","es-ES":"Invita su reacción honesta y sus preguntas"}],"rubric":{"content":{"strong":"States the truth plainly, owns it, validates her, and offers a credible concrete next step","adequate":"Delivers the news and some recognition but path forward is thin or vague","weak":"Softens into false hope, deflects blame, or ignores her likely exit"},"delivery":{"strong":"Empathetic, steady, sincere tone that conveys respect under pressure","adequate":"Caring but slightly hesitant or scripted","weak":"Cold, defensive, or evasive"},"time":{"strong":"Uses near the full 60s with clear structure","adequate":"Noticeably short or slightly over","weak":"Far too short or rambles past time"}},"modelAnswer":{"en":"Priya, I want to be straight with you because you've earned that. The lead role was cut when budget froze. It's not a reflection of you, it's a hard constraint I couldn't change, and I'm sorry you heard 'close' for so long. You are essential here. I can't promise a title today, but I can commit to a real plan: an expanded scope, a retention adjustment, and a defined path the moment budget reopens. How are you feeling hearing this?","de":"Priya, ich will ehrlich zu dir sein, das hast du verdient. Die Leitungsstelle wurde mit dem Budgetstopp gestrichen. Das liegt nicht an dir, es ist ein harter Zwang, den ich nicht ändern konnte, und es tut mir leid, dass du so lange 'nah' gehört hast. Du bist hier unverzichtbar. Ich kann heute keinen Titel versprechen, aber einen echten Plan: mehr Verantwortung, eine Gehaltsanpassung und einen klaren Weg, sobald das Budget wieder offen ist. Wie geht es dir damit?","es-ES":"Priya, quiero ser franco contigo porque te lo has ganado. El puesto de líder se eliminó cuando se congeló el presupuesto. No es un reflejo de ti, es una restricción dura que no pude cambiar, y siento que oyeras 'cerca' tanto tiempo. Eres esencial aquí. No puedo prometerte un título hoy, pero sí un plan real: más alcance, un ajuste salarial y un camino definido en cuanto se reabra el presupuesto. ¿Cómo te sientes al oír esto?"}},
  {"id":"HR-3","type":"situational","category":"professional_communication","department":"people","difficulty":4,"media":{"scene":"office_1on1","alt":{"en":"An HR leader receiving a serious complaint in a closed-door meeting","de":"Eine HR-Leitung erhält eine ernste Beschwerde in einem vertraulichen Gespräch","es-ES":"Un líder de RR. HH. recibe una queja seria en una reunión a puerta cerrada"}},"roleCaption":{"en":"An employee discloses a harassment complaint to you","de":"Eine Mitarbeiterin meldet dir eine Belästigungsbeschwerde","es-ES":"Una empleada te comunica una queja de acoso"},"scenario":{"en":"Daniel, a junior analyst, closes your door and says, voice shaking, that a senior director has repeatedly made inappropriate comments and last week touched his shoulder in a way that felt threatening. He's scared of retaliation and almost didn't come. The director is influential and well-liked by leadership. You have 60 seconds to respond in the moment, the way that sets everything that follows on the right footing. What do you say?","de":"Daniel, ein Junior-Analyst, schließt deine Tür und sagt mit zitternder Stimme, ein Senior Director habe wiederholt unangemessene Bemerkungen gemacht und ihn letzte Woche bedrohlich an der Schulter berührt. Er fürchtet Vergeltung und wäre fast nicht gekommen. Der Director ist einflussreich und bei der Führung beliebt. Du hast 60 Sekunden zu reagieren, so dass alles Weitere richtig beginnt. Was sagst du?","es-ES":"Daniel, un analista junior, cierra tu puerta y dice, con voz temblorosa, que un director sénior ha hecho comentarios inapropiados repetidamente y la semana pasada le tocó el hombro de forma amenazante. Teme represalias y casi no vino. El director es influyente y querido por la dirección. Tienes 60 segundos para responder en el momento de forma que todo lo siguiente empiece bien. ¿Qué dices?"},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Thank him and affirm it took courage to come forward","de":"Ihm danken und bestätigen, dass es Mut brauchte","es-ES":"Agradécele y afirma que vino con valentía"},{"en":"Take it seriously; do not minimize or judge","de":"Es ernst nehmen; nicht verharmlosen oder bewerten","es-ES":"Tómalo en serio; no minimices ni juzgues"},{"en":"Explain the process and protection from retaliation","de":"Den Prozess und den Schutz vor Vergeltung erklären","es-ES":"Explica el proceso y la protección contra represalias"},{"en":"Be clear on confidentiality limits, no promises you can't keep","de":"Vertraulichkeitsgrenzen klarstellen, keine unhaltbaren Versprechen","es-ES":"Aclara los límites de confidencialidad, sin promesas que no puedas cumplir"},{"en":"State concrete next steps and that you'll act fairly","de":"Konkrete nächste Schritte nennen und faires Handeln zusichern","es-ES":"Indica los próximos pasos concretos y que actuarás con justicia"}],"rubric":{"content":{"strong":"Validates courage, takes it seriously, explains process and anti-retaliation, sets honest confidentiality and clear next steps","adequate":"Supportive and outlines some process but vague on retaliation or confidentiality limits","weak":"Minimizes, promises absolute secrecy, hints at the director's status, or improvises an investigation"},"delivery":{"strong":"Calm, warm, controlled tone that conveys safety and seriousness","adequate":"Caring but slightly anxious or uneven","weak":"Dismissive, alarmed, or coldly procedural"},"time":{"strong":"Uses near the full 60s with clear structure","adequate":"Noticeably short or slightly over","weak":"Far too short or rambles past time"}},"modelAnswer":{"en":"Daniel, thank you for telling me. I know that took real courage, and I'm glad you came. I take this seriously and you've done the right thing. You will not face retaliation for raising this; that's protected, and I'll be watching for it. I have to be honest: I can't promise total secrecy, because I'm required to look into it properly and fairly. Here's what happens next, and I'll explain every step so nothing surprises you. Are you okay to continue?","de":"Daniel, danke, dass du es mir sagst. Das brauchte echten Mut, und ich bin froh, dass du gekommen bist. Ich nehme das ernst, und du hast richtig gehandelt. Du wirst dafür keine Vergeltung erfahren; das ist geschützt, und ich achte darauf. Ich muss ehrlich sein: Ich kann keine völlige Geheimhaltung versprechen, weil ich der Sache ordentlich und fair nachgehen muss. So geht es weiter, und ich erkläre jeden Schritt. Können wir weitermachen?","es-ES":"Daniel, gracias por contármelo. Sé que requirió verdadero valor y me alegra que vinieras. Me lo tomo en serio y has hecho lo correcto. No sufrirás represalias por plantearlo; eso está protegido y estaré atento. Debo ser honesto: no puedo prometer secreto total, porque debo investigarlo de forma adecuada y justa. Esto es lo que pasará ahora, y te explicaré cada paso para que nada te sorprenda. ¿Estás bien para continuar?"}},
  {"id":"OPS-1","type":"situational","category":"professional_communication","department":"operations","difficulty":2,"media":{"scene":"client_meeting","alt":{"en":"A logistics control room with screens showing delayed shipments and red route alerts.","de":"Ein Logistik-Leitstand mit Bildschirmen, die verspätete Sendungen und rote Routenwarnungen zeigen.","es-ES":"Una sala de control logístico con pantallas que muestran envíos retrasados y alertas de ruta en rojo."}},"roleCaption":{"en":"You face the client whose peak-season orders are now stuck.","de":"Du stehst dem Kunden gegenüber, dessen Bestellungen zur Hochsaison nun feststecken.","es-ES":"Te enfrentas al cliente cuyos pedidos de temporada alta están ahora bloqueados."},"scenario":{"en":"It is the morning before Black Friday. Your primary carrier has just frozen all outbound freight after a depot fire, and 12,000 of your biggest client's orders are stranded. The client's head of e-commerce is on the call, furious, asking what happens to their promised next-day delivery. You have 60 seconds to respond out loud: own the situation, give them a credible recovery path, and tell them what you need from them now.","de":"Es ist der Morgen vor Black Friday. Dein Hauptspediteur hat nach einem Depotbrand alle ausgehenden Frachten gestoppt, und 12.000 Bestellungen deines größten Kunden stecken fest. Der E-Commerce-Leiter des Kunden ist in der Leitung, wütend, und fragt, was mit der zugesagten Next-Day-Lieferung passiert. Du hast 60 Sekunden, um laut zu antworten: Übernimm die Verantwortung, biete einen glaubwürdigen Lösungsweg und sage, was du jetzt von ihm brauchst.","es-ES":"Es la mañana antes del Black Friday. Tu transportista principal acaba de congelar toda la carga saliente tras un incendio en un depósito, y 12.000 pedidos de tu mayor cliente están bloqueados. El responsable de e-commerce del cliente está en la llamada, furioso, preguntando qué pasa con la entrega al día siguiente prometida. Tienes 60 segundos para responder en voz alta: asume la situación, ofrece una vía de recuperación creíble y di qué necesitas de él ahora."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Acknowledge the impact and take ownership without deflecting blame.","de":"Die Auswirkung anerkennen und Verantwortung übernehmen, ohne Schuld abzuwälzen.","es-ES":"Reconocer el impacto y asumir la responsabilidad sin desviar la culpa."},{"en":"State the concrete recovery plan: backup carriers and re-routing already in motion.","de":"Den konkreten Wiederherstellungsplan nennen: Ersatzspediteure und Umleitung bereits in Gang.","es-ES":"Exponer el plan de recuperación concreto: transportistas de respaldo y reenrutamiento ya en marcha."},{"en":"Give a realistic, time-bound commitment rather than a vague reassurance.","de":"Eine realistische, terminierte Zusage geben statt vager Beruhigung.","es-ES":"Dar un compromiso realista y con plazo en lugar de una promesa vaga."},{"en":"Ask for the decision you need: which SKUs to prioritise first.","de":"Um die benötigte Entscheidung bitten: welche Artikel zuerst priorisiert werden.","es-ES":"Pedir la decisión que necesitas: qué referencias priorizar primero."},{"en":"Set a clear next check-in time so they feel in control.","de":"Einen klaren nächsten Abstimmungszeitpunkt festlegen, damit sie sich in Kontrolle fühlen.","es-ES":"Fijar un próximo punto de contacto claro para que sientan el control."}],"rubric":{"content":{"strong":"Owns the issue, presents a credible recovery path with backup carriers, gives a time-bound commitment, and asks for SKU prioritisation plus a check-in time.","adequate":"Acknowledges the problem and offers a partial plan but misses either the concrete commitment or the specific ask of the client.","weak":"Deflects blame, over-promises with no plan, or offers only vague reassurance with no recovery actions."},"delivery":{"strong":"Calm, steady, and confident under pressure; tone conveys control and empathy without panic.","adequate":"Mostly composed but some hesitation or filler that slightly undercuts authority.","weak":"Flustered, defensive, or rushed; tone amplifies the client's anxiety."},"time":{"strong":"Uses the full 60 seconds efficiently, covering all points without rushing or trailing off.","adequate":"Covers most points but noticeably rushes the end or finishes well short.","weak":"Runs far over or stops after 20 seconds with key points missing."}},"modelAnswer":{"en":"I want to be straight with you: the depot fire froze our primary carrier, and your 12,000 orders are affected. I own this. We've already activated two backup carriers and are re-routing your priority SKUs tonight; realistically we recover next-day delivery on roughly 70% by tomorrow and the rest within 48 hours. What I need from you is your ranked list of must-ship SKUs in the next hour. Let's reconnect at 2pm with firm tracking numbers.","de":"Ich bin ehrlich mit dir: Der Depotbrand hat unseren Hauptspediteur lahmgelegt, und deine 12.000 Bestellungen sind betroffen. Ich übernehme die Verantwortung. Wir haben bereits zwei Ersatzspediteure aktiviert und leiten deine Prioritäts-Artikel heute Nacht um; realistisch erreichen wir morgen bei rund 70% wieder Next-Day, den Rest binnen 48 Stunden. Ich brauche von dir innerhalb einer Stunde die priorisierte Liste der zwingend zu versendenden Artikel. Lass uns um 14 Uhr mit festen Tracking-Nummern erneut sprechen.","es-ES":"Quiero ser claro contigo: el incendio del depósito paralizó a nuestro transportista principal y tus 12.000 pedidos están afectados. Asumo la responsabilidad. Ya hemos activado dos transportistas de respaldo y esta noche reenrutamos tus referencias prioritarias; de forma realista recuperamos la entrega al día siguiente en torno al 70% mañana y el resto en 48 horas. Necesito de ti, en la próxima hora, tu lista priorizada de referencias imprescindibles. Reconectemos a las 14:00 con números de seguimiento firmes."}},
  {"id":"OPS-2","type":"situational","category":"strategic_thinking","department":"operations","difficulty":3,"media":{"scene":"boardroom","alt":{"en":"A product war room with a launch countdown clock and a roadmap board full of sticky notes.","de":"Ein Produkt-Kriegsraum mit Launch-Countdown-Uhr und einem Roadmap-Board voller Haftnotizen.","es-ES":"Una sala de guerra de producto con un reloj de cuenta atrás de lanzamiento y un tablero de hoja de ruta lleno de notas adhesivas."}},"roleCaption":{"en":"You decide what to cut so the launch ships on time.","de":"Du entscheidest, was gestrichen wird, damit der Launch pünktlich erfolgt.","es-ES":"Decides qué recortar para que el lanzamiento salga a tiempo."},"scenario":{"en":"You are the product lead. With ten days to a committed launch, engineering reports the build is two features behind: SSO login and an offline mode. Both were promised, both have a stakeholder in the room. Sales says SSO closes enterprise deals; Support says offline mode stops churn. You cannot ship both on time. In 60 seconds, out loud, make the call on what ships now versus what slips, and justify it so both stakeholders accept the trade-off.","de":"Du bist Produktverantwortliche. Zehn Tage vor dem zugesagten Launch meldet die Entwicklung, dass der Build bei zwei Features zurückliegt: SSO-Login und Offline-Modus. Beide wurden versprochen, beide haben einen Stakeholder im Raum. Der Vertrieb sagt, SSO schließt Enterprise-Deals ab; der Support sagt, der Offline-Modus stoppt Abwanderung. Du kannst nicht beide pünktlich liefern. Triff in 60 Sekunden laut die Entscheidung, was jetzt ausgeliefert wird und was sich verschiebt, und begründe es so, dass beide Stakeholder den Kompromiss akzeptieren.","es-ES":"Eres la responsable de producto. A diez días del lanzamiento comprometido, ingeniería informa de que el desarrollo va dos funciones atrasado: inicio de sesión SSO y modo sin conexión. Ambas se prometieron, ambas tienen un interesado en la sala. Ventas dice que el SSO cierra acuerdos empresariales; Soporte dice que el modo sin conexión frena la fuga de clientes. No puedes entregar ambas a tiempo. En 60 segundos, en voz alta, decide qué se lanza ahora y qué se aplaza, y justifícalo para que ambos interesados acepten el compromiso."},"weights":{"content":0.6,"delivery":0.25,"time":0.15},"keyPoints":[{"en":"State a clear decision criterion before naming the winner (e.g. revenue at risk vs reach).","de":"Ein klares Entscheidungskriterium nennen, bevor der Gewinner benannt wird (z. B. gefährdeter Umsatz vs. Reichweite).","es-ES":"Exponer un criterio de decisión claro antes de nombrar la opción elegida (p. ej. ingresos en riesgo frente a alcance)."},{"en":"Make a definite call rather than hedging or splitting the difference.","de":"Eine eindeutige Entscheidung treffen, statt zu lavieren oder zu halbieren.","es-ES":"Tomar una decisión definitiva en lugar de titubear o partir la diferencia."},{"en":"Acknowledge the losing stakeholder's concern and give the slipped feature a firm date.","de":"Die Sorge des unterlegenen Stakeholders anerkennen und dem verschobenen Feature ein festes Datum geben.","es-ES":"Reconocer la preocupación del interesado no elegido y dar una fecha firme a la función aplazada."},{"en":"Tie the choice back to the shared business goal, not personal preference.","de":"Die Wahl an das gemeinsame Geschäftsziel binden, nicht an persönliche Vorlieben.","es-ES":"Vincular la elección al objetivo de negocio común, no a una preferencia personal."},{"en":"Confirm next steps and who owns the follow-up.","de":"Nächste Schritte bestätigen und festlegen, wer das Follow-up verantwortet.","es-ES":"Confirmar los próximos pasos y quién es responsable del seguimiento."}],"rubric":{"content":{"strong":"Names an explicit criterion, makes a firm call, gives the slipped feature a committed date, links to the business goal, and assigns follow-up ownership.","adequate":"Makes a decision with some rationale but leaves the slipped feature undated or the criterion implicit.","weak":"Avoids deciding, tries to ship both, or picks one with no rationale that either stakeholder could accept."},"delivery":{"strong":"Decisive and even-handed; tone respects both stakeholders while projecting authority.","adequate":"Clear decision but tone tilts toward one side or shows mild discomfort with the conflict.","weak":"Wavering or apologetic; delivery invites the decision to be re-litigated."},"time":{"strong":"Full 60 seconds used to lay out criterion, call, and follow-up cleanly.","adequate":"Covers the call but compresses the rationale or follow-up at the end.","weak":"Overruns badly or stops early with the trade-off unjustified."}},"modelAnswer":{"en":"Our criterion is revenue at immediate risk. SSO unblocks three signed enterprise deals worth more than the churn offline mode prevents this quarter, so SSO ships at launch and offline mode slips to the next sprint, committed for the 30th. Support, I hear the churn risk; we'll mitigate with a manual sync workaround in the release notes and you'll have offline mode in three weeks, dated and resourced. Sales, you're on for the enterprise close. Priya owns the follow-up plan by Friday.","de":"Unser Kriterium ist der unmittelbar gefährdete Umsatz. SSO macht drei unterzeichnete Enterprise-Deals frei, die mehr wert sind als die Abwanderung, die der Offline-Modus dieses Quartal verhindert. Also geht SSO zum Launch live und der Offline-Modus verschiebt sich auf den nächsten Sprint, zugesagt zum 30. Support, ich höre das Abwanderungsrisiko; wir mildern es mit einer manuellen Sync-Behelfslösung in den Release Notes, und du bekommst den Offline-Modus in drei Wochen, terminiert und besetzt. Vertrieb, du bist für den Enterprise-Abschluss dran. Priya verantwortet den Follow-up-Plan bis Freitag.","es-ES":"Nuestro criterio es el ingreso en riesgo inmediato. El SSO desbloquea tres acuerdos empresariales firmados que valen más que la fuga que el modo sin conexión evita este trimestre, así que el SSO sale en el lanzamiento y el modo sin conexión se aplaza al próximo sprint, comprometido para el día 30. Soporte, entiendo el riesgo de fuga; lo mitigamos con una sincronización manual provisional en las notas de versión, y tendrás el modo sin conexión en tres semanas, con fecha y recursos. Ventas, cuentas con el cierre empresarial. Priya lidera el plan de seguimiento para el viernes."}},
  {"id":"OPS-3","type":"conflict","category":"leadership_decisions","department":"operations","difficulty":4,"media":{"scene":"exec_committee","alt":{"en":"An executive committee room where quality charts show a spike in a safety defect.","de":"Ein Vorstandsraum, in dem Qualitätsdiagramme einen Anstieg eines Sicherheitsdefekts zeigen.","es-ES":"Una sala de comité ejecutivo donde los gráficos de calidad muestran un repunte de un defecto de seguridad."}},"roleCaption":{"en":"You recommend a recall the CFO does not want.","de":"Du empfiehlst einen Rückruf, den der CFO nicht will.","es-ES":"Recomiendas una retirada que el director financiero no quiere."},"scenario":{"en":"You run operations. Quality data shows a battery defect in a shipped product with a small but real fire risk: 0.3% of units. No injuries yet. A full recall costs eight million and dents the quarter; the CFO argues for a quiet field-fix only. The CEO turns to you in the exec committee and asks for your recommendation, now. In 60 seconds, out loud, state your call on the recall, defend it against the cost objection, and lay out the immediate first move.","de":"Du leitest den Betrieb. Qualitätsdaten zeigen einen Batteriedefekt in einem ausgelieferten Produkt mit kleinem, aber realem Brandrisiko: 0,3% der Einheiten. Noch keine Verletzten. Ein voller Rückruf kostet acht Millionen und belastet das Quartal; der CFO plädiert für eine stille Feldreparatur. Der CEO wendet sich im Vorstandsausschuss an dich und fragt jetzt nach deiner Empfehlung. Nenne in 60 Sekunden laut deine Entscheidung zum Rückruf, verteidige sie gegen den Kosteneinwand und lege den unmittelbaren ersten Schritt dar.","es-ES":"Diriges operaciones. Los datos de calidad muestran un defecto de batería en un producto ya distribuido con un riesgo de incendio pequeño pero real: el 0,3% de las unidades. Aún sin heridos. Una retirada total cuesta ocho millones y daña el trimestre; el director financiero aboga por una reparación discreta sobre el terreno. El consejero delegado se gira hacia ti en el comité ejecutivo y pide tu recomendación, ahora. En 60 segundos, en voz alta, expón tu decisión sobre la retirada, defiéndela frente a la objeción de coste y plantea el primer paso inmediato."},"weights":{"content":0.6,"delivery":0.2,"time":0.2},"keyPoints":[{"en":"Lead with safety and liability as the non-negotiable frame.","de":"Mit Sicherheit und Haftung als nicht verhandelbarem Rahmen beginnen.","es-ES":"Empezar con la seguridad y la responsabilidad como marco innegociable."},{"en":"Make a clear recommendation rather than deferring the hard call.","de":"Eine klare Empfehlung aussprechen, statt die schwere Entscheidung aufzuschieben.","es-ES":"Hacer una recomendación clara en lugar de eludir la decisión difícil."},{"en":"Address the cost objection directly: weigh 8m against injury, recall escalation, and brand damage.","de":"Den Kosteneinwand direkt ansprechen: 8 Mio. gegen Verletzung, Rückruf-Eskalation und Markenschaden abwägen.","es-ES":"Abordar la objeción de coste directamente: sopesar 8M frente a lesiones, escalada de la retirada y daño de marca."},{"en":"Name the immediate first move (stop sale, notify regulator, segment affected lots).","de":"Den unmittelbaren ersten Schritt nennen (Verkaufsstopp, Behörde informieren, betroffene Chargen eingrenzen).","es-ES":"Nombrar el primer paso inmediato (detener venta, notificar al regulador, segmentar los lotes afectados)."},{"en":"Show you respect the CFO's concern while holding the safety line.","de":"Zeigen, dass du die Sorge des CFO respektierst, aber die Sicherheitslinie hältst.","es-ES":"Mostrar que respetas la preocupación del director financiero mientras mantienes la línea de seguridad."}],"rubric":{"content":{"strong":"Leads with safety, recommends the recall decisively, rebuts the cost case with liability and brand math, and names a concrete first move plus regulator notification.","adequate":"Recommends action and touches on cost but leaves the first move vague or under-defends against the CFO.","weak":"Hedges, sides with cost over safety without analysis, or names no immediate action."},"delivery":{"strong":"Grave, steady, and authoritative; conveys moral clarity without grandstanding.","adequate":"Clear stance but some hesitation when countering the CFO.","weak":"Tentative or defensive; tone undercuts a high-stakes safety call."},"time":{"strong":"Full 60 seconds used to state the call, rebut cost, and give the first move.","adequate":"Covers the recommendation but rushes the rebuttal or first move.","weak":"Overruns or ends early with the safety case unmade."}},"modelAnswer":{"en":"My recommendation is a full recall, and we start it today. A fire risk in customers' hands isn't a cost question, it's a safety and liability one. The eight million is real, but one injury, a regulator-forced recall, or the headline costs us far more in brand and legal exposure. I respect the CFO's concern, so we'll phase the spend, but we hold the safety line. First move: stop sale now, notify the regulator proactively, and segment the affected lots so the field-fix covers the rest. I'll have the plan in two hours.","de":"Meine Empfehlung ist ein vollständiger Rückruf, und wir starten ihn heute. Ein Brandrisiko in Kundenhand ist keine Kostenfrage, sondern eine Sicherheits- und Haftungsfrage. Die acht Millionen sind real, aber eine Verletzung, ein behördlich erzwungener Rückruf oder die Schlagzeile kosten uns weit mehr an Marke und rechtlichem Risiko. Ich respektiere die Sorge des CFO, also staffeln wir die Ausgaben, aber wir halten die Sicherheitslinie. Erster Schritt: Verkauf sofort stoppen, die Behörde proaktiv informieren und die betroffenen Chargen eingrenzen, damit die Feldreparatur den Rest abdeckt. Den Plan habe ich in zwei Stunden.","es-ES":"Mi recomendación es una retirada total, y la iniciamos hoy. Un riesgo de incendio en manos de los clientes no es una cuestión de coste, sino de seguridad y responsabilidad. Los ocho millones son reales, pero una lesión, una retirada forzada por el regulador o el titular nos cuestan mucho más en marca y exposición legal. Respeto la preocupación del director financiero, así que escalonaremos el gasto, pero mantenemos la línea de seguridad. Primer paso: detener la venta ya, notificar al regulador de forma proactiva y segmentar los lotes afectados para que la reparación cubra el resto. Tendré el plan en dos horas."}},
  {"id":"CS-1","type":"conflict","category":"conflict_resolution","department":"customer","difficulty":2,"media":{"scene":"video_call","alt":{"en":"A support agent on a video call facing a visibly frustrated customer.","de":"Ein Support-Mitarbeiter in einem Videoanruf mit einem sichtlich verärgerten Kunden.","es-ES":"Un agente de soporte en una videollamada frente a un cliente visiblemente frustrado."}},"roleCaption":{"en":"You are the Customer Success Manager. The customer is on screen, angry.","de":"Sie sind der Customer Success Manager. Der Kunde ist auf dem Bildschirm und wütend.","es-ES":"Eres el Customer Success Manager. El cliente está en pantalla, enfadado."},"scenario":{"en":"You join a video call and the customer is fuming. A bug in last night's release deleted three hours of their team's work. \"This is the second time this month,\" they snap. \"I'm posting screenshots on LinkedIn tonight unless you give me a real answer right now.\" You have 60 seconds to defuse this and keep their trust.","de":"Sie treten einem Videoanruf bei und der Kunde kocht vor Wut. Ein Fehler im gestrigen Release hat drei Stunden Arbeit seines Teams gelöscht. \"Das ist schon das zweite Mal diesen Monat\", schnaubt er. \"Ich poste heute Abend Screenshots auf LinkedIn, wenn Sie mir nicht sofort eine echte Antwort geben.\" Sie haben 60 Sekunden, um die Situation zu entschärfen und das Vertrauen zu wahren.","es-ES":"Te unes a una videollamada y el cliente está furioso. Un error en la versión de anoche borró tres horas de trabajo de su equipo. \"Es la segunda vez este mes\", espeta. \"Voy a publicar capturas en LinkedIn esta noche a menos que me des una respuesta real ahora mismo.\" Tienes 60 segundos para calmar la situación y conservar su confianza."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Acknowledge the impact and apologize sincerely without making excuses.","de":"Die Auswirkungen anerkennen und sich aufrichtig entschuldigen, ohne Ausreden.","es-ES":"Reconocer el impacto y disculparse con sinceridad sin poner excusas."},{"en":"Take ownership and confirm the bug is being investigated now.","de":"Verantwortung übernehmen und bestätigen, dass der Fehler jetzt untersucht wird.","es-ES":"Asumir la responsabilidad y confirmar que el error se está investigando ahora."},{"en":"Offer a concrete next step with a clear timeline.","de":"Einen konkreten nächsten Schritt mit klarem Zeitrahmen anbieten.","es-ES":"Ofrecer un siguiente paso concreto con un plazo claro."},{"en":"Address the repeat issue to rebuild credibility.","de":"Das wiederholte Problem ansprechen, um Glaubwürdigkeit wiederherzustellen.","es-ES":"Abordar el problema recurrente para recuperar la credibilidad."},{"en":"Stay calm and avoid being defensive about the review threat.","de":"Ruhig bleiben und bei der Drohung mit der Bewertung nicht defensiv reagieren.","es-ES":"Mantener la calma y no ponerse a la defensiva ante la amenaza de la reseña."}],"rubric":{"content":{"strong":"Apologizes, owns the issue, gives a concrete next step and timeline, and addresses the recurrence.","adequate":"Apologizes and offers a next step but misses the recurrence or a clear timeline.","weak":"Defensive, makes excuses, or offers no concrete action."},"delivery":{"strong":"Calm, warm, confident tone that conveys genuine empathy and control.","adequate":"Mostly steady but some tension or hesitation shows.","weak":"Flustered, robotic, or defensive tone that escalates the customer."},"time":{"strong":"Uses 50-60 seconds, complete and unhurried.","adequate":"Slightly short or rushed but covers the essentials.","weak":"Far too short or runs long without resolution."}},"modelAnswer":{"en":"I'm really sorry; losing three hours of your team's work is unacceptable, and I understand why you're furious, especially as a repeat. I'm taking ownership personally. Our engineers are already investigating, and I'll have a root-cause update to you within two hours, plus the steps we're taking so this never happens again. I'd also like to recover what we can of that lost work today. You have my direct line, and I will not let this slip.","de":"Es tut mir wirklich leid; drei Stunden Arbeit Ihres Teams zu verlieren, ist inakzeptabel, und ich verstehe Ihren Ärger, gerade weil es sich wiederholt. Ich übernehme persönlich die Verantwortung. Unsere Entwickler untersuchen es bereits, und ich gebe Ihnen innerhalb von zwei Stunden ein Update zur Ursache sowie zu den Schritten, damit das nie wieder passiert. Ich möchte heute auch retten, was von der verlorenen Arbeit möglich ist. Sie haben meine Durchwahl, und ich lasse das nicht schleifen.","es-ES":"Lo siento mucho; perder tres horas de trabajo de tu equipo es inaceptable, y entiendo tu enfado, sobre todo al repetirse. Asumo la responsabilidad personalmente. Nuestros ingenieros ya lo están investigando, y te daré una actualización de la causa raíz en dos horas, junto con las medidas para que no vuelva a ocurrir. También quiero recuperar hoy lo posible de ese trabajo perdido. Tienes mi línea directa y no dejaré que esto se descuide."}},
  {"id":"CS-2","type":"situational","category":"professional_communication","department":"customer","difficulty":3,"media":{"scene":"client_meeting","alt":{"en":"A customer success manager across the table from a tense enterprise client.","de":"Ein Customer Success Manager gegenüber einem angespannten Großkunden am Tisch.","es-ES":"Un customer success manager frente a un cliente empresarial tenso en la mesa."}},"roleCaption":{"en":"You are the account lead, meeting your largest client in person.","de":"Sie sind der Account-Verantwortliche und treffen Ihren größten Kunden persönlich.","es-ES":"Eres el responsable de la cuenta, reuniéndote en persona con tu mayor cliente."},"scenario":{"en":"Your biggest enterprise client's product launch ran on your platform, and a six-hour outage took their checkout down on launch day. Their VP leans forward: \"We lost an estimated $400K and a lot of face. Why should we renew with you in ninety days?\" The renewal is worth 20% of your team's revenue. You have 60 seconds.","de":"Der Produktlaunch Ihres größten Großkunden lief auf Ihrer Plattform, und ein sechsstündiger Ausfall legte ihren Checkout am Launch-Tag lahm. Ihr VP beugt sich vor: \"Wir haben geschätzt 400.000 Dollar und viel Ansehen verloren. Warum sollten wir in neunzig Tagen verlängern?\" Die Verlängerung macht 20 % des Umsatzes Ihres Teams aus. Sie haben 60 Sekunden.","es-ES":"El lanzamiento de producto de tu mayor cliente empresarial se ejecutó en tu plataforma, y una caída de seis horas tumbó su pago el día del lanzamiento. Su VP se inclina hacia adelante: \"Perdimos unos 400.000 dólares y mucha imagen. ¿Por qué deberíamos renovar contigo en noventa días?\" La renovación supone el 20% de los ingresos de tu equipo. Tienes 60 segundos."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Own the outage fully and acknowledge the financial and reputational damage.","de":"Den Ausfall vollständig verantworten und den finanziellen und Reputationsschaden anerkennen.","es-ES":"Asumir la caída por completo y reconocer el daño financiero y reputacional."},{"en":"Present what has already changed to prevent a repeat.","de":"Darlegen, was bereits geändert wurde, um eine Wiederholung zu verhindern.","es-ES":"Presentar lo que ya ha cambiado para evitar que se repita."},{"en":"Offer concrete remediation: credits, SLA commitments, or a dedicated response plan.","de":"Konkrete Wiedergutmachung anbieten: Gutschriften, SLA-Zusagen oder einen dedizierten Reaktionsplan.","es-ES":"Ofrecer una compensación concreta: créditos, compromisos de SLA o un plan de respuesta dedicado."},{"en":"Reconnect to the future value and partnership, not just damage control.","de":"Den Bezug zum künftigen Mehrwert und zur Partnerschaft herstellen, nicht nur Schadensbegrenzung.","es-ES":"Reconectar con el valor futuro y la asociación, no solo con el control de daños."},{"en":"Invite their terms for rebuilding trust over the next ninety days.","de":"Ihre Bedingungen für den Wiederaufbau des Vertrauens in den nächsten neunzig Tagen einladen.","es-ES":"Invitar a que propongan sus condiciones para reconstruir la confianza en los próximos noventa días."}],"rubric":{"content":{"strong":"Owns the outage, shows concrete prevention and remediation, and pivots to future partnership value.","adequate":"Owns it and offers some remediation but is thin on prevention or future value.","weak":"Deflects blame, over-promises vaguely, or offers no credible plan."},"delivery":{"strong":"Composed, executive-level presence; honest without groveling, confident without dismissing.","adequate":"Generally steady but slips into either defensiveness or over-apology.","weak":"Nervous, evasive, or tone-deaf to the stakes."},"time":{"strong":"Uses 50-60 seconds with a clear arc from accountability to forward value.","adequate":"Covers main points but rushed or slightly incomplete.","weak":"Too short to be credible or rambles past the point."}},"modelAnswer":{"en":"You're right to ask, and I won't minimize it: the outage was on us, and it cost you money and credibility on the worst possible day. Since then we've added redundant failover, real-time launch-day monitoring, and a named engineer on standby for your events. I'm proposing service credits and a strengthened SLA in writing this week. Over the next ninety days, judge us on consistency, not promises. Tell me what proof you need to renew with confidence, and I'll build the plan around it.","de":"Ihre Frage ist berechtigt, und ich verharmlose nichts: Der Ausfall lag bei uns und hat Sie am denkbar schlechtesten Tag Geld und Glaubwürdigkeit gekostet. Seitdem haben wir redundantes Failover, Echtzeit-Monitoring für Launch-Tage und einen benannten Bereitschaftsingenieur für Ihre Events eingeführt. Ich schlage diese Woche schriftlich Gutschriften und ein verstärktes SLA vor. Beurteilen Sie uns in den nächsten neunzig Tagen an Konstanz, nicht an Versprechen. Sagen Sie mir, welchen Nachweis Sie brauchen, und ich baue den Plan darum herum.","es-ES":"Tienes razón en preguntar, y no lo minimizaré: la caída fue culpa nuestra y te costó dinero y credibilidad en el peor día posible. Desde entonces hemos añadido conmutación por error redundante, monitorización en tiempo real para días de lanzamiento y un ingeniero asignado de guardia para tus eventos. Esta semana propondré créditos de servicio y un SLA reforzado por escrito. En los próximos noventa días, júzganos por la constancia, no por promesas. Dime qué pruebas necesitas para renovar con confianza y construiré el plan a tu medida."}},
  {"id":"CS-3","type":"conflict","category":"conflict_resolution","department":"customer","difficulty":4,"media":{"scene":"office_1on1","alt":{"en":"A support lead on a tense phone call about a refund demand.","de":"Ein Support-Leiter in einem angespannten Telefonat über eine Rückerstattungsforderung.","es-ES":"Un responsable de soporte en una llamada tensa sobre una solicitud de reembolso."}},"roleCaption":{"en":"You are the Support Lead. A long-time customer demands a full refund.","de":"Sie sind der Support-Leiter. Ein langjähriger Kunde fordert eine volle Rückerstattung.","es-ES":"Eres el Responsable de Soporte. Un cliente de larga data exige un reembolso completo."},"scenario":{"en":"A loyal three-year customer calls demanding a full $12,000 annual refund after a feature they relied on was deprecated with little notice. Policy only allows you to refund the unused two months, roughly $2,000. \"After three years, this is how you treat me? Refund everything or I'm gone and I'll tell every peer in my network.\" You have 60 seconds.","de":"Ein treuer Kunde seit drei Jahren ruft an und fordert eine volle Jahresrückerstattung von 12.000 Dollar, nachdem eine Funktion, auf die er angewiesen war, mit kurzer Vorankündigung eingestellt wurde. Die Richtlinie erlaubt nur die Erstattung der ungenutzten zwei Monate, etwa 2.000 Dollar. \"Nach drei Jahren behandeln Sie mich so? Erstatten Sie alles, oder ich bin weg und erzähle es jedem in meinem Netzwerk.\" Sie haben 60 Sekunden.","es-ES":"Un cliente fiel de tres años llama exigiendo un reembolso anual completo de 12.000 dólares después de que una función de la que dependía se descontinuara con poco aviso. La política solo permite reembolsar los dos meses no usados, unos 2.000 dólares. \"¿Después de tres años, así me tratas? Devuélvelo todo o me voy y se lo contaré a cada colega de mi red.\" Tienes 60 segundos."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Validate their loyalty and the genuine frustration over the deprecation.","de":"Ihre Treue und die echte Frustration über die Einstellung würdigen.","es-ES":"Validar su fidelidad y la frustración genuina por la descontinuación."},{"en":"Be honest about the policy limit without hiding behind it.","de":"Ehrlich über die Richtliniengrenze sein, ohne sich dahinter zu verstecken.","es-ES":"Ser honesto sobre el límite de la política sin escudarse en ella."},{"en":"Offer creative value within your authority: credits, migration help, or a discount.","de":"Kreativen Mehrwert im Rahmen der Befugnisse anbieten: Gutschriften, Migrationshilfe oder Rabatt.","es-ES":"Ofrecer valor creativo dentro de tu autoridad: créditos, ayuda de migración o un descuento."},{"en":"Commit to escalating the refund request rather than a flat no.","de":"Zusagen, die Rückerstattungsanfrage zu eskalieren, statt eines glatten Neins.","es-ES":"Comprometerte a escalar la solicitud de reembolso en lugar de un no rotundo."},{"en":"Focus on retaining the relationship, not just resolving the transaction.","de":"Auf den Erhalt der Beziehung fokussieren, nicht nur auf die Transaktion.","es-ES":"Centrarse en conservar la relación, no solo en resolver la transacción."}],"rubric":{"content":{"strong":"Empathizes, is transparent about limits, offers creative remediation, escalates, and protects the relationship.","adequate":"Empathizes and offers something but either over-promises or hides behind policy.","weak":"Flat refusal, over-promises beyond authority, or ignores the relationship."},"delivery":{"strong":"Warm yet firm, manages a hostile tone without caving or hardening.","adequate":"Mostly composed but wavers toward appeasement or rigidity.","weak":"Defensive, scripted, or capitulates without managing the situation."},"time":{"strong":"Uses 50-60 seconds, balanced between empathy and concrete offers.","adequate":"Covers key beats but rushed or uneven.","weak":"Too brief to satisfy or rambles without a clear offer."}},"modelAnswer":{"en":"Three years means a lot to us, and I'm genuinely sorry we deprecated something you depended on without enough notice; that's on us. I want to be straight with you: my policy lets me refund the two unused months today, about $2,000. But I won't stop there. I can add account credit, personally manage your migration to the replacement, and I'll escalate your full-refund request to my director this afternoon and call you back by tomorrow. I'd rather earn back your trust than lose three good years.","de":"Drei Jahre bedeuten uns viel, und es tut mir aufrichtig leid, dass wir etwas, worauf Sie angewiesen waren, ohne ausreichende Vorankündigung eingestellt haben; das liegt an uns. Ich bin ehrlich: Meine Richtlinie erlaubt mir heute die Erstattung der zwei ungenutzten Monate, etwa 2.000 Dollar. Aber dabei bleibt es nicht. Ich kann ein Guthaben hinzufügen, Ihre Migration persönlich begleiten und Ihre Forderung nach voller Erstattung heute Nachmittag an meinen Direktor eskalieren und Sie bis morgen zurückrufen. Ich will lieber Ihr Vertrauen zurückgewinnen als drei gute Jahre verlieren.","es-ES":"Tres años significan mucho para nosotros, y lamento de verdad que descontinuáramos algo de lo que dependías sin suficiente aviso; es culpa nuestra. Quiero ser claro contigo: mi política me permite reembolsar hoy los dos meses no usados, unos 2.000 dólares. Pero no me quedaré ahí. Puedo añadir crédito en tu cuenta, gestionar personalmente tu migración al reemplazo y escalaré tu solicitud de reembolso completo a mi director esta tarde y te devolveré la llamada mañana. Prefiero recuperar tu confianza que perder tres buenos años."}},
  {"id":"LEG-1","type":"situational","category":"professional_communication","department":"legal","difficulty":2,"media":{"scene":"client_meeting","alt":{"en":"A procurement lead sits across a table reviewing a vendor contract.","de":"Ein Einkaufsleiter sitzt am Tisch und prüft einen Lieferantenvertrag.","es-ES":"Un responsable de compras revisa al otro lado de la mesa un contrato con un proveedor."}},"roleCaption":{"en":"You are negotiating a key contract clause with a vendor.","de":"Sie verhandeln eine zentrale Vertragsklausel mit einem Lieferanten.","es-ES":"Estás negociando una cláusula clave del contrato con un proveedor."},"scenario":{"en":"You are across the table from a strategic vendor your company needs. They want to cap their liability at one month's fees and strike the indemnity clause entirely. Your business team is eager to sign this quarter. You have 60 seconds to hold firm on the liability and indemnity terms without blowing up the relationship, and to explain why these protections are non-negotiable.","de":"Sie sitzen einem strategischen Lieferanten gegenüber, den Ihr Unternehmen braucht. Er will seine Haftung auf eine Monatsgebühr begrenzen und die Freistellungsklausel ganz streichen. Ihr Geschäftsteam will dieses Quartal unterschreiben. Sie haben 60 Sekunden, um bei Haftung und Freistellung standhaft zu bleiben, ohne die Beziehung zu sprengen, und zu erklären, warum diese Schutzklauseln nicht verhandelbar sind.","es-ES":"Estás frente a un proveedor estratégico que tu empresa necesita. Quieren limitar su responsabilidad a una mensualidad y eliminar por completo la cláusula de indemnización. Tu equipo de negocio quiere firmar este trimestre. Tienes 60 segundos para mantenerte firme en responsabilidad e indemnización sin romper la relación, y explicar por qué estas protecciones no son negociables."},"weights":{"content":0.55,"delivery":0.25,"time":0.2},"keyPoints":[{"en":"Affirm you want the deal and value the partnership.","de":"Bekräftigen Sie, dass Sie den Vertrag wollen und die Partnerschaft schätzen.","es-ES":"Afirma que quieres el acuerdo y valoras la colaboración."},{"en":"Explain liability caps must reflect realistic exposure, not one month's fees.","de":"Erklären Sie, dass die Haftungsobergrenze das reale Risiko widerspiegeln muss, nicht eine Monatsgebühr.","es-ES":"Explica que el límite de responsabilidad debe reflejar el riesgo real, no una mensualidad."},{"en":"Tie indemnity to specific risks like IP and data breach, not open-ended.","de":"Knüpfen Sie die Freistellung an konkrete Risiken wie IP und Datenschutzverletzungen, nicht unbegrenzt.","es-ES":"Vincula la indemnización a riesgos concretos como propiedad intelectual y filtración de datos, no abierta."},{"en":"Offer a concession elsewhere to keep momentum.","de":"Bieten Sie an anderer Stelle ein Zugeständnis an, um den Schwung zu halten.","es-ES":"Ofrece una concesión en otro punto para mantener el impulso."},{"en":"Set a clear next step and timeline to protect the quarter.","de":"Legen Sie einen klaren nächsten Schritt und Zeitplan fest, um das Quartal zu schützen.","es-ES":"Fija un siguiente paso y un plazo claros para proteger el trimestre."}],"rubric":{"content":{"strong":"Holds firm on liability and indemnity, justifies each with concrete risk, and offers a workable path forward.","adequate":"States the position but gives thin justification or no path to close.","weak":"Caves on the terms or fails to explain why they matter."},"delivery":{"strong":"Calm, collaborative, and confident; firm without being adversarial.","adequate":"Mostly steady but occasionally defensive or hesitant.","weak":"Combative or unsure, damaging rapport."},"time":{"strong":"Covers position, rationale, and next step within the minute.","adequate":"Runs slightly long or omits one element.","weak":"Rambles or stops well short."}},"modelAnswer":{"en":"I want to get this signed too, and we value you as a partner. But a one-month liability cap doesn't match the exposure if something goes wrong, and we can't strike indemnity entirely. Let's keep indemnity but scope it tightly to IP and data-breach claims, and set the cap at twelve months' fees. In exchange, I can flex on payment terms and the audit frequency. If you agree in principle today, I'll turn the redline around by Thursday so we still close this quarter.","de":"Ich will das auch unterschreiben, und wir schätzen Sie als Partner. Aber eine Haftungsgrenze von einem Monat passt nicht zum Risiko, wenn etwas schiefgeht, und wir können die Freistellung nicht ganz streichen. Behalten wir die Freistellung, aber eng begrenzt auf IP- und Datenschutzfälle, und setzen die Grenze auf zwölf Monatsgebühren. Im Gegenzug bin ich bei Zahlungszielen und Auditfrequenz flexibel. Stimmen Sie heute grundsätzlich zu, liefere ich das Redline bis Donnerstag, damit wir dieses Quartal abschließen.","es-ES":"Yo también quiero firmar, y te valoramos como socio. Pero un límite de un mes no refleja el riesgo si algo sale mal, y no podemos eliminar la indemnización del todo. Mantengámosla, pero acotada a propiedad intelectual y filtración de datos, y fijemos el límite en doce mensualidades. A cambio, puedo flexibilizar los plazos de pago y la frecuencia de auditoría. Si lo acuerdas hoy en principio, te devuelvo el redline el jueves y cerramos este trimestre."}},
  {"id":"LEG-2","type":"conflict","category":"conflict_resolution","department":"legal","difficulty":3,"media":{"scene":"office_1on1","alt":{"en":"A compliance officer talks with a product leader in an office.","de":"Eine Compliance-Verantwortliche spricht mit einer Produktverantwortlichen im Büro.","es-ES":"Una responsable de cumplimiento habla con un líder de producto en una oficina."}},"roleCaption":{"en":"You must stop a launch over a compliance gap.","de":"Sie müssen einen Launch wegen einer Compliance-Lücke stoppen.","es-ES":"Debes detener un lanzamiento por una brecha de cumplimiento."},"scenario":{"en":"The VP of Product wants to ship a new feature on Monday. You've found it processes EU customer data without a lawful basis or completed DPIA, a clear GDPR gap. The VP says the deadline is committed to the board and a delay costs revenue. You have 60 seconds to push back, make the risk concrete, and propose a path that doesn't just say no.","de":"Der Produkt-VP will am Montag ein neues Feature ausliefern. Sie haben festgestellt, dass es EU-Kundendaten ohne Rechtsgrundlage und ohne abgeschlossene DSFA verarbeitet, eine klare DSGVO-Lücke. Der VP sagt, der Termin sei dem Vorstand zugesagt und eine Verzögerung koste Umsatz. Sie haben 60 Sekunden, um Widerstand zu leisten, das Risiko greifbar zu machen und einen Weg vorzuschlagen, der nicht nur Nein sagt.","es-ES":"El VP de Producto quiere lanzar una nueva función el lunes. Has descubierto que procesa datos de clientes de la UE sin base legal ni EIPD completada, una brecha clara del RGPD. El VP dice que la fecha está comprometida con el consejo y que un retraso cuesta ingresos. Tienes 60 segundos para frenarlo, concretar el riesgo y proponer un camino que no sea solo decir que no."},"weights":{"content":0.6,"delivery":0.2,"time":0.2},"keyPoints":[{"en":"Acknowledge the revenue pressure and the board commitment.","de":"Erkennen Sie den Umsatzdruck und die Vorstandszusage an.","es-ES":"Reconoce la presión de ingresos y el compromiso con el consejo."},{"en":"Name the specific gap: no lawful basis, no DPIA, GDPR exposure.","de":"Benennen Sie die konkrete Lücke: keine Rechtsgrundlage, keine DSFA, DSGVO-Risiko.","es-ES":"Nombra la brecha concreta: sin base legal, sin EIPD, riesgo de RGPD."},{"en":"Quantify the downside: fines up to 4% of global revenue and reputational harm.","de":"Beziffern Sie das Risiko: Bußgelder bis zu 4 % des weltweiten Umsatzes und Reputationsschaden.","es-ES":"Cuantifica el riesgo: multas de hasta el 4% de la facturación global y daño reputacional."},{"en":"Offer a phased path: ship to non-EU users now, EU after DPIA.","de":"Bieten Sie einen stufenweisen Weg: jetzt für Nicht-EU-Nutzer, EU nach DSFA.","es-ES":"Ofrece un camino por fases: lanzar a usuarios no UE ahora, UE tras la EIPD."},{"en":"Commit to a fast, dated turnaround on the DPIA.","de":"Verpflichten Sie sich zu einer schnellen, terminierten Bearbeitung der DSFA.","es-ES":"Comprométete a completar la EIPD con rapidez y fecha concreta."}],"rubric":{"content":{"strong":"Clearly states the legal blocker, quantifies exposure, and offers a credible phased alternative with a timeline.","adequate":"Identifies the gap but is vague on consequences or offers no alternative.","weak":"Either rolls over to the deadline or blocks with no path forward."},"delivery":{"strong":"Firm, respectful, solution-oriented; partners rather than lectures.","adequate":"Generally composed but slips into either apology or rigidity.","weak":"Defensive, preachy, or easily talked out of the position."},"time":{"strong":"Risk, rationale, and alternative all land inside 60 seconds.","adequate":"Covers most but runs over or drops the alternative.","weak":"Loses the thread or never reaches a proposal."}},"modelAnswer":{"en":"I hear the board committed to Monday and a slip costs us. I'm not trying to kill this, but as built it processes EU data with no lawful basis and no DPIA, that's a direct GDPR violation, with fines up to four percent of global revenue and real reputational risk. Here's my proposal: ship Monday to non-EU users only, and I'll fast-track the DPIA and lawful-basis review to clear EU users by Friday. That protects the launch and keeps us defensible. Can we align leadership on that?","de":"Ich weiß, der Vorstand hat Montag zugesagt und Verzug kostet uns. Ich will das nicht stoppen, aber so verarbeitet es EU-Daten ohne Rechtsgrundlage und ohne DSFA, ein direkter DSGVO-Verstoß, mit Bußgeldern bis zu vier Prozent des weltweiten Umsatzes und echtem Reputationsrisiko. Mein Vorschlag: Montag nur für Nicht-EU-Nutzer ausliefern, und ich beschleunige DSFA und Prüfung der Rechtsgrundlage, um EU-Nutzer bis Freitag freizugeben. Das schützt den Launch und uns. Können wir die Führung darauf einschwören?","es-ES":"Sé que el consejo comprometió el lunes y un retraso nos cuesta. No busco frenarlo, pero tal como está procesa datos de la UE sin base legal ni EIPD, una infracción directa del RGPD, con multas de hasta el cuatro por ciento de la facturación global y riesgo reputacional real. Mi propuesta: lanzar el lunes solo a usuarios no UE, y acelero la EIPD y la revisión de base legal para habilitar la UE el viernes. Así protegemos el lanzamiento y quedamos defendibles. ¿Alineamos a la dirección en esto?"}},
  {"id":"LEG-3","type":"situational","category":"strategic_thinking","department":"legal","difficulty":4,"media":{"scene":"exec_committee","alt":{"en":"A general counsel briefs the executive committee in a tense room.","de":"Eine Chefjuristin informiert den Vorstand in einem angespannten Raum.","es-ES":"Una asesora jurídica informa al comité ejecutivo en una sala tensa."}},"roleCaption":{"en":"You must brief the board on a data breach disclosure decision.","de":"Sie müssen den Vorstand über eine Datenschutzverletzung und Meldung informieren.","es-ES":"Debes informar al comité sobre la divulgación de una brecha de datos."},"scenario":{"en":"As General Counsel, you're in front of the executive committee. A breach exposed personal data of roughly 80,000 customers eighteen hours ago. Some on the team want to wait until you 'know more' before notifying regulators and customers. The 72-hour GDPR clock is running and several US states have their own deadlines. You have 60 seconds to give a clear recommendation and own the decision.","de":"Als Chefjuristin stehen Sie vor dem Vorstand. Vor achtzehn Stunden wurden bei einem Vorfall personenbezogene Daten von rund 80.000 Kunden offengelegt. Einige im Team wollen warten, bis Sie 'mehr wissen', bevor Behörden und Kunden informiert werden. Die 72-Stunden-Frist der DSGVO läuft, und mehrere US-Bundesstaaten haben eigene Fristen. Sie haben 60 Sekunden für eine klare Empfehlung und müssen die Entscheidung verantworten.","es-ES":"Como asesora jurídica, estás ante el comité ejecutivo. Hace dieciocho horas una brecha expuso datos personales de unos 80.000 clientes. Algunos del equipo quieren esperar a 'saber más' antes de notificar a reguladores y clientes. El reloj de 72 horas del RGPD corre y varios estados de EE. UU. tienen sus propios plazos. Tienes 60 segundos para dar una recomendación clara y asumir la decisión."},"weights":{"content":0.6,"delivery":0.25,"time":0.15},"keyPoints":[{"en":"State the recommendation up front: notify within the 72-hour window.","de":"Nennen Sie die Empfehlung vorab: Meldung innerhalb der 72-Stunden-Frist.","es-ES":"Da la recomendación de entrada: notificar dentro del plazo de 72 horas."},{"en":"Explain that waiting for full facts is not a legal defense for delay.","de":"Erklären Sie, dass Warten auf alle Fakten keine Rechtfertigung für Verzug ist.","es-ES":"Explica que esperar a tener todos los datos no justifica el retraso."},{"en":"Address multi-jurisdiction deadlines: GDPR plus US state laws.","de":"Adressieren Sie mehrere Fristen: DSGVO plus US-Bundesstaatengesetze.","es-ES":"Aborda los plazos multijurisdicción: RGPD más leyes estatales de EE. UU."},{"en":"Frame disclosure as risk-reducing, not just compliance.","de":"Stellen Sie die Meldung als risikomindernd dar, nicht nur als Pflicht.","es-ES":"Plantea la divulgación como reductora de riesgo, no solo cumplimiento."},{"en":"Lay out immediate next steps and who does what.","de":"Legen Sie die nächsten Schritte dar und wer was übernimmt.","es-ES":"Expón los próximos pasos inmediatos y quién hace qué."}],"rubric":{"content":{"strong":"Gives a decisive notify recommendation, grounds it in the 72-hour rule and state laws, and sets concrete next steps.","adequate":"Recommends disclosure but is fuzzy on deadlines or next steps.","weak":"Equivocates, defers, or counsels waiting in a way that creates legal exposure."},"delivery":{"strong":"Calm, authoritative, owns the call under pressure without hedging.","adequate":"Mostly composed but hedges or over-qualifies.","weak":"Anxious or evasive; fails to project command of the decision."},"time":{"strong":"Recommendation, rationale, and next steps delivered crisply within the minute.","adequate":"Slightly long or thin on one element.","weak":"Runs over badly or never lands a clear recommendation."}},"modelAnswer":{"en":"My recommendation is clear: we notify the regulators within the 72-hour window and prepare customer notice now. Waiting until we 'know everything' isn't a defense; GDPR expects notification on reasonable suspicion, and several US states have their own clocks already ticking. Early, honest disclosure reduces our liability and protects trust far more than a delay ever will. Today I'll file the regulator notice with what we know, draft customer comms, and stand up the forensic timeline. I'll own this decision, but I need the committee aligned in the next hour.","de":"Meine Empfehlung ist klar: Wir melden den Behörden innerhalb der 72-Stunden-Frist und bereiten jetzt die Kundeninformation vor. Auf vollständiges Wissen zu warten ist keine Verteidigung; die DSGVO erwartet die Meldung bei begründetem Verdacht, und mehrere US-Staaten haben eigene laufende Fristen. Frühe, ehrliche Offenlegung senkt unsere Haftung und schützt Vertrauen weit mehr als jeder Verzug. Heute reiche ich die Behördenmeldung mit unserem Kenntnisstand ein, entwerfe die Kundenkommunikation und baue die forensische Chronologie auf. Ich verantworte die Entscheidung, brauche aber das Gremium in der nächsten Stunde geeint.","es-ES":"Mi recomendación es clara: notificamos a los reguladores dentro del plazo de 72 horas y preparamos ya el aviso a clientes. Esperar a 'saberlo todo' no es una defensa; el RGPD exige notificar ante sospecha razonable, y varios estados de EE. UU. ya tienen sus relojes en marcha. La divulgación temprana y honesta reduce nuestra responsabilidad y protege la confianza mucho más que cualquier demora. Hoy presento la notificación al regulador con lo que sabemos, redacto la comunicación a clientes y monto la cronología forense. Asumo la decisión, pero necesito al comité alineado en la próxima hora."}},
  {"id":"LEAD-1","type":"situational","category":"leadership_decisions","department":"leadership","difficulty":2,"media":{"scene":"office_1on1","alt":{"en":"A manager standing in front of a small team in an open office","de":"Eine Führungskraft steht vor einem kleinen Team in einem Großraumbüro","es-ES":"Un responsable de pie frente a un equipo pequeño en una oficina abierta"}},"roleCaption":{"en":"You are the team lead addressing your team","de":"Du bist die Teamleitung und sprichst zu deinem Team","es-ES":"Eres el líder del equipo y te diriges a tu equipo"},"scenario":{"en":"Your team just learned that the big client account you spent three months pitching for went to a competitor. The room is quiet and deflated. People worked nights and weekends on this. You have 60 seconds to address them before everyone drifts back to their desks. They need to hear from you now.","de":"Dein Team hat gerade erfahren, dass der große Kunde, um den ihr drei Monate lang geworben habt, an einen Wettbewerber ging. Der Raum ist still und niedergeschlagen. Die Leute haben Nächte und Wochenenden investiert. Du hast 60 Sekunden, um zu ihnen zu sprechen, bevor alle an ihre Schreibtische zurückkehren. Sie müssen jetzt etwas von dir hören.","es-ES":"Tu equipo acaba de enterarse de que la gran cuenta de cliente por la que trabajasteis tres meses se la llevó un competidor. La sala está en silencio y desanimada. La gente trabajó noches y fines de semana en esto. Tienes 60 segundos para hablarles antes de que todos vuelvan a sus mesas. Necesitan oírte ahora."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Acknowledge the loss honestly without sugarcoating it","de":"Den Verlust ehrlich anerkennen, ohne ihn zu beschönigen","es-ES":"Reconoce la pérdida con honestidad, sin endulzarla"},{"en":"Recognise the specific effort and sacrifice the team made","de":"Den konkreten Einsatz und das Opfer des Teams würdigen","es-ES":"Reconoce el esfuerzo y sacrificio concretos del equipo"},{"en":"Reframe the work as building capability, not wasted effort","de":"Die Arbeit als Kompetenzaufbau umdeuten, nicht als vergeudet","es-ES":"Replantea el trabajo como creación de capacidad, no esfuerzo perdido"},{"en":"Give one clear, forward-looking next step","de":"Einen klaren, nach vorn gerichteten nächsten Schritt geben","es-ES":"Da un siguiente paso claro y orientado al futuro"}],"rubric":{"content":{"strong":"Names the loss directly, validates the team's effort, reframes it as learning, and offers a concrete next step.","adequate":"Acknowledges the loss and effort but stays vague on what comes next.","weak":"Either denies the disappointment with empty positivity or dwells only on blame."},"delivery":{"strong":"Calm, warm and steady; pace matches the somber mood then lifts with the forward message.","adequate":"Clear but flat, or slightly rushed past the emotional acknowledgement.","weak":"Monotone, dismissive, or visibly flustered; undermines credibility."},"time":{"strong":"Lands the full message within 55-60 seconds with natural pauses.","adequate":"Covers the core in time but cuts the forward step short.","weak":"Runs well over or finishes far too early with thin content."}},"modelAnswer":{"en":"I won't pretend this doesn't sting. We lost it, and I know how much of yourselves you poured in, the late nights, the weekends. That effort was real and it mattered. But here's what I saw: this team got sharper, faster, and tighter than ever. That capability doesn't disappear with one deal. Tomorrow we'll debrief what we learned and aim it at the next opportunity. I'm proud of you. Take tonight, then we go again.","de":"Ich tue nicht so, als täte das nicht weh. Wir haben verloren, und ich weiß, wie viel ihr gegeben habt, die langen Nächte, die Wochenenden. Dieser Einsatz war echt und er zählte. Aber ich habe gesehen: Dieses Team wurde schärfer und stärker als je zuvor. Diese Fähigkeit verschwindet nicht mit einem Deal. Morgen werten wir aus, was wir gelernt haben, und richten es auf die nächste Chance. Ich bin stolz auf euch. Nehmt euch den Abend, dann geht es weiter.","es-ES":"No voy a fingir que esto no duele. Lo perdimos, y sé cuánto disteis de vosotros, las noches, los fines de semana. Ese esfuerzo fue real e importó. Pero esto es lo que vi: este equipo se volvió más afilado y unido que nunca. Esa capacidad no desaparece con un solo trato. Mañana analizaremos lo aprendido y lo dirigiremos a la próxima oportunidad. Estoy orgulloso de vosotros. Descansad esta noche, y volvemos a empezar."}},
  {"id":"LEAD-2","type":"situational","category":"leadership_decisions","department":"leadership","difficulty":3,"media":{"scene":"boardroom","alt":{"en":"An executive at a podium addressing a full all-hands meeting","de":"Eine Führungskraft am Rednerpult spricht vor einer vollen Betriebsversammlung","es-ES":"Un directivo en un podio dirigiéndose a una reunión general completa"}},"roleCaption":{"en":"You are the CEO at the company all-hands","de":"Du bist der CEO bei der Betriebsversammlung","es-ES":"Eres el CEO en la reunión general de la empresa"},"scenario":{"en":"You are about to announce an unpopular strategy pivot: the company is discontinuing its flagship product to bet everything on a new platform. Hundreds of employees built their careers on that product. The room is tense and skeptical. You have 60 seconds to make the case and keep them with you, not lose half the company to fear.","de":"Du verkündest gleich einen unbeliebten Strategiewechsel: Das Unternehmen stellt sein Vorzeigeprodukt ein, um alles auf eine neue Plattform zu setzen. Hunderte Mitarbeiter haben ihre Karriere auf diesem Produkt aufgebaut. Der Raum ist angespannt und skeptisch. Du hast 60 Sekunden, um zu überzeugen und sie bei dir zu halten, statt das halbe Unternehmen an die Angst zu verlieren.","es-ES":"Estás a punto de anunciar un giro estratégico impopular: la empresa discontinúa su producto estrella para apostarlo todo a una nueva plataforma. Cientos de empleados construyeron su carrera sobre ese producto. La sala está tensa y escéptica. Tienes 60 segundos para defender la decisión y mantenerlos contigo, sin perder a media empresa por el miedo."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"State the decision plainly and own it as yours","de":"Die Entscheidung klar benennen und als deine eigene vertreten","es-ES":"Expón la decisión con claridad y asúmela como tuya"},{"en":"Give the honest strategic reason behind the pivot","de":"Den ehrlichen strategischen Grund für den Wechsel nennen","es-ES":"Da la razón estratégica honesta detrás del giro"},{"en":"Honour the value of the flagship and the people behind it","de":"Den Wert des Vorzeigeprodukts und der Menschen würdigen","es-ES":"Honra el valor del producto estrella y de su gente"},{"en":"Address the fear directly: what this means for jobs and roles","de":"Die Angst direkt ansprechen: Was das für Jobs und Rollen bedeutet","es-ES":"Aborda el miedo directamente: qué significa para empleos y roles"},{"en":"Paint a concrete, credible picture of the future you're building","de":"Ein konkretes, glaubwürdiges Bild der Zukunft zeichnen","es-ES":"Pinta una imagen concreta y creíble del futuro que construyes"}],"rubric":{"content":{"strong":"Clear decision, honest rationale, respect for the past, direct on jobs, and a credible vision.","adequate":"Covers the decision and reason but glosses over the fear or the human cost.","weak":"Vague corporate language, no real rationale, ignores the emotional reality."},"delivery":{"strong":"Confident and grounded; conveys conviction without arrogance, steady under skepticism.","adequate":"Clear but hedging or over-rehearsed; conviction wavers.","weak":"Defensive, robotic, or apologetic; loses the room's trust."},"time":{"strong":"Delivers the full arc within 55-60 seconds with deliberate pacing.","adequate":"Hits the main points but rushes the vision or runs slightly long.","weak":"Overruns badly or ends abruptly without addressing fear or future."}},"modelAnswer":{"en":"This is my call, so let me be direct: we are sunsetting our flagship to go all-in on the new platform. That product built this company, and many of you built it. I will never diminish that. But the market has moved, and standing still is the real risk. Your jobs are not disappearing, they're shifting toward where the future is. Over the next quarter, every role gets a clear path forward. I'm not asking for blind faith. I'm asking you to build the next chapter with me.","de":"Das ist meine Entscheidung, also klar und direkt: Wir stellen unser Vorzeigeprodukt ein und setzen voll auf die neue Plattform. Dieses Produkt hat das Unternehmen aufgebaut, und viele von euch haben es geschaffen. Das werde ich nie schmälern. Aber der Markt hat sich bewegt, und Stillstand ist das eigentliche Risiko. Eure Jobs verschwinden nicht, sie verlagern sich dorthin, wo die Zukunft liegt. Im nächsten Quartal bekommt jede Rolle einen klaren Weg. Ich bitte nicht um blinden Glauben. Ich bitte euch, das nächste Kapitel mit mir zu bauen.","es-ES":"Esta es mi decisión, así que seré directo: retiramos nuestro producto estrella para apostarlo todo a la nueva plataforma. Ese producto construyó esta empresa, y muchos de vosotros lo construisteis. Jamás lo minimizaré. Pero el mercado se ha movido, y quedarnos quietos es el verdadero riesgo. Vuestros empleos no desaparecen, se desplazan hacia donde está el futuro. En el próximo trimestre, cada rol tendrá un camino claro. No os pido fe ciega. Os pido que construyáis el próximo capítulo conmigo."}},
  {"id":"LEAD-3","type":"conflict","category":"leadership_decisions","department":"leadership","difficulty":4,"media":{"scene":"exec_committee","alt":{"en":"A leader standing at a tense executive committee table facing skeptical peers","de":"Eine Führungskraft am angespannten Vorstandstisch gegenüber skeptischen Kollegen","es-ES":"Un líder de pie ante una mesa de comité ejecutivo tenso frente a pares escépticos"}},"roleCaption":{"en":"You are defending your decision to the executive committee","de":"Du verteidigst deine Entscheidung vor dem Vorstand","es-ES":"Defiendes tu decisión ante el comité ejecutivo"},"scenario":{"en":"You made a tough call last quarter: you killed a peer's pet project to fund a riskier bet that is now your responsibility. It hasn't paid off yet, and the numbers look bad. Three executive peers, including the one whose project you cut, are openly questioning your judgment in this committee. You have 60 seconds to defend the decision without burning relationships you still need.","de":"Du hast letztes Quartal eine harte Entscheidung getroffen: Du hast das Lieblingsprojekt eines Kollegen gestoppt, um auf eine riskantere Wette zu setzen, die nun deine Verantwortung ist. Sie hat sich noch nicht ausgezahlt, und die Zahlen sehen schlecht aus. Drei Vorstandskollegen, darunter der, dessen Projekt du gestrichen hast, zweifeln offen an deinem Urteil. Du hast 60 Sekunden, um die Entscheidung zu verteidigen, ohne Beziehungen zu verbrennen, die du noch brauchst.","es-ES":"El trimestre pasado tomaste una decisión difícil: cancelaste el proyecto favorito de un colega para financiar una apuesta más arriesgada que ahora es tu responsabilidad. Aún no ha dado frutos y los números pintan mal. Tres pares directivos, incluido aquel cuyo proyecto cortaste, cuestionan abiertamente tu criterio en este comité. Tienes 60 segundos para defender la decisión sin quemar relaciones que aún necesitas."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Own the decision and current results without deflecting blame","de":"Entscheidung und aktuelle Ergebnisse ohne Schuldabwälzung vertreten","es-ES":"Asume la decisión y los resultados sin desviar la culpa"},{"en":"Restate the strategic logic that still holds true","de":"Die strategische Logik wiederholen, die weiterhin gilt","es-ES":"Reafirma la lógica estratégica que sigue siendo válida"},{"en":"Acknowledge the peer's project and the cost to them respectfully","de":"Das Projekt des Kollegen und dessen Verlust respektvoll anerkennen","es-ES":"Reconoce con respeto el proyecto del colega y su coste"},{"en":"Show evidence the bet is tracking, with leading indicators","de":"Mit Frühindikatoren zeigen, dass die Wette auf Kurs ist","es-ES":"Muestra con indicadores tempranos que la apuesta avanza"},{"en":"Offer accountability: a clear checkpoint to reassess together","de":"Verantwortung bieten: einen klaren Prüfpunkt zur gemeinsamen Neubewertung","es-ES":"Ofrece rendición de cuentas: un punto de control para reevaluar juntos"}],"rubric":{"content":{"strong":"Owns results, reaffirms logic, respects the peer, cites leading indicators, and sets a checkpoint.","adequate":"Defends the logic and owns it but thin on evidence or on repairing the peer relationship.","weak":"Deflects blame, ignores the human cost, or offers no path to accountability."},"delivery":{"strong":"Composed under pressure; firm but non-defensive, respectful toward challengers.","adequate":"Holds steady but occasionally defensive or overly conciliatory.","weak":"Combative, rattled, or capitulating; loses authority in the room."},"time":{"strong":"Full, balanced response in 55-60 seconds with controlled pacing.","adequate":"Covers core points but rushes evidence or the checkpoint.","weak":"Runs over, or ends thin without accountability or respect for the peer."}},"modelAnswer":{"en":"Let me own this plainly: I made the call, and the numbers today aren't where I want them. I'm accountable for that. But the logic that drove it still holds, the market window for the old project was closing, and this bet positions us where growth is moving. Maria, cutting your project cost you and your team something real, and I respect that. What I'm seeing now are early signals, engagement and pipeline, that point the right way. I'm not asking for a blank check. Let's set a hard checkpoint in 90 days and judge it on evidence, together.","de":"Lass es mich klar vertreten: Ich habe entschieden, und die Zahlen sind heute nicht da, wo ich sie haben will. Dafür stehe ich gerade. Aber die Logik dahinter gilt weiterhin, das Marktfenster für das alte Projekt schloss sich, und diese Wette positioniert uns dort, wohin das Wachstum geht. Maria, dein Projekt zu streichen hat dich und dein Team etwas Echtes gekostet, das respektiere ich. Was ich jetzt sehe, sind frühe Signale, Engagement und Pipeline, die in die richtige Richtung zeigen. Ich bitte nicht um einen Blankoscheck. Setzen wir in 90 Tagen einen festen Prüfpunkt und beurteilen es gemeinsam anhand der Fakten.","es-ES":"Déjenme asumirlo con claridad: yo tomé la decisión, y los números de hoy no están donde los quiero. Soy responsable de eso. Pero la lógica que la impulsó sigue siendo válida: la ventana de mercado del proyecto anterior se cerraba, y esta apuesta nos sitúa donde se mueve el crecimiento. María, cancelar tu proyecto te costó algo real a ti y a tu equipo, y lo respeto. Lo que veo ahora son señales tempranas, compromiso y pipeline, que apuntan en la dirección correcta. No pido un cheque en blanco. Fijemos un punto de control firme a 90 días y juzguémoslo con evidencia, juntos."}},
  {"id":"LEAD-4","type":"situational","category":"leadership_decisions","department":"leadership","difficulty":3,"media":{"scene":"exec_committee","alt":{"en":"A reorganization announcement slide projected in a tense executive committee room.","de":"Eine Reorganisations-Ankündigungsfolie, projiziert in einem angespannten Vorstandsraum.","es-ES":"Una diapositiva de anuncio de reorganización proyectada en una sala de comité ejecutivo tensa."}},"roleCaption":{"en":"You are a senior director addressing your department right after a reorg is announced.","de":"Sie sind Senior Director und sprechen Ihre Abteilung direkt nach der Ankündigung einer Reorganisation an.","es-ES":"Eres director senior y te diriges a tu departamento justo después de anunciarse una reorganización."},"scenario":{"en":"Leadership has just announced a company-wide reorganization. Three of your team's reporting lines are changing, two roles are being merged, and rumors of layoffs are spreading. Your team looks anxious and silent. In 60 seconds, address them out loud: acknowledge the uncertainty honestly, give them what clarity you can, and set the tone for how you'll move forward together.","de":"Die Führung hat soeben eine unternehmensweite Reorganisation angekündigt. Drei Berichtslinien Ihres Teams ändern sich, zwei Rollen werden zusammengelegt, und Gerüchte über Entlassungen verbreiten sich. Ihr Team wirkt ängstlich und schweigt. Sprechen Sie es in 60 Sekunden laut an: Erkennen Sie die Unsicherheit ehrlich an, geben Sie so viel Klarheit wie möglich und geben Sie den Ton vor, wie Sie gemeinsam weitermachen.","es-ES":"La dirección acaba de anunciar una reorganización en toda la empresa. Tres líneas de reporte de tu equipo cambian, dos puestos se fusionan y corren rumores de despidos. Tu equipo se ve ansioso y en silencio. En 60 segundos, diríbete a ellos en voz alta: reconoce la incertidumbre con honestidad, da la claridad que puedas y marca el tono de cómo avanzaréis juntos."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Acknowledge the uncertainty honestly instead of pretending all is fine.","de":"Erkennen Sie die Unsicherheit ehrlich an, statt so zu tun, als sei alles in Ordnung.","es-ES":"Reconoce la incertidumbre con honestidad en lugar de fingir que todo va bien."},{"en":"Share what you know and clearly name what is still unknown.","de":"Teilen Sie, was Sie wissen, und benennen Sie klar, was noch unklar ist.","es-ES":"Comparte lo que sabes y nombra con claridad lo que aún se desconoce."},{"en":"Commit to transparent, regular updates as decisions firm up.","de":"Verpflichten Sie sich zu transparenten, regelmäßigen Updates, sobald Entscheidungen feststehen.","es-ES":"Comprométete a actualizaciones transparentes y regulares según se concreten las decisiones."},{"en":"Reaffirm your support and the team's continued value.","de":"Bekräftigen Sie Ihre Unterstützung und den fortbestehenden Wert des Teams.","es-ES":"Reafirma tu apoyo y el valor continuo del equipo."},{"en":"Invite questions and offer one-on-one conversations.","de":"Laden Sie zu Fragen ein und bieten Sie Einzelgespräche an.","es-ES":"Invita a preguntas y ofrece conversaciones individuales."}],"rubric":{"content":{"strong":"Honestly acknowledges uncertainty, separates known from unknown, commits to updates, and reassures without making promises they cannot keep.","adequate":"Addresses the change and offers some reassurance but is vague on what is known versus unknown or over-promises.","weak":"Dismisses concerns, hides behind corporate language, or makes unrealistic guarantees."},"delivery":{"strong":"Calm, steady, and warm; pacing conveys composure and genuine empathy.","adequate":"Generally composed but occasionally rushed or flat in tone.","weak":"Anxious, defensive, or robotic delivery that amplifies fear."},"time":{"strong":"Uses 55-65 seconds with a clear arc and confident close.","adequate":"Slightly under or over time but covers the essentials.","weak":"Far too short to reassure or rambles well past time."}},"modelAnswer":{"en":"I won't pretend today is easy. The reorg changes some reporting lines and merges two roles, and I know that raises real questions. Here's what I can tell you: no layoff decisions affecting this team have been made, and I will not let you hear important news through rumor. I'll share verified updates every week. You matter to this company and to me. Bring me your questions, and let's grab time one-on-one this week.","de":"Ich tue nicht so, als wäre heute leicht. Die Reorganisation ändert einige Berichtslinien und legt zwei Rollen zusammen, und das wirft echte Fragen auf. Was ich Ihnen sagen kann: Es gibt keine Entlassungsentscheidung für dieses Team, und Sie sollen Wichtiges nicht über Gerüchte erfahren. Ich teile jede Woche geprüfte Updates. Sie sind für dieses Unternehmen und für mich wichtig. Bringen Sie mir Ihre Fragen, und lassen Sie uns diese Woche einzeln sprechen.","es-ES":"No fingiré que hoy es fácil. La reorganización cambia algunas líneas de reporte y fusiona dos puestos, y sé que eso genera dudas reales. Esto puedo deciros: no hay decisiones de despido que afecten a este equipo, y no permitiré que os enteréis de algo importante por rumores. Compartiré actualizaciones verificadas cada semana. Sois importantes para la empresa y para mí. Traedme vuestras preguntas y veámonos uno a uno esta semana."}},
  {"id":"LEAD-5","type":"conflict","category":"conflict_resolution","department":"leadership","difficulty":4,"media":{"scene":"office_1on1","alt":{"en":"A closed-door one-on-one office with two chairs facing each other.","de":"Ein geschlossenes Einzelbüro mit zwei einander zugewandten Stühlen.","es-ES":"Una oficina de reunión individual a puerta cerrada con dos sillas enfrentadas."}},"roleCaption":{"en":"You are a team lead confronting a brilliant but toxic top performer.","de":"Sie sind Teamleiter und konfrontieren einen brillanten, aber toxischen Spitzenperformer.","es-ES":"Eres líder de equipo y confrontas a un empleado brillante pero tóxico."},"scenario":{"en":"Your highest-performing engineer ships outstanding work but belittles teammates, dominates meetings, and two people have quietly asked to transfer because of him. He knows he's valuable and assumes he's untouchable. He's now sitting across from you. In 60 seconds, confront the behavior directly out loud: name the impact, set a clear expectation, and make consequences real without losing him on the spot.","de":"Ihr leistungsstärkster Ingenieur liefert herausragende Arbeit, setzt aber Kollegen herab, dominiert Meetings, und zwei Personen haben wegen ihm leise um Versetzung gebeten. Er weiß, dass er wertvoll ist, und hält sich für unantastbar. Jetzt sitzt er Ihnen gegenüber. Konfrontieren Sie das Verhalten in 60 Sekunden direkt und laut: Benennen Sie die Wirkung, setzen Sie eine klare Erwartung und machen Sie Konsequenzen real, ohne ihn sofort zu verlieren.","es-ES":"Tu ingeniero de mayor rendimiento entrega un trabajo excelente, pero menosprecia a sus compañeros, domina las reuniones y dos personas han pedido en privado un traslado por su culpa. Sabe que es valioso y se cree intocable. Ahora está sentado frente a ti. En 60 segundos, confronta la conducta directamente en voz alta: nombra el impacto, fija una expectativa clara y haz reales las consecuencias sin perderlo en el acto."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Recognize his strong work before addressing the behavior.","de":"Anerkennen Sie seine starke Arbeit, bevor Sie das Verhalten ansprechen.","es-ES":"Reconoce su buen trabajo antes de abordar la conducta."},{"en":"Describe specific behaviors and their impact on the team, not vague labels.","de":"Beschreiben Sie konkrete Verhaltensweisen und ihre Wirkung aufs Team, keine vagen Etiketten.","es-ES":"Describe conductas concretas y su impacto en el equipo, no etiquetas vagas."},{"en":"Set an unambiguous expectation that respect is non-negotiable.","de":"Setzen Sie eine eindeutige Erwartung, dass Respekt nicht verhandelbar ist.","es-ES":"Fija una expectativa inequívoca de que el respeto no es negociable."},{"en":"Name concrete consequences if the behavior continues.","de":"Benennen Sie konkrete Konsequenzen, falls das Verhalten anhält.","es-ES":"Nombra consecuencias concretas si la conducta continúa."},{"en":"Express belief he can change and offer support to do so.","de":"Drücken Sie aus, dass er sich ändern kann, und bieten Sie Unterstützung an.","es-ES":"Expresa que crees que puede cambiar y ofrécele apoyo para lograrlo."}],"rubric":{"content":{"strong":"Acknowledges talent, cites specific behaviors and impact, sets a firm expectation, names real consequences, and offers a path forward.","adequate":"Raises the issue and sets some expectation but is vague on impact or soft on consequences.","weak":"Avoids the core issue, over-praises to dodge confrontation, or attacks the person rather than the behavior."},"delivery":{"strong":"Firm, calm, and unflinching; conveys authority without aggression.","adequate":"Mostly steady but wavers or hedges when stating consequences.","weak":"Tentative, apologetic, or hostile in tone."},"time":{"strong":"Lands the full message in 55-65 seconds with no filler.","adequate":"Covers most points but runs slightly long or short.","weak":"Cuts off before consequences or drifts well past time."}},"modelAnswer":{"en":"Your work is genuinely excellent, and I value it. But I need to be direct: in the last month you cut off two colleagues, dismissed Maria's design in front of the team, and people are asking to leave. That's the impact. Talent doesn't buy a pass on respect. Going forward, I expect you to let others finish and disagree without belittling. If it continues, it becomes a formal performance issue. I think you can do this, and I'll support you.","de":"Ihre Arbeit ist wirklich exzellent, und ich schätze sie. Aber ich muss direkt sein: Im letzten Monat haben Sie zwei Kollegen unterbrochen, Marias Entwurf vor dem Team abgetan, und Leute wollen gehen. Das ist die Wirkung. Talent kauft keinen Freibrief beim Respekt. Künftig erwarte ich, dass Sie andere ausreden lassen und ohne Herabsetzung widersprechen. Wenn es weitergeht, wird es ein formales Leistungsproblem. Ich glaube, Sie schaffen das, und ich unterstütze Sie.","es-ES":"Tu trabajo es realmente excelente y lo valoro. Pero debo ser directo: el mes pasado interrumpiste a dos colegas, descartaste el diseño de María delante del equipo y hay gente que quiere marcharse. Ese es el impacto. El talento no compra una excepción al respeto. A partir de ahora espero que dejes terminar a los demás y discrepes sin menospreciar. Si continúa, será un problema formal de desempeño. Creo que puedes lograrlo y te apoyaré."}},
  {"id":"LEAD-6","type":"behavioral","category":"self_awareness_development","department":"leadership","difficulty":2,"media":{"scene":"client_meeting","alt":{"en":"An interview-style meeting table with a glass of water and a notepad.","de":"Ein interviewartiger Besprechungstisch mit einem Glas Wasser und einem Notizblock.","es-ES":"Una mesa de reunión estilo entrevista con un vaso de agua y un cuaderno."}},"roleCaption":{"en":"You are a leader reflecting on a decision that failed.","de":"Sie sind eine Führungskraft und reflektieren über eine gescheiterte Entscheidung.","es-ES":"Eres un líder reflexionando sobre una decisión que fracasó."},"scenario":{"en":"In a leadership panel, you're asked: 'Tell us about a time your decision as a leader was wrong and what you learned.' This is a chance to show self-awareness and growth, not perfection. In 60 seconds, tell one real story out loud: the situation, the call you made, why it failed, how you owned it, and the lasting lesson you carry into how you lead today.","de":"In einer Führungsrunde werden Sie gefragt: 'Erzählen Sie von einer Situation, in der Ihre Entscheidung als Führungskraft falsch war, und was Sie daraus gelernt haben.' Das ist eine Chance, Selbstreflexion und Entwicklung zu zeigen, nicht Perfektion. Erzählen Sie in 60 Sekunden laut eine echte Geschichte: die Situation, Ihre Entscheidung, warum sie scheiterte, wie Sie Verantwortung übernahmen und die bleibende Lehre für Ihre heutige Führung.","es-ES":"En un panel de liderazgo te preguntan: 'Cuéntanos una vez en que tu decisión como líder fue equivocada y qué aprendiste.' Es una oportunidad de mostrar autoconciencia y crecimiento, no perfección. En 60 segundos, cuenta una historia real en voz alta: la situación, la decisión que tomaste, por qué falló, cómo asumiste la responsabilidad y la lección duradera que aplicas hoy al liderar."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Choose a real, specific decision rather than a generic example.","de":"Wählen Sie eine echte, konkrete Entscheidung statt eines generischen Beispiels.","es-ES":"Elige una decisión real y concreta en lugar de un ejemplo genérico."},{"en":"Honestly own the mistake without blaming others.","de":"Übernehmen Sie ehrlich Verantwortung für den Fehler, ohne andere zu beschuldigen.","es-ES":"Asume honestamente el error sin culpar a los demás."},{"en":"Explain why it failed and what you did to address it.","de":"Erklären Sie, warum es scheiterte und was Sie zur Behebung taten.","es-ES":"Explica por qué falló y qué hiciste para resolverlo."},{"en":"State a clear, durable lesson that changed how you lead.","de":"Nennen Sie eine klare, dauerhafte Lehre, die Ihre Führung verändert hat.","es-ES":"Expón una lección clara y duradera que cambió tu forma de liderar."}],"rubric":{"content":{"strong":"Specific story with clear ownership, honest cause, corrective action, and a concrete lesson now applied.","adequate":"Tells a real story but glosses over ownership or the lesson is generic.","weak":"Deflects blame, picks a humble-brag failure, or offers no real learning."},"delivery":{"strong":"Authentic, reflective, and composed; vulnerability paired with confidence.","adequate":"Clear but somewhat rehearsed or emotionally flat.","weak":"Defensive, evasive, or visibly uncomfortable in tone."},"time":{"strong":"Complete narrative arc within 55-65 seconds.","adequate":"Covers the story but runs slightly over or under.","weak":"Trails off without a lesson or far exceeds time."}},"modelAnswer":{"en":"Early as a manager, I pushed a tight deadline despite my team flagging it was unrealistic. I trusted my optimism over their data. We shipped late and burned out two people. I owned it publicly, apologized, and renegotiated the timeline. The lasting lesson: when the people doing the work raise a risk, that's signal, not noise. Now I build slack into plans and ask my team to challenge me before I commit. It made me a far better leader.","de":"Früh als Manager drängte ich auf eine enge Frist, obwohl mein Team warnte, sie sei unrealistisch. Ich vertraute meinem Optimismus mehr als ihren Daten. Wir lieferten zu spät und brannten zwei Leute aus. Ich übernahm öffentlich Verantwortung, entschuldigte mich und verhandelte die Frist neu. Die bleibende Lehre: Wenn die Ausführenden ein Risiko nennen, ist das Signal, kein Lärm. Heute plane ich Puffer ein und bitte mein Team, mich vor Zusagen herauszufordern. Das machte mich zu einer besseren Führungskraft.","es-ES":"Al principio como mánager, impuse un plazo ajustado aunque mi equipo avisó de que era irreal. Confié en mi optimismo más que en sus datos. Entregamos tarde y quemamos a dos personas. Lo asumí en público, pedí disculpas y renegocié el plazo. La lección duradera: cuando quien hace el trabajo señala un riesgo, eso es señal, no ruido. Hoy incluyo margen en los planes y pido a mi equipo que me cuestione antes de comprometerme. Me hizo mucho mejor líder."}},
  {"id":"LEAD-7","type":"feedback360","category":"feedback_difficult_conversations","department":"leadership","difficulty":3,"media":{"scene":"feedback_report","alt":{"en":"A 360-degree feedback report on screen with mixed ratings and comments.","de":"Ein 360-Grad-Feedback-Bericht auf dem Bildschirm mit gemischten Bewertungen und Kommentaren.","es-ES":"Un informe de feedback 360 grados en pantalla con valoraciones y comentarios mixtos."}},"roleCaption":{"en":"You just received blunt 360 feedback and must respond to your team.","de":"Sie haben gerade direktes 360-Feedback erhalten und müssen Ihrem Team antworten.","es-ES":"Acabas de recibir un feedback 360 muy directo y debes responder a tu equipo."},"scenario":{"en":"Your 360 review is in. The theme is consistent: your team finds you decisive but says you don't listen, you interrupt, and you make people feel unheard in meetings. It stings, but it's clear. You've gathered the team to respond. In 60 seconds, react out loud: receive the feedback without defensiveness, acknowledge the pattern, and commit to specific changes the team can hold you to.","de":"Ihr 360-Feedback liegt vor. Das Thema ist eindeutig: Ihr Team findet Sie entscheidungsfreudig, sagt aber, Sie hörten nicht zu, unterbrechen und ließen Menschen in Meetings ungehört. Es schmerzt, ist aber klar. Sie haben das Team zur Reaktion versammelt. Reagieren Sie in 60 Sekunden laut: Nehmen Sie das Feedback ohne Abwehr an, erkennen Sie das Muster an und verpflichten Sie sich zu konkreten Änderungen, an denen das Team Sie messen kann.","es-ES":"Tu evaluación 360 ya está. El tema es claro: tu equipo te ve decidido, pero dice que no escuchas, que interrumpes y que la gente se siente desoída en las reuniones. Duele, pero es claro. Has reunido al equipo para responder. En 60 segundos, reacciona en voz alta: recibe el feedback sin ponerte a la defensiva, reconoce el patrón y comprométete a cambios concretos que el equipo pueda exigirte."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Thank the team for honest, hard-to-give feedback.","de":"Danken Sie dem Team für ehrliches, schwer zu gebendes Feedback.","es-ES":"Agradece al equipo el feedback honesto y difícil de dar."},{"en":"Acknowledge the specific pattern without minimizing or defending.","de":"Erkennen Sie das konkrete Muster an, ohne es zu verharmlosen oder zu verteidigen.","es-ES":"Reconoce el patrón concreto sin minimizarlo ni defenderte."},{"en":"Commit to one or two concrete, observable changes.","de":"Verpflichten Sie sich zu ein bis zwei konkreten, beobachtbaren Änderungen.","es-ES":"Comprométete a uno o dos cambios concretos y observables."},{"en":"Invite the team to call you out when you slip.","de":"Laden Sie das Team ein, Sie darauf hinzuweisen, wenn Sie zurückfallen.","es-ES":"Invita al equipo a señalártelo cuando recaigas."},{"en":"Set a checkpoint to revisit progress together.","de":"Vereinbaren Sie einen Zeitpunkt, um den Fortschritt gemeinsam zu prüfen.","es-ES":"Fija un punto de control para revisar juntos el progreso."}],"rubric":{"content":{"strong":"Receives feedback openly, names the exact pattern, commits to specific observable changes, and sets accountability.","adequate":"Accepts feedback and promises to improve but stays general or vague on actions.","weak":"Defends, rationalizes, or makes empty promises without specifics."},"delivery":{"strong":"Grounded, humble, and sincere; no defensiveness in tone.","adequate":"Mostly open but with traces of justification or stiffness.","weak":"Defensive, dismissive, or performatively contrite."},"time":{"strong":"Delivers a complete response in 55-65 seconds.","adequate":"Covers the key beats but slightly off time.","weak":"Too brief to show commitment or runs well over."}},"modelAnswer":{"en":"Thank you for being honest, even when it was hard to say. I read it clearly: I move fast and decide well, but I cut people off and you leave meetings feeling unheard. I own that. Starting now, two changes: I'll hold my response until everyone who wants to speak has, and I'll close meetings by asking what I missed. Call me out the moment I interrupt. Let's check progress in a month, and I want your read on it.","de":"Danke, dass Sie ehrlich waren, auch wenn es schwerfiel. Ich verstehe es klar: Ich bin schnell und entscheide gut, aber ich falle Leuten ins Wort, und Sie verlassen Meetings ungehört. Das übernehme ich. Ab jetzt zwei Änderungen: Ich halte meine Antwort zurück, bis alle gesprochen haben, und ich schließe Meetings mit der Frage, was ich übersehen habe. Weisen Sie mich sofort darauf hin, wenn ich unterbreche. Prüfen wir den Fortschritt in einem Monat, und ich will Ihre Einschätzung.","es-ES":"Gracias por ser honestos, aunque fuera difícil decirlo. Lo leo con claridad: avanzo rápido y decido bien, pero corto a la gente y salís de las reuniones sin sentiros escuchados. Lo asumo. Desde ya, dos cambios: contendré mi respuesta hasta que hable todo el que quiera, y cerraré las reuniones preguntando qué me he perdido. Señaládmelo en cuanto interrumpa. Revisemos el progreso en un mes, y quiero vuestra valoración."}},
  {"id":"LEAD-8","type":"coaching","category":"professional_communication","department":"leadership","difficulty":3,"media":{"scene":"coaching_room","alt":{"en":"A quiet coaching room with two armchairs and a small table.","de":"Ein ruhiger Coaching-Raum mit zwei Sesseln und einem kleinen Tisch.","es-ES":"Una sala de coaching tranquila con dos sillones y una mesita."}},"roleCaption":{"en":"You are coaching a struggling new manager who is overwhelmed.","de":"Sie coachen einen überforderten neuen Manager.","es-ES":"Estás dando coaching a un nuevo mánager que se siente desbordado."},"scenario":{"en":"A first-time manager you promoted is drowning. She's doing all the work herself, won't delegate, her team is frustrated, and she just admitted she feels like a fraud. She's looking to you for help, not a lecture. In 60 seconds, coach her out loud: validate the struggle, ask or surface the real root cause, and guide her toward one practical next step she can own this week.","de":"Eine erstmalige Managerin, die Sie befördert haben, geht unter. Sie macht alles selbst, delegiert nicht, ihr Team ist frustriert, und sie hat gerade gestanden, sich wie eine Hochstaplerin zu fühlen. Sie sucht Hilfe bei Ihnen, keine Belehrung. Coachen Sie sie in 60 Sekunden laut: Bestätigen Sie den Kampf, benennen oder erfragen Sie die wahre Ursache und führen Sie sie zu einem praktischen nächsten Schritt für diese Woche.","es-ES":"Una mánager primeriza a quien ascendiste se está ahogando. Lo hace todo ella, no delega, su equipo está frustrado y acaba de admitir que se siente una impostora. Busca tu ayuda, no un sermón. En 60 segundos, dale coaching en voz alta: valida su lucha, descubre o pregunta la causa de fondo y guíala hacia un paso práctico que pueda asumir esta semana."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Validate her feelings and normalize the new-manager struggle.","de":"Bestätigen Sie ihre Gefühle und normalisieren Sie den Kampf neuer Manager.","es-ES":"Valida sus emociones y normaliza la lucha del nuevo mánager."},{"en":"Ask questions to surface the real cause rather than prescribing.","de":"Stellen Sie Fragen, um die wahre Ursache zu finden, statt zu verordnen.","es-ES":"Haz preguntas para descubrir la causa real en lugar de imponer soluciones."},{"en":"Reframe delegation as developing the team, not losing control.","de":"Rahmen Sie Delegation als Teamentwicklung, nicht als Kontrollverlust.","es-ES":"Reformula la delegación como desarrollar al equipo, no perder el control."},{"en":"Guide her to one concrete, owned next step for the week.","de":"Führen Sie sie zu einem konkreten, eigenen nächsten Schritt für die Woche.","es-ES":"Guíala hacia un paso concreto y propio para esta semana."},{"en":"Offer ongoing support and express confidence in her.","de":"Bieten Sie weitere Unterstützung an und drücken Sie Vertrauen in sie aus.","es-ES":"Ofrece apoyo continuo y expresa confianza en ella."}],"rubric":{"content":{"strong":"Validates, asks to surface root cause, reframes delegation, and lands one concrete owned step plus ongoing support.","adequate":"Supports and gives advice but leans on telling over coaching or lacks a clear next step.","weak":"Lectures, solves it for her, or offers only vague encouragement."},"delivery":{"strong":"Warm, patient, and empowering; coaching tone, not directive.","adequate":"Supportive but occasionally slips into instructing.","weak":"Impatient, dismissive, or condescending."},"time":{"strong":"Full coaching arc within 55-65 seconds.","adequate":"Covers most beats but slightly off time.","weak":"Rushes past the root cause or overruns badly."}},"modelAnswer":{"en":"First, breathe. What you're feeling is normal; almost every strong manager has felt like a fraud. You earned this role. Let me ask: when you do everything yourself, what are you afraid happens if you hand it off? Usually it's fear the work won't meet your bar. Here's the reframe: delegating is how you build your team's bar. This week, pick one task only you do, hand it to someone, and coach the outcome, not the steps. I'm here every step. You've got this.","de":"Zuerst: durchatmen. Was Sie fühlen, ist normal; fast jede starke Führungskraft fühlte sich mal wie eine Hochstaplerin. Sie haben diese Rolle verdient. Eine Frage: Wenn Sie alles selbst machen, wovor fürchten Sie sich beim Abgeben? Meist die Angst, die Arbeit erreiche Ihr Niveau nicht. Die Umdeutung: Delegieren baut das Niveau Ihres Teams auf. Geben Sie diese Woche eine Aufgabe ab, die nur Sie machen, und coachen Sie das Ergebnis, nicht die Schritte. Ich bin dabei. Sie schaffen das.","es-ES":"Primero, respira. Lo que sientes es normal; casi todo buen mánager se ha sentido un impostor. Te ganaste este puesto. Te pregunto: cuando lo haces todo tú, ¿qué temes que pase si lo delegas? Suele ser el miedo a que el trabajo no llegue a tu nivel. El giro: delegar es como construyes el nivel de tu equipo. Esta semana, elige una tarea que solo haces tú, dásela a alguien y supervisa el resultado, no los pasos. Estoy contigo en todo. Puedes con esto."}},
  {"id":"LEAD-9","type":"situational","category":"strategic_thinking","department":"leadership","difficulty":4,"media":{"scene":"boardroom","alt":{"en":"A boardroom with a budget spreadsheet projected and executives seated.","de":"Ein Sitzungssaal mit projizierter Budget-Tabelle und sitzenden Führungskräften.","es-ES":"Una sala de juntas con una hoja de presupuesto proyectada y ejecutivos sentados."}},"roleCaption":{"en":"You must defend your team's headcount in a budget-cut meeting.","de":"Sie müssen den Personalbestand Ihres Teams in einer Sparrunde verteidigen.","es-ES":"Debes defender la plantilla de tu equipo en una reunión de recortes."},"scenario":{"en":"It's budget season and finance wants every department to cut 15% of headcount. The CFO turns to you and says, 'Make the case for why your team should be spared.' Other leaders are watching, and resources are zero-sum. In 60 seconds, defend your headcount out loud: tie your team to business outcomes, quantify the cost of cutting, and propose a credible, strategic alternative rather than just pleading.","de":"Es ist Budgetzeit, und die Finanzabteilung will, dass jede Abteilung 15 % Personal abbaut. Der CFO wendet sich an Sie: 'Begründen Sie, warum Ihr Team verschont werden soll.' Andere Führungskräfte schauen zu, und die Mittel sind ein Nullsummenspiel. Verteidigen Sie in 60 Sekunden laut Ihren Personalbestand: Verknüpfen Sie Ihr Team mit Geschäftsergebnissen, beziffern Sie die Kosten eines Abbaus und schlagen Sie eine glaubwürdige, strategische Alternative vor, statt nur zu bitten.","es-ES":"Es temporada de presupuesto y finanzas quiere que cada departamento recorte el 15% de la plantilla. El director financiero se vuelve hacia ti: 'Justifica por qué tu equipo debería librarse.' Otros líderes observan y los recursos son de suma cero. En 60 segundos, defiende tu plantilla en voz alta: vincula tu equipo a resultados de negocio, cuantifica el coste de recortar y propón una alternativa creíble y estratégica en lugar de solo suplicar."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Tie the team directly to revenue or critical business outcomes.","de":"Verknüpfen Sie das Team direkt mit Umsatz oder kritischen Geschäftsergebnissen.","es-ES":"Vincula el equipo directamente a ingresos o resultados críticos del negocio."},{"en":"Quantify the cost or risk of cutting, not just the value of keeping.","de":"Beziffern Sie die Kosten oder das Risiko eines Abbaus, nicht nur den Wert des Erhalts.","es-ES":"Cuantifica el coste o riesgo de recortar, no solo el valor de mantener."},{"en":"Acknowledge the company's real financial pressure.","de":"Erkennen Sie den realen finanziellen Druck des Unternehmens an.","es-ES":"Reconoce la presión financiera real de la empresa."},{"en":"Offer a credible strategic alternative or trade-off.","de":"Bieten Sie eine glaubwürdige strategische Alternative oder einen Kompromiss an.","es-ES":"Ofrece una alternativa estratégica creíble o un compromiso."},{"en":"Stay confident and data-driven, not defensive or emotional.","de":"Bleiben Sie selbstbewusst und datengetrieben, nicht defensiv oder emotional.","es-ES":"Mantente seguro y basado en datos, no a la defensiva ni emocional."}],"rubric":{"content":{"strong":"Links team to measurable outcomes, quantifies cut risk, acknowledges pressure, and proposes a strategic alternative.","adequate":"Makes a value case but is light on numbers or offers no alternative.","weak":"Pleads emotionally, ignores the business context, or offers no data."},"delivery":{"strong":"Confident, composed, and executive in tone; commands the room.","adequate":"Clear but occasionally defensive or tentative.","weak":"Anxious, pleading, or combative."},"time":{"strong":"Tight, persuasive case in 55-65 seconds.","adequate":"Covers the case but slightly over or under time.","weak":"Rambles or cuts off before the alternative."}},"modelAnswer":{"en":"I understand the pressure, and I'm not here to plead. My team owns the onboarding flow that drives 30% of new revenue and cut churn by four points last quarter. Removing 15% would slow our release cadence and put roughly two million in renewals at risk, far more than we'd save. Instead, I'll defer two open hires this year and absorb a cross-team tool consolidation that saves eight percent of my budget. We protect the revenue engine and still help you hit the target.","de":"Ich verstehe den Druck und bin nicht hier, um zu betteln. Mein Team verantwortet den Onboarding-Flow, der 30 % des Neuumsatzes treibt und letztes Quartal die Abwanderung um vier Punkte senkte. Ein Abbau von 15 % würde unseren Release-Takt bremsen und rund zwei Millionen an Verlängerungen gefährden, weit mehr als wir sparen würden. Stattdessen verschiebe ich zwei offene Stellen dieses Jahr und übernehme eine teamübergreifende Tool-Konsolidierung, die acht Prozent meines Budgets spart. Wir schützen den Umsatzmotor und helfen Ihnen trotzdem beim Ziel.","es-ES":"Entiendo la presión y no vengo a suplicar. Mi equipo gestiona el flujo de onboarding que genera el 30% de los ingresos nuevos y redujo la fuga cuatro puntos el último trimestre. Recortar un 15% frenaría nuestro ritmo de lanzamientos y pondría en riesgo unos dos millones en renovaciones, mucho más de lo que ahorraríamos. En su lugar, aplazaré dos contrataciones abiertas este año y asumiré una consolidación de herramientas entre equipos que ahorra un ocho por ciento de mi presupuesto. Protegemos el motor de ingresos y aun así te ayudo a alcanzar el objetivo."}},
  {"id":"FIN-4","type":"situational","category":"professional_communication","department":"finance","difficulty":3,"media":{"scene":"exec_committee","alt":{"en":"A finance leader briefing the executive committee around a glass-walled table with a cash-flow chart on screen.","de":"Eine Finanzführungskraft informiert das Führungsteam an einem Glastisch, im Hintergrund eine Cashflow-Grafik.","es-ES":"Un responsable de finanzas informa al comité ejecutivo en una mesa de cristal con un gráfico de flujo de caja en pantalla."}},"roleCaption":{"en":"You are the CFO. A 60-day cash crunch is looming.","de":"Sie sind CFO. Eine Liquiditätslücke in 60 Tagen droht.","es-ES":"Eres el director financiero. Se avecina una tensión de tesorería a 60 días."},"scenario":{"en":"Collections have slipped and a large customer delayed payment. You must tell the CEO and execs that the company will be short on cash in about 60 days unless you act now. You have 60 seconds to explain the gap, the cause, and your proposed steps without triggering panic.","de":"Die Zahlungseingänge sind zurückgegangen und ein Großkunde zahlt verspätet. Sie müssen dem CEO und dem Führungsteam mitteilen, dass in rund 60 Tagen das Geld knapp wird, falls Sie nicht jetzt handeln. Sie haben 60 Sekunden, um Lücke, Ursache und Maßnahmen zu erklären, ohne Panik auszulösen.","es-ES":"Los cobros han caído y un gran cliente ha retrasado el pago. Debes decir al CEO y a la dirección que la empresa se quedará corta de liquidez en unos 60 días si no actúas ya. Tienes 60 segundos para explicar la brecha, la causa y tus pasos sin provocar pánico."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"State the size and timing of the cash gap clearly.","de":"Höhe und Zeitpunkt der Liquiditätslücke klar benennen.","es-ES":"Indica con claridad el tamaño y el momento de la brecha de caja."},{"en":"Name the root cause: slipped collections and one delayed payer.","de":"Die Ursache nennen: ausbleibende Zahlungen und ein säumiger Großkunde.","es-ES":"Nombra la causa raíz: cobros caídos y un pagador retrasado."},{"en":"Present concrete levers: draw on credit line, defer spend, accelerate receivables.","de":"Konkrete Hebel zeigen: Kreditlinie ziehen, Ausgaben verschieben, Forderungen beschleunigen.","es-ES":"Presenta palancas concretas: usar la línea de crédito, diferir gasto, acelerar cobros."},{"en":"Reassure that this is manageable, not a solvency crisis.","de":"Versichern, dass es beherrschbar ist und keine Solvenzkrise.","es-ES":"Tranquiliza: es manejable, no una crisis de solvencia."},{"en":"Ask for one clear decision today.","de":"Eine klare Entscheidung für heute einfordern.","es-ES":"Pide una decisión clara hoy."}],"rubric":{"content":{"strong":"Quantifies the gap and timing, names the cause, and offers specific, sequenced levers plus a clear ask.","adequate":"Conveys the problem and at least one fix but is vague on numbers, timing, or the decision needed.","weak":"Alarming or unclear; no quantification, cause, or actionable plan."},"delivery":{"strong":"Calm, steady, and confident; tone reassures while conveying urgency.","adequate":"Mostly composed but some hesitation or anxious tone leaks through.","weak":"Panicked, rambling, or flat; undermines confidence."},"time":{"strong":"Uses 55-65 seconds with even pacing and a clean close.","adequate":"Slightly over or under; minor rushing or trailing off.","weak":"Far off target or cut off mid-thought."}},"modelAnswer":{"en":"Here's the situation, plainly: based on current collections, we'll be roughly 1.8 million short on cash in about 60 days. The driver is two slipped receivables, mainly Northwind delaying. This is timing, not a solvency problem. My plan: draw 1 million on our revolver this week, defer non-critical capex one quarter, and put a dedicated person on Northwind's payment. That closes the gap with buffer. What I need today is your approval to draw on the line.","de":"Klar gesagt: Bei den aktuellen Zahlungseingängen fehlen uns in rund 60 Tagen etwa 1,8 Millionen an Liquidität. Ursache sind zwei verspätete Forderungen, vor allem Northwind. Das ist eine Frage des Timings, kein Solvenzproblem. Mein Plan: diese Woche 1 Million aus der Kreditlinie ziehen, unkritische Investitionen ein Quartal verschieben und Northwinds Zahlung eng begleiten. Das schließt die Lücke mit Puffer. Heute brauche ich Ihre Freigabe für die Kreditlinie.","es-ES":"Lo digo claro: con los cobros actuales, nos faltarán unos 1,8 millones de caja en unos 60 días. La causa son dos cobros retrasados, sobre todo Northwind. Es cuestión de calendario, no de solvencia. Mi plan: disponer 1 millón de la línea esta semana, diferir inversiones no críticas un trimestre y asignar a alguien al cobro de Northwind. Eso cierra la brecha con margen. Hoy necesito tu aprobación para usar la línea."}},
  {"id":"FIN-5","type":"behavioral","category":"leadership_decisions","department":"finance","difficulty":4,"media":{"scene":"boardroom","alt":{"en":"A CFO standing at the head of a boardroom defending a capital-expenditure plan to attentive directors.","de":"Ein CFO am Kopfende des Sitzungssaals verteidigt einen Investitionsplan vor aufmerksamen Aufsichtsräten.","es-ES":"Un director financiero al frente de la sala de juntas defiende un plan de inversión ante consejeros atentos."}},"roleCaption":{"en":"You are the CFO. The board is skeptical of your capex ask.","de":"Sie sind CFO. Der Aufsichtsrat zweifelt an Ihrem Investitionsantrag.","es-ES":"Eres el director financiero. El consejo duda de tu petición de inversión."},"scenario":{"en":"You are requesting board approval for a 25 million capital investment in a new plant. Two directors think it is too risky given soft demand. Describe a time you had to defend a major capital decision under scrutiny: walk the board through your reasoning, the returns, and how you handle their risk concerns in 60 seconds.","de":"Sie beantragen die Genehmigung einer 25-Millionen-Investition in ein neues Werk. Zwei Aufsichtsräte halten das angesichts schwacher Nachfrage für zu riskant. Schildern Sie, wie Sie eine große Investitionsentscheidung unter Prüfung verteidigt haben: Logik, Rendite und Umgang mit den Risikobedenken in 60 Sekunden.","es-ES":"Solicitas al consejo aprobar una inversión de 25 millones en una nueva planta. Dos consejeros la ven arriesgada por la demanda débil. Describe una vez que defendiste una decisión de capital importante bajo escrutinio: razonamiento, retornos y cómo gestionas sus dudas de riesgo en 60 segundos."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Frame the strategic rationale, not just the numbers.","de":"Die strategische Begründung darlegen, nicht nur Zahlen.","es-ES":"Plantea la lógica estratégica, no solo las cifras."},{"en":"Show the expected return, payback, and key assumptions.","de":"Erwartete Rendite, Amortisation und zentrale Annahmen zeigen.","es-ES":"Muestra el retorno esperado, el repago y los supuestos clave."},{"en":"Acknowledge the demand risk honestly and quantify it.","de":"Das Nachfragerisiko offen anerkennen und quantifizieren.","es-ES":"Reconoce con honestidad el riesgo de demanda y cuantifícalo."},{"en":"Offer downside protection: phasing, off-ramps, sensitivities.","de":"Absicherung nach unten bieten: Phasen, Ausstiegspunkte, Sensitivitäten.","es-ES":"Ofrece protección a la baja: fases, salidas, sensibilidades."},{"en":"Make a confident, specific recommendation.","de":"Eine selbstbewusste, konkrete Empfehlung aussprechen.","es-ES":"Haz una recomendación firme y concreta."}],"rubric":{"content":{"strong":"Ties capex to strategy, gives returns and assumptions, addresses demand risk with concrete mitigation and a clear recommendation.","adequate":"Covers returns and some risk handling but thin on mitigation or assumptions.","weak":"Defensive or numbers-only; ignores the directors' risk concern."},"delivery":{"strong":"Authoritative and composed under challenge; invites scrutiny without defensiveness.","adequate":"Generally steady but slightly defensive or uneven when pressed.","weak":"Defensive, dismissive, or shaky."},"time":{"strong":"Uses 55-65 seconds with a structured arc and clean close.","adequate":"Slightly off; minor rush or drift.","weak":"Well over or under, or cut off."}},"modelAnswer":{"en":"I understand the caution, and I share it. This plant supports our highest-margin line, where we're capacity-constrained even in a soft market. The base case returns 18 percent IRR with a four-year payback; even at 20 percent lower demand it clears our hurdle. To protect the downside, I've phased the build in two stages, with a go/no-go after stage one and a contractual exit on the second tranche. So we commit 25 million only if early demand confirms. My recommendation is to approve stage one now.","de":"Ich verstehe die Vorsicht und teile sie. Dieses Werk bedient unsere margenstärkste Linie, wo wir selbst im schwachen Markt an Kapazitätsgrenzen stoßen. Der Basisfall liefert 18 Prozent IRR bei vier Jahren Amortisation; selbst bei 20 Prozent weniger Nachfrage übertrifft er unsere Schwelle. Zur Absicherung habe ich den Bau in zwei Phasen gegliedert, mit Go/No-Go nach Phase eins und vertraglichem Ausstieg bei der zweiten Tranche. Die vollen 25 Millionen binden wir nur, wenn die frühe Nachfrage es bestätigt. Mein Vorschlag: Phase eins jetzt genehmigen.","es-ES":"Entiendo la cautela y la comparto. Esta planta sostiene nuestra línea de mayor margen, donde estamos al límite de capacidad incluso con mercado flojo. El caso base rinde un 18 por ciento de TIR con repago a cuatro años; aun con un 20 por ciento menos de demanda supera nuestro umbral. Para proteger la baja, he dividido la obra en dos fases, con decisión go/no-go tras la primera y salida contractual en el segundo tramo. Comprometemos los 25 millones solo si la demanda temprana lo confirma. Mi recomendación: aprobar la fase uno ya."}},
  {"id":"FIN-6","type":"conflict","category":"conflict_resolution","department":"finance","difficulty":4,"media":{"scene":"office_1on1","alt":{"en":"A CFO and a sales VP in a tense one-on-one across a desk, body language guarded.","de":"Ein CFO und ein Vertriebsleiter in einem angespannten Vieraugengespräch am Schreibtisch, mit reservierter Körpersprache.","es-ES":"Un director financiero y un VP de ventas en un cara a cara tenso sobre un escritorio, con lenguaje corporal reservado."}},"roleCaption":{"en":"You are the CFO pushing back on aggressive revenue recognition.","de":"Sie sind CFO und stellen sich gegen aggressive Umsatzrealisierung.","es-ES":"Eres el director financiero y frenas un reconocimiento de ingresos agresivo."},"scenario":{"en":"The VP of Sales wants to book a 4 million multi-year deal entirely in this quarter to hit the number. You believe the contract terms require it to be recognized over time, and booking it now would be improper. He is pressing hard and the quarter closes Friday. Hold the line in 60 seconds without blowing up the relationship.","de":"Der Vertriebsleiter will einen 4-Millionen-Mehrjahresvertrag vollständig in diesem Quartal verbuchen, um das Ziel zu erreichen. Sie meinen, die Vertragsbedingungen erfordern eine Verteilung über die Laufzeit, und eine Sofortbuchung wäre unzulässig. Er drängt stark, das Quartal schließt am Freitag. Bleiben Sie in 60 Sekunden standhaft, ohne die Beziehung zu zerstören.","es-ES":"El VP de ventas quiere contabilizar un contrato plurianual de 4 millones íntegro este trimestre para cumplir el objetivo. Crees que las condiciones obligan a reconocerlo a lo largo del tiempo y hacerlo ahora sería indebido. Él presiona fuerte y el trimestre cierra el viernes. Mantente firme en 60 segundos sin romper la relación."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Acknowledge the pressure and shared goal of hitting the number.","de":"Den Druck und das gemeinsame Ziel anerkennen.","es-ES":"Reconoce la presión y el objetivo común de cumplir la cifra."},{"en":"State the accounting rule clearly and why it applies.","de":"Die Bilanzierungsregel klar nennen und warum sie greift.","es-ES":"Expón la norma contable con claridad y por qué aplica."},{"en":"Name the real risk: audit, restatement, personal exposure.","de":"Das echte Risiko benennen: Prüfung, Neudarstellung, persönliche Haftung.","es-ES":"Nombra el riesgo real: auditoría, reformulación, exposición personal."},{"en":"Offer a legitimate alternative to help him succeed.","de":"Eine legitime Alternative bieten, die ihm hilft.","es-ES":"Ofrece una alternativa legítima para ayudarle a tener éxito."},{"en":"Stay firm but respectful; this is non-negotiable.","de":"Fest, aber respektvoll bleiben; das ist nicht verhandelbar.","es-ES":"Mantente firme pero respetuoso; esto no es negociable."}],"rubric":{"content":{"strong":"Holds the line on the standard, explains the risk, validates his goal, and offers a legitimate path forward.","adequate":"Refuses correctly but is thin on the rule, the risk, or an alternative.","weak":"Caves, hedges, or attacks; treats it as negotiable."},"delivery":{"strong":"Firm, calm, and respectful; no aggression, no wavering.","adequate":"Mostly firm but slightly combative or apologetic.","weak":"Either hostile or weak and easily pushed."},"time":{"strong":"Uses 55-65 seconds, controlled throughout.","adequate":"Slightly off pace.","weak":"Far off or cut short."}},"modelAnswer":{"en":"I get it, we both want to land this quarter, and this is a great win. But I can't recognize the full four million now. The contract has ongoing performance obligations, so the standard requires we spread it over the term; booking it all today would be a misstatement, and that puts the audit and both of us at real risk. What I can do is recognize the first period now and help you re-scope a separate deliverable that legitimately closes this quarter. Let's find that together today.","de":"Ich verstehe das, wir wollen beide dieses Quartal liefern, und das ist ein starker Abschluss. Aber ich kann die vollen vier Millionen jetzt nicht realisieren. Der Vertrag hat laufende Leistungspflichten, deshalb verlangt der Standard eine Verteilung über die Laufzeit; eine Sofortbuchung wäre eine Fehldarstellung und gefährdet die Prüfung und uns beide. Was geht: die erste Periode jetzt zu erfassen und mit dir eine separate Leistung zu finden, die dieses Quartal legitim abschließt. Lass uns das heute gemeinsam machen.","es-ES":"Lo entiendo, ambos queremos cerrar este trimestre y es un gran logro. Pero no puedo reconocer los cuatro millones completos ahora. El contrato tiene obligaciones de desempeño continuas, así que la norma exige repartirlo en el plazo; contabilizarlo todo hoy sería un error material y pone en riesgo real la auditoría y a los dos. Lo que sí puedo: reconocer el primer periodo ahora y ayudarte a reformular un entregable separado que cierre legítimamente este trimestre. Resolvámoslo hoy juntos."}},
  {"id":"FIN-7","type":"feedback360","category":"self_awareness_development","department":"finance","difficulty":3,"media":{"scene":"feedback_report","alt":{"en":"A finance leader reviewing a 360-degree feedback report on a tablet in a quiet office.","de":"Eine Finanzführungskraft liest einen 360-Grad-Feedbackbericht auf einem Tablet in einem ruhigen Büro.","es-ES":"Un responsable de finanzas revisa un informe de feedback de 360 grados en una tableta en una oficina tranquila."}},"roleCaption":{"en":"You are a finance director responding to 360 feedback.","de":"Sie sind Finanzdirektor und reagieren auf 360-Grad-Feedback.","es-ES":"Eres director de finanzas y respondes a un feedback de 360 grados."},"scenario":{"en":"Your 360 review says peers find you technically excellent but that you 'make people feel stupid' in meetings and shut down questions. It stung, and you partly disagree. Respond out loud to your coach: react to the feedback, show what you take from it, and commit to a change in 60 seconds.","de":"Ihr 360-Grad-Feedback besagt, Kollegen halten Sie für fachlich exzellent, aber Sie ließen Menschen sich in Meetings 'dumm fühlen' und würgten Fragen ab. Das hat wehgetan, und Sie sind teils anderer Meinung. Reagieren Sie laut gegenüber Ihrem Coach: auf das Feedback eingehen, das Wesentliche aufnehmen und eine Veränderung zusagen, in 60 Sekunden.","es-ES":"Tu evaluación de 360 dice que los compañeros te ven técnicamente excelente, pero que haces 'sentir tontos' a los demás en reuniones y cortas las preguntas. Te ha dolido y en parte no estás de acuerdo. Responde en voz alta a tu coach: reacciona al feedback, muestra qué extraes y comprométete a un cambio en 60 segundos."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Acknowledge the feedback without defensiveness.","de":"Das Feedback ohne Abwehr anerkennen.","es-ES":"Reconoce el feedback sin ponerte a la defensiva."},{"en":"Show genuine self-reflection on the impact you have.","de":"Echte Selbstreflexion über die eigene Wirkung zeigen.","es-ES":"Muestra autorreflexión genuina sobre tu impacto."},{"en":"Separate intent from impact honestly.","de":"Absicht und Wirkung ehrlich trennen.","es-ES":"Separa con honestidad la intención del impacto."},{"en":"Commit to one specific behavior change.","de":"Eine konkrete Verhaltensänderung zusagen.","es-ES":"Comprométete a un cambio de conducta concreto."},{"en":"Avoid blaming the raters or excusing yourself.","de":"Keine Schuldzuweisung an die Bewerter, keine Ausreden.","es-ES":"Evita culpar a los evaluadores o excusarte."}],"rubric":{"content":{"strong":"Owns the impact, distinguishes intent from effect, and commits to a specific, observable change.","adequate":"Accepts the feedback but is vague on the change or partly defensive.","weak":"Dismisses, rationalizes, or blames the feedback."},"delivery":{"strong":"Open, reflective, and grounded; tone shows real ownership.","adequate":"Mostly sincere but some defensiveness or flatness.","weak":"Defensive, dismissive, or performative."},"time":{"strong":"Uses 55-65 seconds with reflective pacing.","adequate":"Slightly off pace.","weak":"Far off or cut short."}},"modelAnswer":{"en":"My honest first reaction was defensiveness, because I never intend to belittle anyone. But several people felt that way, and intent isn't impact. If colleagues hold back questions around me, that's costing us better decisions, and it's on me. I think it comes from jumping to the answer too fast. So here's my commitment: in every finance review, I'll ask a question before I give my view, and I'll wait. I'd like you to hold me to that and check back in a month.","de":"Meine ehrliche erste Reaktion war Abwehr, denn ich will niemanden kleinmachen. Aber mehrere empfanden es so, und Absicht ist nicht gleich Wirkung. Wenn Kollegen bei mir Fragen zurückhalten, kostet uns das bessere Entscheidungen, und das liegt an mir. Ich glaube, es kommt daher, dass ich zu schnell zur Antwort springe. Mein Vorsatz: In jedem Finanz-Review stelle ich erst eine Frage, bevor ich meine Sicht gebe, und warte ab. Bitte halte mich daran fest und prüfe in einem Monat nach.","es-ES":"Mi primera reacción honesta fue defensiva, porque nunca pretendo menospreciar a nadie. Pero varias personas lo sintieron así, y la intención no es el impacto. Si los compañeros se callan preguntas a mi lado, eso nos cuesta mejores decisiones, y es responsabilidad mía. Creo que viene de saltar a la respuesta demasiado rápido. Mi compromiso: en cada revisión financiera haré una pregunta antes de dar mi opinión, y esperaré. Te pido que me lo recuerdes y lo revisemos en un mes."}},
  {"id":"FIN-8","type":"coaching","category":"feedback_difficult_conversations","department":"finance","difficulty":2,"media":{"scene":"coaching_room","alt":{"en":"A finance manager coaching a worried junior analyst in a small, calm meeting room.","de":"Ein Finanzmanager coacht einen besorgten Nachwuchsanalysten in einem kleinen, ruhigen Besprechungsraum.","es-ES":"Un gerente financiero orienta a un analista junior preocupado en una sala pequeña y tranquila."}},"roleCaption":{"en":"You are the manager coaching an analyst who made an error.","de":"Sie sind Manager und coachen einen Analysten, der einen Fehler gemacht hat.","es-ES":"Eres el gerente que orienta a un analista que cometió un error."},"scenario":{"en":"A junior analyst made a formula error that overstated forecast revenue by 600,000 in a deck that already went to leadership. He is mortified. You need to correct the record and coach him so he learns without being crushed. Speak to him directly for 60 seconds: address the mistake, the fix, and his growth.","de":"Ein Nachwuchsanalyst hat durch einen Formelfehler die Umsatzprognose um 600.000 zu hoch ausgewiesen, in einer Präsentation, die bereits an die Führung ging. Er ist am Boden. Sie müssen die Zahlen korrigieren und ihn so coachen, dass er lernt, ohne zerstört zu werden. Sprechen Sie 60 Sekunden direkt mit ihm: Fehler, Korrektur und seine Entwicklung.","es-ES":"Un analista junior cometió un error de fórmula que infló los ingresos previstos en 600.000 en una presentación que ya llegó a la dirección. Está hundido. Debes corregir las cifras y orientarle para que aprenda sin quedar destrozado. Háblale directamente 60 segundos: el error, la corrección y su desarrollo."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Address the error clearly and without minimizing it.","de":"Den Fehler klar und ohne Verharmlosung ansprechen.","es-ES":"Aborda el error con claridad y sin minimizarlo."},{"en":"Separate the person from the mistake.","de":"Person und Fehler trennen.","es-ES":"Separa a la persona del error."},{"en":"Agree the immediate fix and corrected message to leadership.","de":"Sofortige Korrektur und richtige Botschaft an die Führung abstimmen.","es-ES":"Acuerda la corrección inmediata y el mensaje rectificado a dirección."},{"en":"Build a habit or check to prevent recurrence.","de":"Eine Gewohnheit oder Kontrolle aufbauen, um Wiederholung zu vermeiden.","es-ES":"Crea un hábito o control para evitar que se repita."},{"en":"End with encouragement and confidence in him.","de":"Mit Ermutigung und Vertrauen in ihn schließen.","es-ES":"Cierra con ánimo y confianza en él."}],"rubric":{"content":{"strong":"Names the error, sets the fix, builds a safeguard, and reframes it as growth with clear next steps.","adequate":"Covers the fix or the lesson but misses the safeguard or reassurance.","weak":"Either harsh and blaming or so soft the lesson is lost."},"delivery":{"strong":"Warm, steady, and direct; supportive without sugarcoating.","adequate":"Mostly supportive but uneven tone.","weak":"Cold, scolding, or evasive."},"time":{"strong":"Uses 55-65 seconds, balanced pacing.","adequate":"Slightly off pace.","weak":"Far off or cut short."}},"modelAnswer":{"en":"First, breathe, this is fixable and it's not who you are. The formula pulled the wrong range, so revenue was overstated by 600,000. Here's what we do: you rebuild the model now, I review it, and we send leadership a short corrected note today, owning it cleanly. That's how trust is kept. Going forward, let's add a simple checksum row and a second set of eyes before anything goes up. You're a strong analyst; everyone hits one of these. The way you handle it now is what matters.","de":"Erst mal durchatmen, das ist behebbar und sagt nichts über dich aus. Die Formel zog den falschen Bereich, dadurch war der Umsatz um 600.000 zu hoch. Wir machen Folgendes: Du baust das Modell jetzt neu, ich prüfe es, und wir schicken der Führung heute eine kurze Korrekturnotiz und stehen offen dazu. So bewahrt man Vertrauen. Künftig fügen wir eine einfache Prüfsummenzeile ein und lassen vor dem Versand jemanden gegenlesen. Du bist ein starker Analyst; jeder erlebt so etwas. Entscheidend ist, wie du jetzt damit umgehst.","es-ES":"Primero, respira, esto tiene arreglo y no te define. La fórmula tomó el rango equivocado, así que los ingresos se inflaron en 600.000. Esto hacemos: rehaces el modelo ahora, yo lo reviso y enviamos hoy a dirección una nota corregida breve, asumiéndolo con claridad. Así se mantiene la confianza. De aquí en adelante añadimos una fila de control y una segunda revisión antes de enviar nada. Eres un buen analista; a todos nos pasa una vez. Lo que importa es cómo lo gestionas ahora."}},
  {"id":"FIN-9","type":"situational","category":"strategic_thinking","department":"finance","difficulty":4,"media":{"scene":"video_call","alt":{"en":"A CFO on a video call presenting a down-round valuation to investor faces on screen.","de":"Ein CFO präsentiert in einer Videokonferenz eine Down-Round-Bewertung vor Investoren auf dem Bildschirm.","es-ES":"Un director financiero en videollamada presenta una valoración a la baja ante inversores en pantalla."}},"roleCaption":{"en":"You are the CFO presenting a down-round to investors.","de":"Sie sind CFO und präsentieren Investoren eine Down-Round.","es-ES":"Eres el director financiero y presentas una ronda a la baja a inversores."},"scenario":{"en":"To extend runway, the company must raise at a valuation 30 percent below the last round. On a video call with existing investors, you must explain why the down-round is the right move, protect confidence, and ask them to participate. Deliver that case in 60 seconds.","de":"Um die Liquidität zu verlängern, muss das Unternehmen zu einer Bewertung 30 Prozent unter der letzten Runde Kapital aufnehmen. In einer Videokonferenz mit Bestandsinvestoren müssen Sie erklären, warum die Down-Round richtig ist, Vertrauen wahren und um Beteiligung bitten. Bringen Sie diesen Fall in 60 Sekunden.","es-ES":"Para alargar la pista de financiación, la empresa debe captar a una valoración un 30 por ciento por debajo de la ronda anterior. En una videollamada con inversores actuales, debes explicar por qué la ronda a la baja es lo correcto, proteger la confianza y pedirles que participen. Expón el caso en 60 segundos."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Be transparent about why the down-round is necessary.","de":"Transparent erklären, warum die Down-Round nötig ist.","es-ES":"Sé transparente sobre por qué es necesaria la ronda a la baja."},{"en":"Frame it as a strategic choice that secures the future.","de":"Sie als strategische Entscheidung für die Zukunft rahmen.","es-ES":"Enmárcala como una decisión estratégica que asegura el futuro."},{"en":"Show the runway and milestones the raise buys.","de":"Die gewonnene Liquidität und Meilensteine aufzeigen.","es-ES":"Muestra la pista y los hitos que compra la ronda."},{"en":"Acknowledge the dilution and value lost honestly.","de":"Verwässerung und Wertverlust offen anerkennen.","es-ES":"Reconoce con honestidad la dilución y el valor perdido."},{"en":"Make a clear ask for their continued participation.","de":"Klar um ihre weitere Beteiligung bitten.","es-ES":"Pide con claridad su participación continuada."}],"rubric":{"content":{"strong":"Justifies the down-round strategically, shows runway and milestones, owns the dilution, and makes a clear ask.","adequate":"Explains the raise but glosses over the valuation hit or the ask.","weak":"Spins or hides the down-round; no credible plan or ask."},"delivery":{"strong":"Confident and candid; conveys resolve, not desperation.","adequate":"Mostly steady but some unease or over-spin.","weak":"Apologetic, evasive, or panicked."},"time":{"strong":"Uses 55-65 seconds, well structured.","adequate":"Slightly off pace.","weak":"Far off or cut short."}},"modelAnswer":{"en":"I'll be direct: we're raising at roughly 30 percent below the last round. The market reset valuations across our sector, and I'd rather price honestly than chase a number we can't defend. This raise gives us 24 months of runway, enough to hit profitability on our core product without needing the market to cooperate. Yes, it dilutes us, and I feel that too. But it converts a financing risk into an execution story we control. I'm asking you to lead your pro-rata. Your signal here matters.","de":"Ich sage es direkt: Wir nehmen zu rund 30 Prozent unter der letzten Runde auf. Der Markt hat die Bewertungen in unserem Sektor zurückgesetzt, und ich preise lieber ehrlich, als eine Zahl zu jagen, die wir nicht verteidigen können. Diese Runde verschafft uns 24 Monate Liquidität, genug, um mit dem Kernprodukt profitabel zu werden, ohne auf den Markt angewiesen zu sein. Ja, das verwässert uns, und das spüre ich auch. Aber es macht aus einem Finanzierungsrisiko eine Umsetzungsgeschichte, die wir steuern. Ich bitte euch, eure Pro-rata anzuführen. Euer Signal zählt.","es-ES":"Seré directo: captamos a alrededor de un 30 por ciento por debajo de la ronda anterior. El mercado ha reajustado las valoraciones de nuestro sector y prefiero poner un precio honesto que perseguir una cifra indefendible. Esta ronda nos da 24 meses de pista, suficiente para alcanzar la rentabilidad del producto central sin depender del mercado. Sí, nos diluye, y yo también lo siento. Pero convierte un riesgo de financiación en una historia de ejecución que controlamos. Os pido que lideréis vuestro prorrateo. Vuestra señal aquí importa."}},
  {"id":"TEC-4","type":"situational","category":"professional_communication","department":"technology","difficulty":4,"media":{"scene":"exec_committee","alt":{"en":"A CTO standing before an executive committee delivering an incident briefing on screens behind them","de":"Eine CTO steht vor einem Exekutivausschuss und hält ein Incident-Briefing vor Bildschirmen","es-ES":"Un CTO de pie ante un comité ejecutivo dando un informe de incidente con pantallas detrás"}},"roleCaption":{"en":"You are the CTO briefing the executive committee on a data-loss incident.","de":"Sie sind die CTO und informieren den Exekutivausschuss über einen Datenverlustvorfall.","es-ES":"Eres el CTO informando al comité ejecutivo sobre un incidente de pérdida de datos."},"scenario":{"en":"A failed migration overnight deleted 6 hours of customer transaction records before backups caught it. About 2,000 customers are affected and support is fielding angry calls. The executive committee has pulled you into an emergency meeting. They want to know what happened, what you've recovered, what customers will experience, and how you'll prevent a repeat. Give your 60-second briefing now.","de":"Eine fehlgeschlagene Migration löschte über Nacht 6 Stunden Kundentransaktionsdaten, bevor Backups eingriffen. Rund 2.000 Kunden sind betroffen und der Support nimmt wütende Anrufe entgegen. Der Exekutivausschuss hat Sie zu einer Krisensitzung gerufen. Sie wollen wissen, was passiert ist, was Sie wiederhergestellt haben, was Kunden erleben und wie Sie eine Wiederholung verhindern. Geben Sie jetzt Ihr 60-Sekunden-Briefing.","es-ES":"Una migración fallida durante la noche borró 6 horas de registros de transacciones de clientes antes de que las copias de seguridad lo detectaran. Unos 2.000 clientes están afectados y soporte recibe llamadas furiosas. El comité ejecutivo te ha convocado a una reunión de emergencia. Quieren saber qué pasó, qué has recuperado, qué experimentarán los clientes y cómo evitarás que se repita. Da tu informe de 60 segundos ahora."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"State the scope plainly: what was lost, how many customers, the recovery status","de":"Den Umfang klar benennen: was verloren ging, wie viele Kunden, der Wiederherstellungsstand","es-ES":"Indica el alcance con claridad: qué se perdió, cuántos clientes, el estado de la recuperación"},{"en":"Take ownership without blaming individuals or making excuses","de":"Verantwortung übernehmen, ohne Einzelne zu beschuldigen oder sich zu rechtfertigen","es-ES":"Asume la responsabilidad sin culpar a personas ni poner excusas"},{"en":"Describe the concrete customer impact and the remediation plan for them","de":"Die konkrete Kundenauswirkung und den Wiedergutmachungsplan beschreiben","es-ES":"Describe el impacto concreto en el cliente y el plan de remediación para ellos"},{"en":"Name two specific safeguards to prevent recurrence","de":"Zwei konkrete Schutzmaßnahmen gegen eine Wiederholung nennen","es-ES":"Nombra dos salvaguardas concretas para evitar la repetición"},{"en":"Commit to a clear timeline and next update","de":"Sich zu einem klaren Zeitplan und nächsten Update verpflichten","es-ES":"Comprométete con un cronograma claro y la próxima actualización"}],"rubric":{"content":{"strong":"Clear scope, owned accountability, concrete customer remediation, two specific safeguards, and a committed timeline.","adequate":"Covers what happened and impact but is vague on safeguards or remediation specifics.","weak":"Deflects blame, omits customer impact, or offers no prevention plan or timeline."},"delivery":{"strong":"Calm, steady, and authoritative under pressure; conveys control without minimizing.","adequate":"Mostly composed but some hedging or nervous pacing.","weak":"Defensive, panicked, or evasive tone that erodes confidence."},"time":{"strong":"Lands within 55-65 seconds covering all four asks.","adequate":"Slightly over or under, mostly complete.","weak":"Runs far over or stops well short of the brief."}},"modelAnswer":{"en":"Here's where we stand. Last night's migration deleted six hours of transaction records before our backups intervened, affecting about 2,000 customers. We've recovered all but the final 40 minutes, which we're reconstructing from logs by tomorrow. Affected customers will see a confirmation email and any duplicate charges reversed. I own this. Two fixes are already in motion: migrations now require a verified snapshot before running, and a staged rollout gate. I'll update you at 5pm.","de":"So ist der Stand. Die Migration letzte Nacht löschte sechs Stunden Transaktionsdaten, bevor Backups eingriffen, rund 2.000 Kunden sind betroffen. Wir haben alles bis auf die letzten 40 Minuten wiederhergestellt, die wir bis morgen aus Logs rekonstruieren. Betroffene Kunden erhalten eine Bestätigungs-E-Mail, Doppelbuchungen werden storniert. Ich übernehme die Verantwortung. Zwei Korrekturen laufen: Migrationen erfordern jetzt einen geprüften Snapshot und ein gestaffeltes Rollout-Gate. Ich informiere Sie um 17 Uhr.","es-ES":"Esta es la situación. La migración de anoche borró seis horas de registros antes de que actuaran las copias, afectando a unos 2.000 clientes. Hemos recuperado todo salvo los últimos 40 minutos, que reconstruiremos desde los logs para mañana. Los clientes afectados recibirán un correo de confirmación y se revertirán cargos duplicados. Asumo la responsabilidad. Ya hay dos arreglos en marcha: las migraciones exigen ahora un snapshot verificado y una compuerta de despliegue por fases. Os actualizo a las 17h."}},
  {"id":"TEC-5","type":"conflict","category":"conflict_resolution","department":"technology","difficulty":3,"media":{"scene":"office_1on1","alt":{"en":"A tense one-on-one between an engineering leader and a product manager at a small table","de":"Ein angespanntes Vieraugengespräch zwischen einer Engineering-Leiterin und einem Produktmanager an einem kleinen Tisch","es-ES":"Un tenso cara a cara entre una líder de ingeniería y un gerente de producto en una mesa pequeña"}},"roleCaption":{"en":"You are the engineering lead pushing back on scope added mid-sprint.","de":"Sie sind die Engineering-Leiterin und wehren sich gegen mitten im Sprint hinzugefügten Umfang.","es-ES":"Eres la líder de ingeniería oponiéndote al alcance añadido a mitad de sprint."},"scenario":{"en":"Three days into a two-week sprint, your product manager wants to add a 'small' feature a key client requested, insisting it won't disrupt the committed work. Your team is already at capacity and the original goals are at risk. The PM is frustrated and feels engineering always says no. You're now sitting down to address this directly. Make your case in 60 seconds.","de":"Drei Tage in einen zweiwöchigen Sprint will Ihr Produktmanager ein 'kleines' Feature hinzufügen, das ein wichtiger Kunde wünscht, und besteht darauf, dass es die zugesagte Arbeit nicht stört. Ihr Team ist bereits ausgelastet und die ursprünglichen Ziele sind gefährdet. Der PM ist frustriert und findet, Engineering sage immer Nein. Sie sprechen es jetzt direkt an. Bringen Sie Ihren Standpunkt in 60 Sekunden.","es-ES":"A tres días de un sprint de dos semanas, tu gerente de producto quiere añadir una función 'pequeña' que pidió un cliente clave, insistiendo en que no afectará el trabajo comprometido. Tu equipo ya está al límite y los objetivos originales corren peligro. El PM está frustrado y siente que ingeniería siempre dice que no. Vas a abordarlo directamente. Expón tu caso en 60 segundos."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Acknowledge the client need as legitimate, not an obstacle","de":"Den Kundenbedarf als legitim anerkennen, nicht als Hindernis","es-ES":"Reconoce la necesidad del cliente como legítima, no como un obstáculo"},{"en":"Make the trade-off explicit: what gets cut if this goes in","de":"Den Kompromiss explizit machen: was wegfällt, wenn dies hinzukommt","es-ES":"Haz explícito el intercambio: qué se elimina si esto entra"},{"en":"Offer a path, not just a refusal (next sprint, swap, or scoped-down)","de":"Einen Weg anbieten, nicht nur eine Ablehnung (nächster Sprint, Tausch, abgespeckt)","es-ES":"Ofrece un camino, no solo una negativa (próximo sprint, intercambio o versión reducida)"},{"en":"Protect the team without sounding rigid or territorial","de":"Das Team schützen, ohne starr oder territorial zu wirken","es-ES":"Protege al equipo sin sonar rígido ni territorial"},{"en":"Invite the PM to decide the trade-off with you","de":"Den PM einladen, den Kompromiss gemeinsam zu entscheiden","es-ES":"Invita al PM a decidir el intercambio contigo"}],"rubric":{"content":{"strong":"Validates the need, names the explicit trade-off, and offers a concrete collaborative path forward.","adequate":"Pushes back with reasons but offers a thin alternative or skips the trade-off math.","weak":"Flat refusal or capitulation; no trade-off framing or collaborative option."},"delivery":{"strong":"Firm yet collaborative; respectful tone that lowers the temperature.","adequate":"Reasonable but slightly defensive or curt in places.","weak":"Combative, dismissive, or passive tone that deepens the conflict."},"time":{"strong":"Lands within 55-65 seconds, complete and focused.","adequate":"Slightly off target but covers the core argument.","weak":"Rambles past time or cuts off mid-point."}},"modelAnswer":{"en":"I hear you, and I get why this client matters. The issue isn't the feature, it's the timing. We committed this sprint to capacity, so adding it doesn't expand the day, it displaces something. So let's decide together: we can pull it in by dropping the reporting tweak, ship a scoped-down version this week, or slot the full thing first into next sprint. I'm not saying no. I'm asking which trade-off we make so I'm not quietly breaking the commitment we both made.","de":"Ich verstehe dich, und mir ist klar, warum dieser Kunde wichtig ist. Das Problem ist nicht das Feature, sondern das Timing. Wir haben diesen Sprint voll verplant, das Hinzufügen verlängert den Tag nicht, es verdrängt etwas. Entscheiden wir gemeinsam: Wir ziehen es rein und streichen die Reporting-Anpassung, liefern diese Woche eine abgespeckte Version, oder setzen es als Erstes in den nächsten Sprint. Ich sage nicht Nein. Ich frage, welchen Kompromiss wir wählen, damit ich unsere Zusage nicht stillschweigend breche.","es-ES":"Te escucho, y entiendo por qué importa este cliente. El problema no es la función, es el momento. Comprometimos este sprint al límite, así que añadirla no alarga el día, desplaza algo. Decidamos juntos: la metemos quitando el ajuste de informes, lanzamos una versión reducida esta semana, o ponemos la completa primera en el próximo sprint. No digo que no. Pregunto qué intercambio hacemos para no romper en silencio el compromiso que ambos asumimos."}},
  {"id":"TEC-6","type":"feedback360","category":"feedback_difficult_conversations","department":"technology","difficulty":4,"media":{"scene":"feedback_report","alt":{"en":"An engineering manager reviewing a 360 feedback report before a difficult conversation","de":"Eine Engineering-Managerin prüft einen 360-Grad-Feedback-Bericht vor einem schwierigen Gespräch","es-ES":"Una gerente de ingeniería revisa un informe de feedback 360 antes de una conversación difícil"}},"roleCaption":{"en":"You are giving a brilliant but abrasive senior engineer hard feedback.","de":"Sie geben einem brillanten, aber schroffen Senior-Engineer hartes Feedback.","es-ES":"Vas a dar feedback duro a un ingeniero senior brillante pero abrasivo."},"scenario":{"en":"Your strongest engineer is technically exceptional but his 360 review is brutal: peers call him dismissive in reviews, juniors avoid asking him questions, and two people hinted they'd leave if paired with him. He genuinely doesn't see the problem and believes results speak for themselves. You're meeting one-on-one to deliver this. Give the feedback in 60 seconds in a way he can actually hear.","de":"Ihr stärkster Engineer ist technisch herausragend, aber sein 360-Feedback ist hart: Kollegen nennen ihn abweisend in Reviews, Junioren meiden seine Fragen, und zwei deuteten an, sie würden gehen, wenn sie mit ihm gepaart würden. Er sieht das Problem wirklich nicht und glaubt, Ergebnisse sprechen für sich. Sie liefern dies im Vieraugengespräch. Geben Sie das Feedback in 60 Sekunden so, dass er es wirklich hören kann.","es-ES":"Tu mejor ingeniero es técnicamente excepcional, pero su evaluación 360 es brutal: los compañeros lo llaman desdeñoso en las revisiones, los júnior evitan preguntarle, y dos insinuaron que se irían si los emparejan con él. Él de verdad no ve el problema y cree que los resultados hablan por sí solos. Os reunís a solas para comunicarlo. Da el feedback en 60 segundos de forma que pueda escucharlo de verdad."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Open by genuinely valuing his technical contribution","de":"Mit echter Wertschätzung seines technischen Beitrags beginnen","es-ES":"Empieza valorando con sinceridad su aporte técnico"},{"en":"Use specific behaviors and impact, not labels like 'toxic'","de":"Konkrete Verhaltensweisen und Wirkung nennen, keine Etiketten wie 'toxisch'","es-ES":"Usa conductas e impacto concretos, no etiquetas como 'tóxico'"},{"en":"Connect the behavior to a cost he cares about (team output, attrition)","de":"Das Verhalten mit Kosten verknüpfen, die ihm wichtig sind (Teamleistung, Fluktuation)","es-ES":"Conecta la conducta con un coste que le importe (rendimiento, rotación)"},{"en":"Make clear this is non-negotiable, not optional polish","de":"Klarmachen, dass dies nicht verhandelbar ist, kein optionaler Feinschliff","es-ES":"Deja claro que no es negociable, no un pulido opcional"},{"en":"Offer support and a concrete next step","de":"Unterstützung und einen konkreten nächsten Schritt anbieten","es-ES":"Ofrece apoyo y un siguiente paso concreto"}],"rubric":{"content":{"strong":"Affirms strength, cites specific behaviors and impact, sets a clear non-negotiable bar, and offers support.","adequate":"Names the problem but leans on labels or softens the bar so the message blurs.","weak":"Vague praise sandwich, no specifics, or attacks character with no path forward."},"delivery":{"strong":"Direct and warm; steady tone that conveys respect and seriousness at once.","adequate":"Clear but either too soft or slightly harsh in spots.","weak":"Apologetic and mushy or cold and accusatory."},"time":{"strong":"Lands within 55-65 seconds, complete and balanced.","adequate":"Slightly off but covers the key message.","weak":"Overruns or omits the impact or the ask."}},"modelAnswer":{"en":"Your engineering is the best on this team, and I want you here for years. That's why this matters. In the 360, peers consistently described your reviews as dismissive, and juniors have stopped asking you questions. Two people told me they'd leave a project rather than pair with you. Your code is excellent, but it's costing us the people around you. This part isn't optional. I'll back you fully, get you a coach if useful, and we check in every two weeks. Can we start there?","de":"Deine Arbeit ist die beste im Team, und ich will dich noch Jahre hier haben. Genau deshalb zählt das. Im 360 beschrieben Kollegen deine Reviews durchweg als abweisend, und Junioren stellen dir keine Fragen mehr. Zwei sagten mir, sie würden ein Projekt verlassen, statt mit dir zu arbeiten. Dein Code ist exzellent, aber er kostet uns die Menschen um dich herum. Das ist nicht optional. Ich unterstütze dich voll, hole bei Bedarf einen Coach, und wir sprechen alle zwei Wochen. Fangen wir damit an?","es-ES":"Tu ingeniería es la mejor del equipo, y te quiero aquí durante años. Por eso esto importa. En el 360, los compañeros describieron tus revisiones como desdeñosas, y los júnior han dejado de preguntarte. Dos me dijeron que dejarían un proyecto antes que trabajar contigo. Tu código es excelente, pero nos está costando la gente a tu alrededor. Esta parte no es opcional. Te respaldaré del todo, te consigo un coach si ayuda, y nos vemos cada dos semanas. ¿Empezamos por ahí?"}},
  {"id":"TEC-7","type":"behavioral","category":"leadership_decisions","department":"technology","difficulty":3,"media":{"scene":"exec_committee","alt":{"en":"A VP of engineering addressing the CEO and leadership about an AI feature's readiness","de":"Ein VP Engineering spricht mit dem CEO und der Führung über die Reife eines KI-Features","es-ES":"Un VP de ingeniería se dirige al CEO y la dirección sobre la preparación de una función de IA"}},"roleCaption":{"en":"You are telling the CEO the AI feature isn't trustworthy enough to ship.","de":"Sie sagen dem CEO, dass das KI-Feature noch nicht vertrauenswürdig genug zum Ausliefern ist.","es-ES":"Le dices al CEO que la función de IA aún no es lo bastante fiable para lanzarla."},"scenario":{"en":"The CEO has publicly teased an AI feature for next week's launch and the board is excited. But your testing shows it hallucinates wrong answers about 8% of the time on real customer queries, sometimes confidently. Shipping it risks customer trust and possibly legal exposure. The CEO wants it live. You've asked for five minutes before the all-hands. Tell them why it can't ship yet in 60 seconds.","de":"Der CEO hat ein KI-Feature öffentlich für den Launch nächste Woche angeteasert und der Vorstand ist begeistert. Doch Ihre Tests zeigen, dass es bei echten Kundenanfragen in etwa 8% der Fälle falsche Antworten halluziniert, manchmal selbstbewusst. Ein Launch gefährdet das Kundenvertrauen und womöglich rechtlich. Der CEO will es live. Sie haben fünf Minuten vor dem All-Hands erbeten. Erklären Sie in 60 Sekunden, warum es noch nicht ausgeliefert werden kann.","es-ES":"El CEO ha adelantado públicamente una función de IA para el lanzamiento de la próxima semana y la junta está entusiasmada. Pero tus pruebas muestran que alucina respuestas erróneas en torno al 8% de las consultas reales, a veces con seguridad. Lanzarla arriesga la confianza del cliente y quizá exposición legal. El CEO quiere sacarla. Has pedido cinco minutos antes de la reunión general. Explica en 60 segundos por qué aún no puede lanzarse."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Lead with the data and the concrete risk, not vague caution","de":"Mit Daten und konkretem Risiko beginnen, nicht mit vager Vorsicht","es-ES":"Empieza con los datos y el riesgo concreto, no con cautela vaga"},{"en":"Translate the technical flaw into business and trust terms","de":"Den technischen Fehler in Geschäfts- und Vertrauensbegriffe übersetzen","es-ES":"Traduce el fallo técnico a términos de negocio y confianza"},{"en":"Respect the CEO's commitment and the launch pressure","de":"Das Engagement des CEO und den Launch-Druck respektieren","es-ES":"Respeta el compromiso del CEO y la presión del lanzamiento"},{"en":"Offer a credible alternative (limited beta, delay, guardrails)","de":"Eine glaubwürdige Alternative anbieten (begrenzte Beta, Aufschub, Leitplanken)","es-ES":"Ofrece una alternativa creíble (beta limitada, retraso, salvaguardas)"},{"en":"State your recommendation clearly and own it","de":"Ihre Empfehlung klar aussprechen und dazu stehen","es-ES":"Expón tu recomendación con claridad y respáldala"}],"rubric":{"content":{"strong":"Cites the 8% data, frames trust/legal risk, respects the pressure, and offers a credible alternative with a clear recommendation.","adequate":"Raises the concern with some data but is thin on alternatives or wavers on the recommendation.","weak":"Vague worry, no data, no alternative, or simply caves to pressure."},"delivery":{"strong":"Confident and respectful; conviction without alarmism or defensiveness.","adequate":"Clear but slightly hedged or tentative under the CEO's expectation.","weak":"Either apologetic and easily overruled or combative and absolute."},"time":{"strong":"Lands within 55-65 seconds, complete and decisive.","adequate":"Slightly off but makes the case.","weak":"Overruns or trails off without a recommendation."}},"modelAnswer":{"en":"I know how much is riding on next week, and I want this to win as much as you do. Here's my concern: in testing on real queries, it gives confidently wrong answers about 8% of the time. At our volume that's thousands of customers misled in week one, and given the topics, it's a trust and legal risk we can't walk back. My recommendation: launch it as an invite-only beta with a visible 'AI may be wrong' label while we close the gap. We keep the moment, without betting the brand on it.","de":"Ich weiß, wie viel von nächster Woche abhängt, und ich will diesen Erfolg genauso wie Sie. Mein Bedenken: Bei Tests mit echten Anfragen gibt es in etwa 8% selbstbewusst falsche Antworten. Bei unserem Volumen sind das Tausende fehlgeleitete Kunden in Woche eins, und angesichts der Themen ein Vertrauens- und Rechtsrisiko, das wir nicht zurückholen können. Meine Empfehlung: als Invite-only-Beta mit sichtbarem 'KI kann irren'-Hinweis starten, während wir die Lücke schließen. Wir behalten den Moment, ohne die Marke aufs Spiel zu setzen.","es-ES":"Sé cuánto depende de la próxima semana, y quiero que esto triunfe tanto como tú. Mi preocupación: en pruebas con consultas reales, da respuestas erróneas con seguridad en torno al 8% de las veces. A nuestro volumen son miles de clientes mal informados en la primera semana, y dados los temas, es un riesgo de confianza y legal que no podemos deshacer. Mi recomendación: lanzarla como beta por invitación con una etiqueta visible de 'la IA puede equivocarse' mientras cerramos la brecha. Conservamos el momento sin apostar la marca."}},
  {"id":"TEC-8","type":"coaching","category":"self_awareness_development","department":"technology","difficulty":2,"media":{"scene":"coaching_room","alt":{"en":"An engineering director coaching a visibly tired team lead in a quiet room","de":"Ein Engineering-Direktor coacht einen sichtlich erschöpften Teamleiter in einem ruhigen Raum","es-ES":"Un director de ingeniería asesora a un líder de equipo visiblemente cansado en una sala tranquila"}},"roleCaption":{"en":"You are coaching a team lead who is sliding into burnout.","de":"Sie coachen einen Teamleiter, der in ein Burnout abrutscht.","es-ES":"Estás asesorando a un líder de equipo que se desliza hacia el agotamiento."},"scenario":{"en":"One of your best team leads has been working nights and weekends, snapping in standups, and shipping late despite the hours. You suspect burnout, and they've quietly hinted they feel like they're failing. They're proud and may resist help. You've set aside time for a one-on-one. Coach them in 60 seconds in a way that opens the conversation rather than dictating a fix.","de":"Einer Ihrer besten Teamleiter arbeitet nachts und am Wochenende, ist im Standup gereizt und liefert trotz der Stunden verspätet. Sie vermuten Burnout, und er hat leise angedeutet, sich als Versager zu fühlen. Er ist stolz und könnte Hilfe ablehnen. Sie haben Zeit für ein Vieraugengespräch reserviert. Coachen Sie ihn in 60 Sekunden so, dass sich das Gespräch öffnet, statt eine Lösung vorzuschreiben.","es-ES":"Uno de tus mejores líderes de equipo trabaja noches y fines de semana, salta en las reuniones diarias y entrega tarde pese a las horas. Sospechas agotamiento, y él ha insinuado en voz baja que siente que está fracasando. Es orgulloso y puede resistirse a la ayuda. Has reservado tiempo para un cara a cara. Asesóralo en 60 segundos de modo que abra la conversación en lugar de imponer una solución."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Open with care and a specific observation, not a diagnosis","de":"Mit Fürsorge und einer konkreten Beobachtung beginnen, keiner Diagnose","es-ES":"Abre con cuidado y una observación concreta, no un diagnóstico"},{"en":"Normalize the struggle and remove shame","de":"Die Belastung normalisieren und Scham nehmen","es-ES":"Normaliza la dificultad y elimina la vergüenza"},{"en":"Ask an open question and create space to answer","de":"Eine offene Frage stellen und Raum zum Antworten schaffen","es-ES":"Haz una pregunta abierta y da espacio para responder"},{"en":"Signal support and concrete relief options","de":"Unterstützung und konkrete Entlastungsoptionen signalisieren","es-ES":"Señala apoyo y opciones concretas de alivio"},{"en":"Reaffirm your confidence in them","de":"Ihr Vertrauen in ihn bekräftigen","es-ES":"Reafirma tu confianza en él"}],"rubric":{"content":{"strong":"Specific caring observation, removes shame, asks an open question, offers concrete relief, and reaffirms confidence.","adequate":"Shows concern but jumps to solutions or skips the open question.","weak":"Diagnoses or lectures, offers no support, or makes them feel judged."},"delivery":{"strong":"Warm, unhurried, genuinely curious; invites trust.","adequate":"Caring but slightly rushed or prescriptive in tone.","weak":"Clinical, impatient, or transactional."},"time":{"strong":"Lands within 55-65 seconds and leaves room to listen.","adequate":"Slightly off but conversational.","weak":"Overruns by monologuing or stops abruptly."}},"modelAnswer":{"en":"I wanted to talk because I care about you, not just the deliverables. I've noticed you online at midnight, and standups feel tense lately, and that's not like you. I'm not here to tell you what to do, I want to understand what this stretch has felt like for you. Honestly, what's it been like? Whatever it is, you're not failing, this team is strong because of you. If we need to shift load, pause a project, or get you real recovery time, we can. Where do we start?","de":"Ich wollte reden, weil du mir wichtig bist, nicht nur die Lieferungen. Mir ist aufgefallen, dass du um Mitternacht online bist, und die Standups wirken zuletzt angespannt, das passt nicht zu dir. Ich will dir nicht sagen, was zu tun ist, sondern verstehen, wie sich diese Phase für dich angefühlt hat. Ehrlich, wie war es? Was auch immer es ist, du versagst nicht, dieses Team ist stark wegen dir. Wenn wir Last verschieben, ein Projekt pausieren oder dir echte Erholung verschaffen müssen, geht das. Wo fangen wir an?","es-ES":"Quería hablar porque me importas tú, no solo las entregas. He notado que estás conectado a medianoche, y las reuniones se sienten tensas últimamente, y eso no es propio de ti. No vengo a decirte qué hacer, quiero entender cómo ha sido esta etapa para ti. Sinceramente, ¿cómo lo has vivido? Sea lo que sea, no estás fracasando, este equipo es fuerte gracias a ti. Si hay que repartir carga, pausar un proyecto o darte recuperación de verdad, podemos. ¿Por dónde empezamos?"}},
  {"id":"TEC-9","type":"situational","category":"strategic_thinking","department":"technology","difficulty":4,"media":{"scene":"boardroom","alt":{"en":"A CTO in a boardroom making the case to pay down technical debt before new features","de":"Eine CTO im Sitzungssaal begründet, technische Schulden vor neuen Features abzubauen","es-ES":"Una CTO en una sala de juntas defendiendo saldar deuda técnica antes de nuevas funciones"}},"roleCaption":{"en":"You are justifying slowing features for a quarter to pay down tech debt.","de":"Sie begründen, Features ein Quartal lang zu drosseln, um technische Schulden abzubauen.","es-ES":"Justificas frenar funciones un trimestre para saldar deuda técnica."},"scenario":{"en":"Your platform's velocity is collapsing: deploys fail often, incidents are rising, and engineers spend half their time firefighting legacy code. You want to dedicate the next quarter mostly to tech debt, which means almost no new customer-facing features. The board and sales leaders, who want growth, are skeptical and worried about competitors. Make the case to the board in 60 seconds.","de":"Die Geschwindigkeit Ihrer Plattform bricht ein: Deploys schlagen oft fehl, Incidents steigen, und Engineers verbringen die halbe Zeit mit Legacy-Code-Löscharbeiten. Sie wollen das nächste Quartal überwiegend technischen Schulden widmen, also fast keine neuen kundenseitigen Features. Vorstand und Vertriebsleitung, die Wachstum wollen, sind skeptisch und besorgt über Wettbewerber. Bringen Sie Ihren Standpunkt in 60 Sekunden vor dem Vorstand.","es-ES":"La velocidad de tu plataforma se desploma: los despliegues fallan a menudo, los incidentes crecen y los ingenieros pasan la mitad del tiempo apagando fuegos en código heredado. Quieres dedicar el próximo trimestre sobre todo a la deuda técnica, lo que implica casi ninguna función nueva para clientes. La junta y los líderes de ventas, que quieren crecimiento, están escépticos y temen a los competidores. Defiende tu caso ante la junta en 60 segundos."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Quantify the cost of the status quo in business terms","de":"Die Kosten des Status quo in Geschäftsbegriffen beziffern","es-ES":"Cuantifica el coste del statu quo en términos de negocio"},{"en":"Frame tech debt work as an investment in future velocity, not a pause","de":"Schuldenabbau als Investition in künftige Geschwindigkeit rahmen, nicht als Pause","es-ES":"Enmarca el trabajo de deuda como inversión en velocidad futura, no una pausa"},{"en":"Acknowledge the growth concern and the competitive fear directly","de":"Die Wachstumssorge und Wettbewerbsangst direkt anerkennen","es-ES":"Reconoce directamente la preocupación por el crecimiento y la competencia"},{"en":"Offer a bounded plan with measurable outcomes","de":"Einen begrenzten Plan mit messbaren Ergebnissen anbieten","es-ES":"Ofrece un plan acotado con resultados medibles"},{"en":"Show what faster, more reliable shipping unlocks after","de":"Zeigen, was schnelleres, zuverlässigeres Ausliefern danach ermöglicht","es-ES":"Muestra qué desbloquea después un envío más rápido y fiable"}],"rubric":{"content":{"strong":"Quantifies status-quo cost, frames debt as velocity investment, addresses the growth fear, and offers a bounded measurable plan.","adequate":"Makes the velocity argument but is light on numbers or the bounded plan.","weak":"Abstract 'we need to fix things' plea with no business framing or plan."},"delivery":{"strong":"Confident and strategic; speaks the board's language with conviction.","adequate":"Clear but slightly technical or defensive.","weak":"Jargon-heavy, apologetic, or fails to connect to business value."},"time":{"strong":"Lands within 55-65 seconds, complete and persuasive.","adequate":"Slightly off but covers the argument.","weak":"Overruns or omits the plan or the payoff."}},"modelAnswer":{"en":"I want growth too, and that's exactly why I'm raising this. Right now engineers spend half their time firefighting, deploys fail often, and incidents are rising. We're already shipping slowly, we're just paying for it in chaos instead of choosing it. I'm proposing one focused quarter to cut that firefighting in half, with clear targets: deploy success up, incident rate down, lead time halved. This isn't a pause on growth, it's removing the brake. After this, we ship the roadmap faster and more reliably than competitors can. I'll report metrics monthly.","de":"Ich will auch Wachstum, und genau deshalb spreche ich es an. Aktuell verbringen Engineers die halbe Zeit mit Löscharbeiten, Deploys schlagen oft fehl, Incidents steigen. Wir liefern bereits langsam, zahlen es nur im Chaos statt es zu wählen. Ich schlage ein fokussiertes Quartal vor, um diese Löscharbeiten zu halbieren, mit klaren Zielen: höhere Deploy-Erfolgsrate, weniger Incidents, halbierte Durchlaufzeit. Das ist keine Wachstumspause, es löst die Bremse. Danach liefern wir die Roadmap schneller und zuverlässiger als die Konkurrenz. Ich berichte monatlich Kennzahlen.","es-ES":"Yo también quiero crecimiento, y por eso lo planteo. Ahora los ingenieros pasan la mitad del tiempo apagando fuegos, los despliegues fallan a menudo y los incidentes suben. Ya entregamos despacio, solo que lo pagamos en caos en vez de elegirlo. Propongo un trimestre enfocado en reducir a la mitad esos fuegos, con metas claras: más éxito de despliegue, menos incidentes, mitad de lead time. No es una pausa al crecimiento, es quitar el freno. Después entregaremos la hoja de ruta más rápido y fiable que la competencia. Reportaré métricas cada mes."}},
  {"id":"COM-4","type":"situational","category":"professional_communication","department":"commercial","difficulty":2,"media":{"scene":"video_call","alt":{"en":"A discovery video call with a prospect who just joined and is checking the time.","de":"Ein Discovery-Videocall mit einem Interessenten, der gerade beigetreten ist und auf die Uhr schaut.","es-ES":"Una videollamada de descubrimiento con un cliente potencial que acaba de entrar y mira la hora."}},"roleCaption":{"en":"You are the account executive opening a cold discovery call.","de":"Sie sind der Account Executive und eroeffnen einen kalten Discovery-Call.","es-ES":"Eres el ejecutivo de cuentas que abre una llamada de descubrimiento en frio."},"scenario":{"en":"You finally landed a call with a busy VP who replied to one cold email. She joins three minutes late, says 'I've got fifteen minutes, what's this about?' You have no rapport and no agenda set. Open the call: earn the time, frame why you're worth it, and get her talking about her world.","de":"Endlich haben Sie einen Termin mit einer vielbeschaeftigten VP, die auf eine Kalt-E-Mail geantwortet hat. Sie kommt drei Minuten zu spaet und sagt: 'Ich habe fuenfzehn Minuten, worum geht es?' Es gibt keine Beziehung und keine Agenda. Eroeffnen Sie das Gespraech: verdienen Sie sich die Zeit, machen Sie klar, warum es sich lohnt, und bringen Sie sie dazu, ueber ihre Welt zu sprechen.","es-ES":"Por fin conseguiste una llamada con una VP muy ocupada que respondio a un correo en frio. Entra tres minutos tarde y dice: 'Tengo quince minutos, de que se trata?' No hay relacion ni agenda. Abre la llamada: gana el tiempo, explica por que vale la pena y haz que ella hable de su mundo."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Acknowledge her time and set a crisp, value-first agenda.","de":"Wuerdigen Sie ihre Zeit und setzen Sie eine knappe, wertorientierte Agenda.","es-ES":"Reconoce su tiempo y propon una agenda breve centrada en el valor."},{"en":"Anchor on a specific problem you see in her segment, not your product.","de":"Verankern Sie sich an einem konkreten Problem ihres Segments, nicht an Ihrem Produkt.","es-ES":"Ancla en un problema concreto de su segmento, no en tu producto."},{"en":"Ask one sharp, open question to make her the speaker.","de":"Stellen Sie eine pointierte, offene Frage, damit sie spricht.","es-ES":"Haz una pregunta abierta y precisa para que ella tome la palabra."},{"en":"Offer an easy exit to lower the pressure and build trust.","de":"Bieten Sie einen einfachen Ausstieg, um Druck zu senken und Vertrauen zu schaffen.","es-ES":"Ofrece una salida facil para bajar la presion y generar confianza."},{"en":"Stay calm and unhurried despite the short clock.","de":"Bleiben Sie ruhig und unaufgeregt trotz der knappen Zeit.","es-ES":"Manten la calma y sin prisas pese al poco tiempo."}],"rubric":{"content":{"strong":"Earns the time with a value-first agenda, anchors on a segment-specific problem, and hands the floor over with one sharp open question.","adequate":"Sets some agenda and asks a question but leans on product or stays generic.","weak":"Launches into a pitch, talks about the product, and never invites her to speak."},"delivery":{"strong":"Warm, composed, and confident; unhurried pace that signals respect for her time without rushing.","adequate":"Mostly steady but occasionally rushed or filler-heavy under the time pressure.","weak":"Nervous, rushed, or over-eager; energy undercuts credibility."},"time":{"strong":"Opens and pivots to her within 60 seconds, leaving room for dialogue.","adequate":"Slightly long or short but lands the core open.","weak":"Runs over or stops abruptly with no question or handoff."}},"modelAnswer":{"en":"Thanks for hopping on, I know fifteen minutes is real money for you. I'll be quick. We work with VPs in your space who are losing deals at the handoff between sales and onboarding, and it's quietly costing them renewals. I don't yet know if that's you, so honestly, if it's not relevant after five minutes, tell me and we'll stop. To start: when a deal closes today, what actually happens in the first week?","de":"Danke, dass Sie dabei sind, ich weiss, fuenfzehn Minuten sind fuer Sie bares Geld. Ich fasse mich kurz. Wir arbeiten mit VPs in Ihrem Umfeld, die Deals an der Uebergabe zwischen Vertrieb und Onboarding verlieren, und das kostet leise Verlaengerungen. Ob das auf Sie zutrifft, weiss ich noch nicht; wenn es nach fuenf Minuten irrelevant ist, sagen Sie es, und wir hoeren auf. Zum Start: Wenn heute ein Deal abgeschlossen wird, was passiert in der ersten Woche wirklich?","es-ES":"Gracias por conectarte, se que quince minutos valen oro para ti. Sere breve. Trabajamos con VPs de tu sector que pierden acuerdos en la transicion entre ventas y onboarding, y eso les cuesta renovaciones sin que se note. Aun no se si es tu caso; si en cinco minutos no es relevante, dimelo y paramos. Para empezar: cuando se cierra un acuerdo hoy, que pasa de verdad en la primera semana?"}},
  {"id":"COM-5","type":"situational","category":"strategic_thinking","department":"commercial","difficulty":3,"media":{"scene":"client_meeting","alt":{"en":"A buyer across the table folds his arms after saying there is no budget.","de":"Ein Einkaeufer verschraenkt die Arme, nachdem er gesagt hat, es gebe kein Budget.","es-ES":"Un comprador cruza los brazos tras decir que no hay presupuesto."}},"roleCaption":{"en":"You are the sales lead facing a 'no budget' objection.","de":"Sie sind der Vertriebsleiter und stehen vor dem Einwand 'kein Budget'.","es-ES":"Eres el responsable de ventas ante la objecion 'no hay presupuesto'."},"scenario":{"en":"Late in a strong deal, the champion goes quiet and the economic buyer says flatly: 'Look, I like it, but there's no budget this year.' The fit is real and the pain is real. Respond: don't discount on reflex, don't argue. Reframe the cost of inaction and find the path to value they can fund.","de":"Spaet in einem starken Deal wird der Champion still und der wirtschaftliche Entscheider sagt trocken: 'Schauen Sie, es gefaellt mir, aber dieses Jahr gibt es kein Budget.' Die Passung ist echt, der Schmerz ist echt. Reagieren Sie: rabattieren Sie nicht reflexhaft, streiten Sie nicht. Stellen Sie die Kosten des Nichthandelns dar und finden Sie einen finanzierbaren Weg zum Wert.","es-ES":"Avanzado un buen acuerdo, el champion se queda callado y el comprador economico dice sin rodeos: 'Mira, me gusta, pero este ano no hay presupuesto.' El encaje es real y el dolor es real. Responde: no descuentes por reflejo ni discutas. Replantea el coste de no actuar y encuentra una via de valor que puedan financiar."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Acknowledge the constraint without flinching or discounting.","de":"Wuerdigen Sie die Einschraenkung, ohne zu zucken oder zu rabattieren.","es-ES":"Reconoce la limitacion sin titubear ni descontar."},{"en":"Quantify the cost of doing nothing for another year.","de":"Beziffern Sie die Kosten, ein weiteres Jahr nichts zu tun.","es-ES":"Cuantifica el coste de no hacer nada otro ano mas."},{"en":"Separate 'no budget' from 'not a priority' with a question.","de":"Trennen Sie 'kein Budget' von 'keine Prioritaet' durch eine Frage.","es-ES":"Separa 'sin presupuesto' de 'sin prioridad' con una pregunta."},{"en":"Offer a fundable path: smaller scope, phasing, or a different budget line.","de":"Bieten Sie einen finanzierbaren Weg: kleinerer Umfang, Phasen oder andere Budgetlinie.","es-ES":"Ofrece una via financiable: alcance menor, fases u otra partida."}],"rubric":{"content":{"strong":"Reframes cost of inaction with a number, tests whether it's budget or priority, and proposes a concrete fundable path without caving on price.","adequate":"Reframes value somewhat but either discounts reflexively or skips the priority test.","weak":"Caves with a discount, argues with the buyer, or accepts the no and walks."},"delivery":{"strong":"Calm, consultative, and unrattled; conveys partnership rather than desperation.","adequate":"Steady but slightly defensive or pleading in spots.","weak":"Anxious or pushy; tone signals neediness or pressure."},"time":{"strong":"Delivers a complete reframe and ask within the window.","adequate":"Slightly over or under but covers the core.","weak":"Rambles past time or cuts off before proposing a path."}},"modelAnswer":{"en":"I hear you, and I won't push you to spend money you don't have. Let me ask differently. You said this gap costs your team two days a week; over a year, that's real headcount. So the question isn't the price, it's whether this beats whatever else fights for next year's budget. If it does, let's not wait twelve months. Could we start with a scoped pilot funded from operating costs, prove the number, and build the case together?","de":"Ich verstehe Sie und draenge Sie nicht, Geld auszugeben, das Sie nicht haben. Lassen Sie mich anders fragen. Sie sagten, diese Luecke kostet Ihr Team zwei Tage pro Woche; ueber ein Jahr ist das echte Personalkapazitaet. Die Frage ist nicht der Preis, sondern ob das wichtiger ist als alles, was ums naechste Budget kaempft. Wenn ja, warten wir nicht zwoelf Monate. Starten wir mit einem Pilot aus dem Betriebsbudget, belegen die Zahl und bauen den Case gemeinsam?","es-ES":"Te entiendo, y no voy a presionarte para gastar dinero que no tienes. Dejame preguntarlo distinto. Dijiste que esta brecha cuesta a tu equipo dos dias por semana; en un ano, eso es plantilla real. La cuestion no es el precio, sino si esto pesa mas que lo que compite por el presupuesto del proximo ano. Si es asi, no esperemos doce meses. Empezamos con un piloto desde gasto operativo, probamos la cifra y construimos el caso juntos?"}},
  {"id":"COM-6","type":"behavioral","category":"self_awareness_development","department":"commercial","difficulty":3,"media":{"scene":"exec_committee","alt":{"en":"Executives around a table review a slipped quarter on screen.","de":"Fuehrungskraefte am Tisch betrachten ein verfehltes Quartal auf dem Bildschirm.","es-ES":"Ejecutivos en una mesa revisan un trimestre fallido en pantalla."}},"roleCaption":{"en":"You are the commercial lead explaining a missed quarter.","de":"Sie sind der Commercial Lead und erklaeren ein verfehltes Quartal.","es-ES":"Eres el responsable comercial explicando un trimestre no cumplido."},"scenario":{"en":"Your team missed quota by 18% and the exec committee wants answers. It's tempting to blame the market, a product gap, and marketing leads. Tell the committee about a time your own forecasting or coaching call contributed to the miss, what you learned, and what you've changed. Own it without collapsing into excuses or self-flagellation.","de":"Ihr Team hat das Ziel um 18% verfehlt, und das Exec-Komitee will Antworten. Es ist verlockend, Markt, Produktluecke und Marketing-Leads die Schuld zu geben. Erzaehlen Sie dem Komitee von einer Situation, in der Ihre eigene Forecast- oder Coaching-Entscheidung zum Verfehlen beitrug, was Sie gelernt und geaendert haben. Stehen Sie dazu, ohne in Ausreden oder Selbstgeisselung zu verfallen.","es-ES":"Tu equipo no alcanzo la cuota por un 18% y el comite ejecutivo quiere respuestas. Es tentador culpar al mercado, a un fallo de producto y a los leads de marketing. Cuenta al comite una vez en que tu propia decision de forecast o coaching contribuyo al fallo, que aprendiste y que has cambiado. Asumelo sin caer en excusas ni en autoflagelacion."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Name a specific decision you owned that contributed to the miss.","de":"Nennen Sie eine konkrete eigene Entscheidung, die zum Verfehlen beitrug.","es-ES":"Nombra una decision concreta tuya que contribuyo al fallo."},{"en":"Show the lesson, not just the apology.","de":"Zeigen Sie die Lehre, nicht nur die Entschuldigung.","es-ES":"Muestra el aprendizaje, no solo la disculpa."},{"en":"Describe the concrete change already in motion.","de":"Beschreiben Sie die konkrete Aenderung, die bereits laeuft.","es-ES":"Describe el cambio concreto que ya esta en marcha."},{"en":"Balance accountability with confidence to lead forward.","de":"Balancieren Sie Verantwortung mit dem Selbstvertrauen, weiterzufuehren.","es-ES":"Equilibra responsabilidad con confianza para liderar adelante."}],"rubric":{"content":{"strong":"Owns a specific decision, extracts a clear lesson, and names a concrete change already underway without blame-shifting.","adequate":"Takes some ownership but blurs into external factors or vague lessons.","weak":"Blames market, product, or marketing; offers no personal learning or change."},"delivery":{"strong":"Composed and credible; accountable tone that still projects leadership confidence.","adequate":"Mostly steady but tips into defensiveness or over-apology at points.","weak":"Either defensive and excuse-laden or self-flagellating and shaken."},"time":{"strong":"Owns it, draws the lesson, and states the change within the window.","adequate":"Slightly long or short but lands the core arc.","weak":"Runs over with excuses or stops before stating a change."}},"modelAnswer":{"en":"We missed by eighteen points, and part of that sits with me. I let three big deals stay in commit on verbal interest, with no signed business case. My forecast looked confident, but it was hope dressed as data. The lesson: enthusiasm isn't a stage. So we changed the rule. Nothing enters commit without a quantified case and a named buyer. Two of those three are already disqualified, which hurts the optics but gives you a number you can trust.","de":"Wir haben um achtzehn Punkte verfehlt, und ein Teil liegt bei mir. Ich liess drei grosse Deals auf muendliches Interesse im Commit, ohne unterzeichneten Business Case. Mein Forecast wirkte sicher, war aber als Daten verkleidete Hoffnung. Die Lehre: Begeisterung ist keine Phase. Also aenderten wir die Regel. Nichts kommt ins Commit ohne quantifizierten Case und benannten Entscheider. Zwei der drei sind bereits disqualifiziert, das tut der Optik weh, gibt Ihnen aber eine Zahl, der Sie trauen koennen.","es-ES":"Fallamos por dieciocho puntos, y parte recae en mi. Deje tres grandes acuerdos en commit por interes verbal, sin caso de negocio firmado. Mi forecast parecia solido, pero era esperanza disfrazada de datos. La leccion: el entusiasmo no es una etapa. Asi que cambiamos la regla. Nada entra en commit sin un caso cuantificado y un comprador identificado. Dos de esos tres ya estan descalificados, lo cual duele en la imagen, pero te da una cifra fiable."}},
  {"id":"COM-7","type":"conflict","category":"conflict_resolution","department":"commercial","difficulty":4,"media":{"scene":"client_meeting","alt":{"en":"An unhappy customer team faces you across a QBR table with a churn risk flag.","de":"Ein unzufriedenes Kundenteam sitzt Ihnen im QBR mit Abwanderungsrisiko gegenueber.","es-ES":"Un equipo de cliente molesto te enfrenta en un QBR con riesgo de fuga."}},"roleCaption":{"en":"You are the account owner in a tense renewal QBR.","de":"Sie sind der Account-Owner in einem angespannten Renewal-QBR.","es-ES":"Eres el responsable de cuenta en un QBR de renovacion tenso."},"scenario":{"en":"At a quarterly business review, your biggest customer's COO opens with: 'Honestly, we're questioning this renewal. Two outages, a support ticket open for six weeks, and the value you promised never showed up.' Their team is stone-faced. Respond live: don't get defensive, don't over-promise. Rebuild trust, own what's true, and reset the path to renewal.","de":"Im Quartalsreview eroeffnet der COO Ihres groessten Kunden: 'Ehrlich, wir hinterfragen diese Verlaengerung. Zwei Ausfaelle, ein Support-Ticket seit sechs Wochen offen, und der versprochene Wert kam nie.' Sein Team bleibt regungslos. Reagieren Sie live: nicht defensiv, nicht ueberversprechen. Bauen Sie Vertrauen wieder auf, stehen Sie zum Wahren und setzen Sie den Weg zur Verlaengerung neu.","es-ES":"En la revision trimestral, el COO de tu mayor cliente abre con: 'Sinceramente, cuestionamos esta renovacion. Dos caidas, un ticket de soporte abierto seis semanas y el valor prometido nunca aparecio.' Su equipo esta impasible. Responde en directo: sin ponerte a la defensiva ni prometer de mas. Reconstruye la confianza, asume lo cierto y replantea el camino a la renovacion."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Acknowledge the specific failures without deflecting.","de":"Erkennen Sie die konkreten Fehler an, ohne abzulenken.","es-ES":"Reconoce los fallos concretos sin desviar."},{"en":"Separate what you can fix now from what needs time.","de":"Trennen Sie das sofort Loesbare von dem, was Zeit braucht.","es-ES":"Separa lo que arreglas ya de lo que necesita tiempo."},{"en":"Make a concrete, time-bound commitment you can keep.","de":"Machen Sie eine konkrete, terminierte Zusage, die Sie halten koennen.","es-ES":"Haz un compromiso concreto y con plazo que puedas cumplir."},{"en":"Reframe value around their outcomes, not your features.","de":"Rahmen Sie den Wert um ihre Ergebnisse, nicht um Ihre Features.","es-ES":"Replantea el valor en torno a sus resultados, no a tus funciones."},{"en":"Stay grounded and present under hostility.","de":"Bleiben Sie geerdet und praesent unter Feindseligkeit.","es-ES":"Manten la calma y la presencia ante la hostilidad."}],"rubric":{"content":{"strong":"Owns the specific failures, makes a credible time-bound commitment, and resets value around the customer's outcomes without over-promising.","adequate":"Acknowledges issues and commits but vaguely, or slips into a feature pitch.","weak":"Gets defensive, deflects blame, or over-promises a fix it can't guarantee."},"delivery":{"strong":"Steady, sincere, and present; absorbs the hostility without flinching or appeasing.","adequate":"Mostly composed but shows defensiveness or over-eagerness at moments.","weak":"Rattled, defensive, or placating; loses presence under pressure."},"time":{"strong":"Owns, commits, and reframes within the window without rushing.","adequate":"Slightly over or under but covers the arc.","weak":"Rambles or stops before committing to a path."}},"modelAnswer":{"en":"You're right, and I won't spin it. Two outages and a six-week ticket; that's on us, and it's why the value stalled. So let me be concrete, not reassuring. By Friday I'll have our VP of Engineering and an escalation owner with your team, the ticket closed in ten days, and a downtime credit already moving. Then I want one working session, not a pitch, to map success for you. If there's no movement in ninety days, the renewal question is fair.","de":"Sie haben recht, und ich beschoenige nichts. Zwei Ausfaelle und ein sechs Wochen offenes Ticket; das liegt bei uns, deshalb stockte der Wert. Lassen Sie mich konkret statt beruhigend sein. Bis Freitag bringe ich unseren VP Engineering und einen benannten Eskalations-Owner mit Ihrem Team zusammen, schliesse das Ticket in zehn Tagen, und eine Gutschrift laeuft bereits. Dann moechte ich eine Arbeitssitzung, keinen Pitch, um Erfolg fuer Sie zu definieren. Zeigen wir in neunzig Tagen keine Bewegung, ist die Verlaengerungsfrage berechtigt.","es-ES":"Tienes razon, y no voy a maquillarlo. Dos caidas y un ticket abierto seis semanas; es nuestra responsabilidad, y por eso se estanco el valor. Asi que sere concreto, no tranquilizador. Para el viernes pondre a nuestro VP de Ingenieria y a un responsable de escalado con tu equipo, cerrare el ticket en diez dias, y ya hay un credito en marcha. Luego quiero una sesion de trabajo, no un pitch, para mapear tu exito. Si en noventa dias no hay avances, la duda sobre la renovacion es legitima."}},
  {"id":"COM-8","type":"coaching","category":"leadership_decisions","department":"commercial","difficulty":3,"media":{"scene":"coaching_room","alt":{"en":"A sales manager and a discouraged rep sit together reviewing a pipeline.","de":"Ein Vertriebsleiter und ein entmutigter Mitarbeiter sitzen zusammen ueber einer Pipeline.","es-ES":"Un gerente de ventas y un comercial desanimado revisan juntos un pipeline."}},"roleCaption":{"en":"You are the manager coaching an underperforming rep.","de":"Sie sind der Manager und coachen einen leistungsschwachen Mitarbeiter.","es-ES":"Eres el gerente que entrena a un comercial con bajo rendimiento."},"scenario":{"en":"One of your reps has hit 60% of quota for two quarters. He's hardworking and well-liked but his deals stall at the proposal stage. He sits down looking deflated and says, 'Maybe I'm just not cut out for this.' Coach him in this one-on-one: be honest about the gap, but build belief and agree one concrete behaviour change he'll own this week.","de":"Einer Ihrer Mitarbeiter hat zwei Quartale lang 60% des Ziels erreicht. Er ist fleissig und beliebt, aber seine Deals stocken in der Angebotsphase. Er setzt sich niedergeschlagen hin und sagt: 'Vielleicht bin ich dafuer einfach nicht gemacht.' Coachen Sie ihn in diesem Einzelgespraech: seien Sie ehrlich zur Luecke, aber bauen Sie Zuversicht auf und vereinbaren Sie eine konkrete Verhaltensaenderung fuer diese Woche.","es-ES":"Uno de tus comerciales ha logrado el 60% de la cuota dos trimestres. Es trabajador y querido, pero sus acuerdos se atascan en la fase de propuesta. Se sienta abatido y dice: 'Quiza no estoy hecho para esto.' Entrenalo en este uno a uno: se honesto sobre la brecha, pero genera confianza y acuerda un cambio de conducta concreto que asuma esta semana."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Validate the effort while being honest about the gap.","de":"Wuerdigen Sie den Einsatz und seien Sie ehrlich zur Luecke.","es-ES":"Valida el esfuerzo siendo honesto sobre la brecha."},{"en":"Diagnose the real pattern: deals stall at proposal.","de":"Diagnostizieren Sie das Muster: Deals stocken beim Angebot.","es-ES":"Diagnostica el patron: los acuerdos se atascan en la propuesta."},{"en":"Rebuild belief by separating identity from a fixable skill.","de":"Bauen Sie Zuversicht auf, indem Sie Identitaet von einer loesbaren Faehigkeit trennen.","es-ES":"Reconstruye la confianza separando la identidad de una habilidad corregible."},{"en":"Agree one specific behaviour he owns this week.","de":"Vereinbaren Sie eine konkrete Verhaltensaenderung fuer diese Woche.","es-ES":"Acuerda una conducta concreta que asuma esta semana."}],"rubric":{"content":{"strong":"Names the proposal-stage pattern, reframes the slump as a fixable skill not a fixed identity, and lands one specific owned action.","adequate":"Encourages and diagnoses partly but stays vague on the action or the pattern.","weak":"Either only consoles with no honesty, or criticises with no path or belief-building."},"delivery":{"strong":"Warm yet direct; conveys belief and authority without false cheerleading.","adequate":"Supportive but tips into either softness or bluntness at points.","weak":"Flat, harsh, or hollow; tone undercuts the message."},"time":{"strong":"Validates, diagnoses, and commits to an action within the window.","adequate":"Slightly long or short but covers the arc.","weak":"Rambles or ends before agreeing a concrete change."}},"modelAnswer":{"en":"Stop right there, that's not what I see. You're not failing at sales, you're stalling in one spot: the proposal. Your discovery is strong; people trust you. But you send decks and wait. That's a skill, not a verdict on you. So this week: on every deal at proposal, don't email it, walk them through it live and ask what would stop them signing. Three calls, and we review them Friday. I'm betting on you, and I don't bet on people I'm writing off.","de":"Halt, das ist nicht, was ich sehe. Sie scheitern nicht am Verkaufen, Sie stocken an einer Stelle: dem Angebot. Ihre Discovery ist stark; man vertraut Ihnen. Aber Sie schicken Decks und warten. Das ist eine Faehigkeit, kein Urteil ueber Sie. Diese Woche also: Bei jedem Deal im Angebot mailen Sie es nicht, gehen es live durch und fragen, was sie vom Unterschreiben abhaelt. Nur das, drei Gespraeche, und wir sehen sie Freitag an. Ich setze auf Sie, und nicht auf Leute, die ich abschreibe.","es-ES":"Para ahi, eso no es lo que veo. No fracasas en ventas, te atascas en un punto: la propuesta. Tu descubrimiento es solido; la gente confia en ti. Pero envias presentaciones y esperas. Eso es una habilidad, no un veredicto sobre ti. Esta semana: en cada acuerdo en propuesta, no lo mandes, repasalo en directo y pregunta que les impediria firmar. Tres llamadas, y las revisamos el viernes. Apuesto por ti, y no apuesto por gente a la que doy por perdida."}},
  {"id":"COM-9","type":"feedback360","category":"feedback_difficult_conversations","department":"commercial","difficulty":4,"media":{"scene":"office_1on1","alt":{"en":"A manager holds a 360 report while a top performer sits with arms crossed.","de":"Ein Manager haelt einen 360-Bericht, waehrend ein Top-Performer mit verschraenkten Armen sitzt.","es-ES":"Un gerente sostiene un informe 360 mientras un crack se sienta con los brazos cruzados."}},"roleCaption":{"en":"You are giving 360 feedback to your top closer.","de":"Sie geben Ihrem besten Abschliesser 360-Feedback.","es-ES":"Estas dando feedback 360 a tu mejor cerrador."},"scenario":{"en":"Your highest-revenue rep just smashed quota again, but the 360 results are brutal: peers call her abrasive, marketing dreads working with her, and two juniors asked to move off her pod. She's expecting praise. Deliver the feedback: honour the results, but make the behaviour impact land, and hold the line without losing her or starting a war.","de":"Ihre umsatzstaerkste Mitarbeiterin hat erneut das Ziel pulverisiert, aber die 360-Ergebnisse sind brutal: Kollegen nennen sie schroff, das Marketing fuerchtet die Zusammenarbeit, und zwei Junioren baten um Wechsel aus ihrem Pod. Sie erwartet Lob. Geben Sie das Feedback: wuerdigen Sie die Ergebnisse, aber bringen Sie die Verhaltenswirkung an, und halten Sie die Linie, ohne sie zu verlieren oder einen Krieg zu beginnen.","es-ES":"Tu comercial de mayor facturacion ha vuelto a pulverizar la cuota, pero los resultados del 360 son duros: los companeros la llaman aspera, marketing teme trabajar con ella y dos juniors pidieron salir de su pod. Espera elogios. Da el feedback: honra los resultados, pero haz que el impacto de su conducta cale, y manten la linea sin perderla ni iniciar una guerra."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Genuinely honour the revenue results first.","de":"Wuerdigen Sie zuerst aufrichtig die Umsatzergebnisse.","es-ES":"Honra primero de verdad los resultados de ingresos."},{"en":"Deliver the behavioural feedback with specific, sourced examples.","de":"Geben Sie das Verhaltensfeedback mit konkreten, belegten Beispielen.","es-ES":"Da el feedback de conducta con ejemplos concretos y respaldados."},{"en":"Connect the behaviour to a business cost she cares about.","de":"Verknuepfen Sie das Verhalten mit Geschaeftskosten, die ihr wichtig sind.","es-ES":"Conecta la conducta con un coste de negocio que le importe."},{"en":"Hold the standard without diminishing her value.","de":"Halten Sie den Standard, ohne ihren Wert zu schmaelern.","es-ES":"Manten el estandar sin minimizar su valor."},{"en":"Stay calm and firm if she pushes back hard.","de":"Bleiben Sie ruhig und fest, wenn sie heftig kontert.","es-ES":"Manten la calma y firmeza si responde con dureza."}],"rubric":{"content":{"strong":"Honours results, delivers sourced behavioural examples, ties them to a real business cost, and holds the standard without diminishing her.","adequate":"Raises the behaviour but with vague examples or without a clear business link or standard.","weak":"Either only praises and softens the message, or attacks her with no balance or path."},"delivery":{"strong":"Calm, respectful, and unwavering; firm under pushback without becoming combative or appeasing.","adequate":"Mostly composed but wavers, softens, or hardens under tension.","weak":"Rattled, hostile, or caving; loses the line under her reaction."},"time":{"strong":"Honours, delivers, and holds the line within the window.","adequate":"Slightly over or under but covers the arc.","weak":"Rambles or stops before the feedback lands."}},"modelAnswer":{"en":"Let's be clear: your numbers are exceptional, and I value what you bring. That's exactly why I won't soften this. The 360 came back hard. Peers find you abrasive, marketing avoids your launches, two juniors asked off your pod. These are patterns, not one bad day. The cost: deals you could scale, you can't, because nobody wants to build around you. I'm not asking you to dial down your drive, but to win without burning the people you need. Let's pick one relationship to repair this month.","de":"Klar gesagt: Ihre Zahlen sind aussergewoehnlich, und ich schaetze, was Sie einbringen. Genau deshalb beschoenige ich nichts. Das 360 fiel hart aus. Kollegen finden Sie schroff, das Marketing meidet Ihre Launches, zwei Junioren baten um Wechsel. Das sind Muster, kein schlechter Tag. Der Preis: Deals, die Sie skalieren koennten, koennen Sie nicht, weil niemand um Sie herum bauen will. Ich bitte nicht, Ihren Antrieb zu drosseln, sondern zu gewinnen, ohne die Menschen zu verbrennen, die Sie brauchen. Waehlen wir diesen Monat eine Beziehung zum Reparieren, ich helfe.","es-ES":"Seamos claros: tus numeros son excepcionales y valoro lo que aportas. Por eso mismo no voy a suavizarlo. El 360 vino duro. Los companeros te ven aspera, marketing evita tus lanzamientos, dos juniors pidieron salir de tu pod. Son patrones, no un mal dia. El coste: acuerdos que podrias escalar, no puedes, porque nadie quiere construir a tu alrededor. No te pido bajar tu empuje, sino ganar sin quemar a quienes necesitas. Elijamos una relacion para reparar este mes, y te ayudo."}},
  {"id":"HR-4","type":"situational","category":"feedback_difficult_conversations","department":"people","difficulty":4,"media":{"scene":"office_1on1","alt":{"en":"A manager and an employee facing each other across a small table in a private room, blinds drawn.","de":"Eine Führungskraft und ein Mitarbeiter sitzen sich an einem kleinen Tisch in einem privaten Raum gegenüber, die Jalousien sind geschlossen.","es-ES":"Un responsable y un empleado sentados frente a frente en una mesa pequeña en una sala privada, con las persianas bajadas."}},"roleCaption":{"en":"You are the HR business partner delivering a layoff.","de":"Sie sind der HR-Business-Partner und überbringen eine Kündigung.","es-ES":"Eres el socio de RR. HH. que comunica un despido."},"scenario":{"en":"Budget cuts mean you must let Sam go after eight loyal years. The role is being eliminated, the decision is final, and Sam has no idea it is coming. Sam has just sat down across from you and asked, 'So, what's this about?' Deliver the news clearly and humanely.","de":"Budgetkürzungen zwingen Sie, Sam nach acht treuen Jahren zu entlassen. Die Stelle wird gestrichen, die Entscheidung ist endgültig, und Sam ahnt nichts. Sam hat sich gerade Ihnen gegenüber gesetzt und gefragt: 'Also, worum geht es?' Überbringen Sie die Nachricht klar und menschlich.","es-ES":"Los recortes presupuestarios te obligan a despedir a Sam tras ocho años de lealtad. El puesto se elimina, la decisión es definitiva y Sam no lo ve venir. Sam acaba de sentarse frente a ti y pregunta: '¿De qué se trata?'. Comunica la noticia con claridad y humanidad."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"State the decision plainly within the first 20 seconds.","de":"Nennen Sie die Entscheidung klar innerhalb der ersten 20 Sekunden.","es-ES":"Comunica la decisión con claridad en los primeros 20 segundos."},{"en":"Make clear the role, not the person, was eliminated.","de":"Machen Sie deutlich, dass die Stelle, nicht die Person, gestrichen wurde.","es-ES":"Deja claro que se elimina el puesto, no a la persona."},{"en":"Acknowledge the emotional weight without over-apologising.","de":"Erkennen Sie die emotionale Last an, ohne sich zu übertrieben zu entschuldigen.","es-ES":"Reconoce el peso emocional sin disculparte en exceso."},{"en":"Outline concrete next steps: severance, support, timeline.","de":"Skizzieren Sie konkrete nächste Schritte: Abfindung, Unterstützung, Zeitplan.","es-ES":"Detalla los próximos pasos: indemnización, apoyo, plazos."},{"en":"Preserve Sam's dignity and offer a genuine reference.","de":"Wahren Sie Sams Würde und bieten Sie eine ehrliche Referenz an.","es-ES":"Preserva la dignidad de Sam y ofrece una referencia sincera."}],"rubric":{"content":{"strong":"Delivers the decision early and unambiguously, frames it as role elimination, and covers severance, support, and timeline.","adequate":"Conveys the decision and some next steps but buries the news or omits practical details.","weak":"Hedges, blames vaguely, or never states clearly that Sam is being let go."},"delivery":{"strong":"Calm, warm, steady pace; holds composure while showing genuine empathy.","adequate":"Mostly composed but occasionally rushed or stilted.","weak":"Cold, flustered, or rambling; tone undermines the message."},"time":{"strong":"Lands the key message and next steps within 60 seconds.","adequate":"Covers the essentials but runs slightly long or short.","weak":"Wanders well past time or cuts off before next steps."}},"modelAnswer":{"en":"Sam, I have hard news and I want to be straight with you. Due to budget cuts, your role is being eliminated, and today is your last day in it. This is about the position, not your work, which has been excellent for eight years. I'm sorry. Here's what happens next: you'll receive severance, three months of outplacement support, and a strong reference from me. Take your time. What questions can I answer right now?","de":"Sam, ich habe eine schwere Nachricht und will ehrlich sein. Wegen Budgetkürzungen wird Ihre Stelle gestrichen, und heute ist Ihr letzter Tag darin. Es geht um die Position, nicht um Ihre Arbeit, die acht Jahre lang hervorragend war. Es tut mir leid. Was nun folgt: Sie erhalten eine Abfindung, drei Monate Outplacement-Unterstützung und eine starke Referenz von mir. Lassen Sie sich Zeit. Welche Fragen kann ich jetzt beantworten?","es-ES":"Sam, tengo una noticia difícil y quiero ser sincero contigo. Por recortes presupuestarios, tu puesto se elimina y hoy es tu último día en él. Es por la posición, no por tu trabajo, que ha sido excelente durante ocho años. Lo siento. Lo que sigue: recibirás una indemnización, tres meses de apoyo de recolocación y una referencia firme de mi parte. Tómate tu tiempo. ¿Qué dudas puedo resolverte ahora?"}},
  {"id":"HR-5","type":"conflict","category":"conflict_resolution","department":"people","difficulty":4,"media":{"scene":"exec_committee","alt":{"en":"Two senior executives leaning forward at a conference table, visibly tense, others watching.","de":"Zwei leitende Führungskräfte lehnen sich am Konferenztisch vor, sichtlich angespannt, andere schauen zu.","es-ES":"Dos altos directivos inclinados hacia delante en una mesa de reuniones, visiblemente tensos, mientras otros observan."}},"roleCaption":{"en":"You are the CHRO mediating two warring VPs.","de":"Sie sind der CHRO und vermitteln zwischen zwei zerstrittenen VPs.","es-ES":"Eres el director de RR. HH. mediando entre dos vicepresidentes enfrentados."},"scenario":{"en":"Your VP of Sales and VP of Product have openly clashed for months, and it spilled into today's exec meeting as raised voices and a walkout threat. Both are watching you. Step in to de-escalate, name the dynamic, and set a path forward without taking sides.","de":"Ihr VP Sales und Ihr VP Product streiten seit Monaten offen, und heute eskalierte es im Leitungsmeeting mit lauten Stimmen und einer Drohung, das Meeting zu verlassen. Beide schauen Sie an. Greifen Sie ein, deeskalieren Sie, benennen Sie die Dynamik und zeigen Sie einen Weg nach vorn, ohne Partei zu ergreifen.","es-ES":"Tu vicepresidente de Ventas y tu vicepresidente de Producto llevan meses chocando abiertamente, y hoy estalló en la reunión ejecutiva con voces alzadas y la amenaza de abandonar la sala. Ambos te miran. Interviene para desescalar, nombra la dinámica y traza un camino sin tomar partido."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Interrupt the spiral and reset the tone immediately.","de":"Unterbrechen Sie die Eskalation und setzen Sie den Ton sofort zurück.","es-ES":"Interrumpe la espiral y restablece el tono de inmediato."},{"en":"Name the conflict without assigning blame to either side.","de":"Benennen Sie den Konflikt, ohne einer Seite die Schuld zu geben.","es-ES":"Nombra el conflicto sin culpar a ninguna de las partes."},{"en":"Reframe around the shared goal both VPs serve.","de":"Richten Sie den Fokus auf das gemeinsame Ziel beider VPs.","es-ES":"Reorienta hacia el objetivo común que ambos persiguen."},{"en":"Propose a concrete, time-boxed next step offline.","de":"Schlagen Sie einen konkreten, zeitlich begrenzten nächsten Schritt abseits des Meetings vor.","es-ES":"Propón un próximo paso concreto y acotado fuera de la reunión."},{"en":"Protect the room's psychological safety for everyone present.","de":"Schützen Sie die psychologische Sicherheit aller Anwesenden im Raum.","es-ES":"Protege la seguridad psicológica de todos los presentes."}],"rubric":{"content":{"strong":"De-escalates, names the dynamic neutrally, anchors on shared goals, and sets a concrete offline next step.","adequate":"Calms the room and gestures at a path forward but leans toward one side or stays vague.","weak":"Takes sides, lectures, or fails to offer any way forward."},"delivery":{"strong":"Authoritative yet calm; measured pace that lowers the temperature.","adequate":"Mostly steady but occasionally tentative or sharp.","weak":"Anxious, combative, or weak; fails to command the room."},"time":{"strong":"Resets the room and sets next steps within 60 seconds.","adequate":"Gets there but drifts slightly over or under.","weak":"Rambles past time or stops before resolving anything."}},"modelAnswer":{"en":"Let's pause right here. I'm going to stop us, because this matters too much to settle in raised voices. You two are the best in your fields, and you're both fighting for the same outcome: a product that sells and a sales motion that's deliverable. That tension is healthy; this format isn't. So here's what we'll do: you and I, three of us, tomorrow at nine, one hour, to map the real trade-offs. For now, we move on. Agreed?","de":"Lassen Sie uns hier innehalten. Ich stoppe uns, weil das zu wichtig ist, um es mit lauten Stimmen zu klären. Sie beide sind die Besten in Ihren Bereichen und kämpfen für dasselbe Ziel: ein Produkt, das sich verkauft, und ein Vertrieb, der lieferbar ist. Diese Spannung ist gesund; dieses Format nicht. Also: Sie beide und ich, morgen um neun, eine Stunde, um die echten Kompromisse zu klären. Jetzt machen wir weiter. Einverstanden?","es-ES":"Hagamos una pausa aquí. Voy a frenarnos, porque esto importa demasiado para resolverlo a gritos. Sois los mejores en lo vuestro y ambos lucháis por lo mismo: un producto que se vende y una venta que se puede cumplir. Esa tensión es sana; este formato no. Así que: vosotros dos y yo, mañana a las nueve, una hora, para trazar las verdaderas concesiones. Por ahora, seguimos. ¿De acuerdo?"}},
  {"id":"HR-6","type":"feedback360","category":"self_awareness_development","department":"people","difficulty":3,"media":{"scene":"feedback_report","alt":{"en":"An open 360 feedback report on a desk, charts and anonymous comments visible.","de":"Ein offener 360-Grad-Feedbackbericht auf einem Schreibtisch, Diagramme und anonyme Kommentare sichtbar.","es-ES":"Un informe de feedback 360 abierto sobre un escritorio, con gráficos y comentarios anónimos visibles."}},"roleCaption":{"en":"You receive harsh 360 feedback on your listening.","de":"Sie erhalten hartes 360-Grad-Feedback zu Ihrem Zuhören.","es-ES":"Recibes un feedback 360 duro sobre tu escucha."},"scenario":{"en":"Your 360 results are in, and the theme is blunt: your team finds you dismissive and quick to interrupt, even though peers rate you highly. Your coach asks you to respond out loud to the feedback right now: what you make of it and what you'll do. Show real self-awareness, not defensiveness.","de":"Ihre 360-Grad-Ergebnisse sind da, und die Botschaft ist deutlich: Ihr Team empfindet Sie als abweisend und unterbrechungsfreudig, obwohl Kollegen Sie hoch bewerten. Ihr Coach bittet Sie, jetzt laut auf das Feedback zu reagieren: was Sie davon halten und was Sie tun werden. Zeigen Sie echte Selbstreflexion, keine Abwehr.","es-ES":"Tienes los resultados de tu 360 y el mensaje es claro: tu equipo te ve desdeñoso y propenso a interrumpir, aunque tus pares te valoran mucho. Tu coach te pide que respondas en voz alta al feedback ahora mismo: qué opinas y qué harás. Muestra autoconciencia real, sin ponerte a la defensiva."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Accept the feedback without minimising or excusing it.","de":"Nehmen Sie das Feedback an, ohne es zu beschönigen oder zu entschuldigen.","es-ES":"Acepta el feedback sin minimizarlo ni excusarlo."},{"en":"Reflect honestly on why the gap with your team exists.","de":"Reflektieren Sie ehrlich, warum die Lücke zu Ihrem Team besteht.","es-ES":"Reflexiona con honestidad sobre por qué existe esa brecha con tu equipo."},{"en":"Resist defending yourself with the positive peer ratings.","de":"Verteidigen Sie sich nicht mit den positiven Kollegenbewertungen.","es-ES":"No te defiendas con las valoraciones positivas de tus pares."},{"en":"Commit to one or two specific, observable changes.","de":"Verpflichten Sie sich zu ein oder zwei konkreten, beobachtbaren Änderungen.","es-ES":"Comprométete con uno o dos cambios concretos y observables."},{"en":"Invite the team to hold you accountable going forward.","de":"Laden Sie das Team ein, Sie künftig zur Rechenschaft zu ziehen.","es-ES":"Invita al equipo a pedirte cuentas en adelante."}],"rubric":{"content":{"strong":"Owns the feedback, reflects on the root cause, and commits to specific changes with accountability.","adequate":"Accepts the feedback but stays general or offers vague intentions.","weak":"Deflects, rationalises with peer praise, or denies the pattern."},"delivery":{"strong":"Open, grounded, non-defensive tone; sounds genuinely reflective.","adequate":"Mostly sincere but with flashes of defensiveness or detachment.","weak":"Defensive, dismissive, or performative."},"time":{"strong":"Reflection and commitment land within 60 seconds.","adequate":"Covers it but runs slightly over or under.","weak":"Drifts well past time or ends abruptly without commitment."}},"modelAnswer":{"en":"Honestly, this stings, and it should. My team is telling me they don't feel heard, and that's on me, not them. The peer scores don't cancel that out; if anything, they show I save my best listening for the wrong people. I think I interrupt because I'm impatient to solve. So two changes: I'll wait three seconds before responding, and I'll ask one follow-up question before I weigh in. And I'm asking the team to call me out when I slip.","de":"Ehrlich, das trifft mich, und das soll es auch. Mein Team sagt, es fühlt sich nicht gehört, und das liegt an mir, nicht an ihnen. Die Kollegenbewertungen heben das nicht auf; sie zeigen eher, dass ich mein bestes Zuhören für die Falschen aufspare. Ich unterbreche wohl, weil ich ungeduldig lösen will. Also zwei Änderungen: Ich warte drei Sekunden vor einer Antwort und stelle eine Nachfrage, bevor ich mich einbringe. Und ich bitte das Team, mich zu ermahnen, wenn ich rückfällig werde.","es-ES":"Sinceramente, esto duele, y debe doler. Mi equipo me dice que no se siente escuchado, y eso es responsabilidad mía, no suya. Las valoraciones de mis pares no lo compensan; más bien muestran que reservo mi mejor escucha para quien no toca. Creo que interrumpo por impaciencia por resolver. Así que dos cambios: esperaré tres segundos antes de responder y haré una pregunta de seguimiento antes de opinar. Y pido al equipo que me lo señale cuando recaiga."}},
  {"id":"HR-7","type":"coaching","category":"leadership_decisions","department":"people","difficulty":3,"media":{"scene":"coaching_room","alt":{"en":"Two people in armchairs in a quiet coaching room, notebooks resting on knees.","de":"Zwei Personen in Sesseln in einem ruhigen Coaching-Raum, Notizbücher auf den Knien.","es-ES":"Dos personas en sillones en una sala de coaching tranquila, con cuadernos sobre las rodillas."}},"roleCaption":{"en":"You coach a manager who plays favourites.","de":"Sie coachen eine Führungskraft, die Lieblinge bevorzugt.","es-ES":"Asesoras a un responsable que tiene favoritos."},"scenario":{"en":"You're coaching Dana, a talented manager whose team has quietly flagged that she favours two people for the best projects and visibility. Dana hasn't noticed and sees herself as scrupulously fair. Open the conversation: raise the pattern without crushing her, and help her see it for herself.","de":"Sie coachen Dana, eine talentierte Führungskraft, deren Team leise gemeldet hat, dass sie zwei Personen für die besten Projekte und Sichtbarkeit bevorzugt. Dana hat es nicht bemerkt und hält sich für absolut fair. Eröffnen Sie das Gespräch: sprechen Sie das Muster an, ohne sie zu zerstören, und helfen Sie ihr, es selbst zu erkennen.","es-ES":"Asesoras a Dana, una responsable con talento cuyo equipo ha señalado discretamente que favorece a dos personas con los mejores proyectos y visibilidad. Dana no se ha dado cuenta y se considera escrupulosamente justa. Abre la conversación: plantea el patrón sin hundirla y ayúdala a verlo por sí misma."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Open with curiosity and a question, not an accusation.","de":"Beginnen Sie mit Neugier und einer Frage, nicht mit einer Anschuldigung.","es-ES":"Empieza con curiosidad y una pregunta, no con una acusación."},{"en":"Surface the pattern with specific, observable evidence.","de":"Belegen Sie das Muster mit konkreten, beobachtbaren Hinweisen.","es-ES":"Saca el patrón a la luz con evidencia concreta y observable."},{"en":"Affirm her intent while separating it from her impact.","de":"Bestätigen Sie ihre Absicht und trennen Sie sie von ihrer Wirkung.","es-ES":"Reconoce su intención y sepárala de su impacto."},{"en":"Guide her to reach the insight rather than telling her.","de":"Führen Sie sie zur Einsicht, statt sie ihr zu sagen.","es-ES":"Guíala a la conclusión en vez de decírsela."},{"en":"End with a small experiment she can own.","de":"Schließen Sie mit einem kleinen Experiment, das sie selbst gestaltet.","es-ES":"Termina con un pequeño experimento que ella pueda asumir."}],"rubric":{"content":{"strong":"Raises the pattern with evidence, separates intent from impact, and guides Dana to her own insight and an experiment.","adequate":"Names the issue but tells rather than guides, or skips the experiment.","weak":"Accuses, lectures, or softens so much the message is lost."},"delivery":{"strong":"Warm, curious, non-judgemental; uses questions and pauses well.","adequate":"Supportive but occasionally leading or flat.","weak":"Blunt, anxious, or patronising."},"time":{"strong":"Opens the topic and a path forward within 60 seconds.","adequate":"Gets there but slightly over or under time.","weak":"Rambles or stalls before opening the real issue."}},"modelAnswer":{"en":"Dana, can I share something to think about together? When I look at the last quarter's project assignments, the marquee work has gone to the same two people most times. I know fairness matters deeply to you, so I'm curious how you'd read that pattern. What do you notice? Often it's not favouritism, it's trust we build with whoever's nearest. Here's an experiment: next two big projects, sketch who'd grow most from them first, then decide. Want to try that?","de":"Dana, darf ich etwas mit Ihnen zum Nachdenken teilen? Wenn ich die Projektvergaben des letzten Quartals ansehe, ging die Vorzeigearbeit meist an dieselben zwei Personen. Ich weiß, dass Ihnen Fairness sehr wichtig ist, daher bin ich neugierig, wie Sie dieses Muster lesen. Was fällt Ihnen auf? Oft ist es kein Bevorzugen, sondern Vertrauen zu denen, die am nächsten sind. Ein Experiment: Skizzieren Sie bei den nächsten zwei Projekten zuerst, wer am meisten wachsen würde, dann entscheiden Sie. Wollen wir das probieren?","es-ES":"Dana, ¿puedo compartir algo para pensarlo juntos? Mirando las asignaciones del último trimestre, el trabajo más visible ha ido casi siempre a las mismas dos personas. Sé que la justicia te importa mucho, así que me intriga cómo lees ese patrón. ¿Qué observas? A menudo no es favoritismo, es la confianza que construimos con quien tenemos más cerca. Un experimento: en los próximos dos proyectos grandes, esboza primero quién crecería más y luego decide. ¿Lo probamos?"}},
  {"id":"HR-8","type":"situational","category":"professional_communication","department":"people","difficulty":3,"media":{"scene":"boardroom","alt":{"en":"A packed town hall room with employees standing, arms crossed, facing a presenter.","de":"Ein voller Townhall-Raum mit stehenden Mitarbeitern, verschränkten Armen, vor einem Vortragenden.","es-ES":"Una sala de asamblea abarrotada con empleados de pie, brazos cruzados, frente a un ponente."}},"roleCaption":{"en":"You face a return-to-office town hall revolt.","de":"Sie stehen einer Townhall-Revolte gegen die Büropflicht gegenüber.","es-ES":"Te enfrentas a una revuelta en la asamblea por la vuelta a la oficina."},"scenario":{"en":"Leadership has mandated three days a week back in the office. At the all-hands, the mood is hostile: people feel their trust and flexibility are being taken away. You're the People lead at the mic. Address the room: own the decision, hear the frustration, and explain the why without pretending everyone will love it.","de":"Die Führung hat drei Bürotage pro Woche angeordnet. Beim All-Hands ist die Stimmung feindselig: Die Leute fühlen sich um Vertrauen und Flexibilität gebracht. Sie sind die People-Leitung am Mikrofon. Sprechen Sie zum Raum: stehen Sie zur Entscheidung, hören Sie den Frust, und erklären Sie das Warum, ohne so zu tun, als würde es allen gefallen.","es-ES":"La dirección ha impuesto tres días a la semana en la oficina. En la reunión general, el ambiente es hostil: la gente siente que le quitan confianza y flexibilidad. Eres el responsable de Personas en el micrófono. Dirígete a la sala: asume la decisión, escucha la frustración y explica el porqué sin fingir que a todos les encantará."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Acknowledge the frustration honestly and specifically.","de":"Erkennen Sie den Frust ehrlich und konkret an.","es-ES":"Reconoce la frustración con honestidad y concreción."},{"en":"Own the decision instead of hiding behind leadership.","de":"Stehen Sie zur Entscheidung, statt sich hinter der Führung zu verstecken.","es-ES":"Asume la decisión en vez de esconderte tras la dirección."},{"en":"Explain the genuine reasoning behind the change.","de":"Erklären Sie die echten Gründe für die Änderung.","es-ES":"Explica el razonamiento real detrás del cambio."},{"en":"Be honest that not everyone will agree, and that's okay.","de":"Seien Sie ehrlich, dass nicht alle zustimmen werden, und das ist in Ordnung.","es-ES":"Sé honesto en que no todos estarán de acuerdo, y eso está bien."},{"en":"Offer a real channel for input on the rollout.","de":"Bieten Sie einen echten Kanal für Input zur Umsetzung an.","es-ES":"Ofrece un canal real para aportar sobre la implementación."}],"rubric":{"content":{"strong":"Validates the frustration, owns the call, gives honest reasoning, and opens a real input channel.","adequate":"Covers most points but leans on spin or skips the input channel.","weak":"Dismisses the room, hides behind 'leadership decided', or over-promises."},"delivery":{"strong":"Steady, candid, and present; holds the room without defensiveness.","adequate":"Mostly composed but occasionally scripted or defensive.","weak":"Evasive, nervous, or tone-deaf to the mood."},"time":{"strong":"Acknowledges, explains, and opens a path within 60 seconds.","adequate":"Gets there but runs slightly long or short.","weak":"Rambles past time or cuts off before the why."}},"modelAnswer":{"en":"I hear the anger in this room, and I'm not going to talk you out of it. This is a real change, and for many of you it costs commute time and flexibility you'd earned. I own this decision with leadership; it isn't something happening to us from elsewhere. The reasoning is collaboration and onboarding, where we've genuinely lost ground. Some of you will still disagree, and that's fair. What I can do is open a working group on how we phase this in. Bring me the friction points.","de":"Ich höre die Wut in diesem Raum, und ich werde sie Ihnen nicht ausreden. Das ist eine echte Veränderung, und viele von Ihnen kostet sie Pendelzeit und Flexibilität, die Sie sich verdient hatten. Ich stehe mit der Führung zu dieser Entscheidung; sie passiert uns nicht von außen. Der Grund ist Zusammenarbeit und Einarbeitung, wo wir echt an Boden verloren haben. Einige werden weiter anderer Meinung sein, das ist fair. Ich kann eine Arbeitsgruppe zur Umsetzung öffnen. Bringen Sie mir die Reibungspunkte.","es-ES":"Oigo el enfado en esta sala y no voy a intentar quitároslo. Es un cambio real y a muchos os cuesta tiempo de trayecto y flexibilidad que os habíais ganado. Asumo esta decisión junto a la dirección; no es algo que nos venga de fuera. El motivo es la colaboración y la incorporación, donde hemos perdido terreno de verdad. Algunos seguiréis sin estar de acuerdo, y es legítimo. Lo que puedo hacer es abrir un grupo de trabajo sobre cómo implantarlo. Traedme los puntos de fricción."}},
  {"id":"HR-9","type":"behavioral","category":"feedback_difficult_conversations","department":"people","difficulty":2,"media":{"scene":"video_call","alt":{"en":"A one-on-one video call, two faces on screen, a performance document shared.","de":"Ein Einzel-Videoanruf, zwei Gesichter auf dem Bildschirm, ein Leistungsdokument geteilt.","es-ES":"Una videollamada individual, dos caras en pantalla, un documento de desempeño compartido."}},"roleCaption":{"en":"You put an underperformer on a PIP.","de":"Sie setzen einen leistungsschwachen Mitarbeiter auf einen PIP.","es-ES":"Pones a un empleado de bajo rendimiento en un plan de mejora."},"scenario":{"en":"Jordan, a likeable team member, has missed targets for two quarters despite feedback. It's time for a formal performance improvement plan. On this call you must be clear that this is serious, while keeping it constructive and giving Jordan a genuine path to succeed. Open the conversation.","de":"Jordan, ein sympathisches Teammitglied, hat trotz Feedback zwei Quartale lang die Ziele verfehlt. Es ist Zeit für einen formellen Leistungsverbesserungsplan. In diesem Gespräch müssen Sie klarmachen, dass dies ernst ist, und es dennoch konstruktiv halten und Jordan einen echten Weg zum Erfolg geben. Eröffnen Sie das Gespräch.","es-ES":"Jordan, un miembro del equipo que cae bien, ha incumplido objetivos durante dos trimestres pese al feedback. Es hora de un plan formal de mejora del desempeño. En esta llamada debes dejar claro que es serio, manteniéndolo constructivo y dando a Jordan un camino real para tener éxito. Abre la conversación."},"weights":{"content":0.45,"delivery":0.35,"time":0.2},"keyPoints":[{"en":"Be unambiguous that this is a formal, serious step.","de":"Machen Sie unmissverständlich klar, dass dies ein formeller, ernster Schritt ist.","es-ES":"Deja inequívocamente claro que es un paso formal y serio."},{"en":"Ground it in specific, factual performance gaps.","de":"Begründen Sie es mit konkreten, sachlichen Leistungslücken.","es-ES":"Fundaméntalo en brechas de desempeño concretas y objetivas."},{"en":"Make clear the goal is Jordan's success, not exit.","de":"Machen Sie klar, dass das Ziel Jordans Erfolg ist, nicht der Ausstieg.","es-ES":"Deja claro que el objetivo es el éxito de Jordan, no su salida."},{"en":"Define concrete targets, support, and a timeline.","de":"Definieren Sie konkrete Ziele, Unterstützung und einen Zeitplan.","es-ES":"Define objetivos concretos, apoyo y un plazo."},{"en":"Invite Jordan's perspective and questions.","de":"Laden Sie Jordans Sichtweise und Fragen ein.","es-ES":"Invita la perspectiva y las preguntas de Jordan."}],"rubric":{"content":{"strong":"Names the PIP clearly, cites specific gaps, frames it as a path to succeed, and sets targets, support, and timeline.","adequate":"Conveys seriousness and some structure but stays vague on gaps or support.","weak":"Softens so much the seriousness is lost, or omits the path forward."},"delivery":{"strong":"Direct yet supportive; calm, clear, and respectful.","adequate":"Mostly clear but occasionally hedging or stiff.","weak":"Either harsh or so gentle the message doesn't land."},"time":{"strong":"States the plan and path within 60 seconds.","adequate":"Covers it but slightly over or under time.","weak":"Drifts past time or ends before defining the path."}},"modelAnswer":{"en":"Jordan, I want to be direct with you because you deserve clarity. We're starting a formal performance improvement plan today. Over the last two quarters you've missed your targets, even after the feedback we discussed, and that's serious. But I want to be just as clear: the goal here is for you to succeed, not to manage you out. The plan sets specific targets over 60 days, with weekly check-ins and coaching from me. I'd really like to hear how this lands for you and what support would help.","de":"Jordan, ich möchte direkt mit Ihnen sein, weil Sie Klarheit verdienen. Wir starten heute einen formellen Leistungsverbesserungsplan. In den letzten zwei Quartalen haben Sie Ihre Ziele verfehlt, auch nach dem besprochenen Feedback, und das ist ernst. Aber genauso klar: Ziel ist Ihr Erfolg, nicht Ihr Hinausdrängen. Der Plan setzt konkrete Ziele über 60 Tage, mit wöchentlichen Gesprächen und Coaching von mir. Ich möchte wirklich hören, wie das bei Ihnen ankommt und welche Unterstützung helfen würde.","es-ES":"Jordan, quiero ser directo contigo porque mereces claridad. Hoy iniciamos un plan formal de mejora del desempeño. En los dos últimos trimestres has incumplido tus objetivos, incluso tras el feedback que hablamos, y eso es serio. Pero quiero ser igual de claro: el objetivo es que tengas éxito, no apartarte. El plan fija objetivos concretos a 60 días, con seguimientos semanales y acompañamiento mío. Me gustaría mucho oír cómo lo recibes y qué apoyo te ayudaría."}},
  {"id":"OPS-4","type":"situational","category":"leadership_decisions","department":"operations","difficulty":3,"media":{"scene":"office_1on1","alt":{"en":"Operations leader at a monitoring screen showing a halted production line.","de":"Betriebsleiter vor einem Monitor, der eine gestoppte Produktionslinie zeigt.","es-ES":"Responsable de operaciones ante una pantalla que muestra una linea de produccion detenida."}},"roleCaption":{"en":"You are the plant operations lead. Line 3 just went down mid-shift.","de":"Sie sind der Betriebsleiter des Werks. Linie 3 ist mitten in der Schicht ausgefallen.","es-ES":"Eres el responsable de operaciones de la planta. La linea 3 acaba de pararse a mitad de turno."},"scenario":{"en":"Line 3 stopped twenty minutes ago and your largest customer's order ships tonight. The shift supervisor, maintenance lead, and a worried operator are all looking at you for the next move. Take 60 seconds to direct the room: what gets diagnosed first, who does what, and how you'll protect the shipment without cutting corners on safety.","de":"Linie 3 steht seit zwanzig Minuten still und die Bestellung Ihres groessten Kunden geht heute Abend raus. Schichtleiter, Wartungsleiter und ein besorgter Bediener schauen auf Sie. Nehmen Sie sich 60 Sekunden, um den Raum zu fuehren: Was wird zuerst diagnostiziert, wer macht was, und wie schuetzen Sie die Lieferung, ohne bei der Sicherheit Abstriche zu machen.","es-ES":"La linea 3 lleva veinte minutos parada y el pedido de tu mayor cliente sale esta noche. El supervisor de turno, el jefe de mantenimiento y un operario preocupado te miran esperando el siguiente paso. Tienes 60 segundos para dirigir la sala: que se diagnostica primero, quien hace que y como protegeras el envio sin saltarte la seguridad."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Confirm everyone is safe and the line is in a safe state before anything else.","de":"Bestaetigen Sie zuerst, dass alle sicher sind und die Linie in einem sicheren Zustand ist.","es-ES":"Confirma que todos estan a salvo y que la linea esta en estado seguro antes de nada."},{"en":"Assign clear ownership: maintenance diagnoses, supervisor tracks the clock.","de":"Klare Verantwortung zuweisen: Wartung diagnostiziert, Schichtleiter behaelt die Zeit im Blick.","es-ES":"Asigna responsabilidades claras: mantenimiento diagnostica, el supervisor controla el reloj."},{"en":"Set a decision point: if not running in X minutes, trigger the backup plan.","de":"Einen Entscheidungspunkt setzen: laeuft sie in X Minuten nicht, Notfallplan ausloesen.","es-ES":"Fija un punto de decision: si no arranca en X minutos, activa el plan alternativo."},{"en":"Identify how the shipment can still be met or how to communicate a slip early.","de":"Klaeren, wie die Lieferung erreicht oder eine Verzoegerung frueh kommuniziert wird.","es-ES":"Determina como cumplir el envio o como comunicar pronto un retraso."},{"en":"Stay calm and visible so the team stays focused, not panicked.","de":"Ruhig und praesent bleiben, damit das Team fokussiert und nicht panisch bleibt.","es-ES":"Manten la calma y la presencia para que el equipo siga enfocado y sin panico."}],"rubric":{"content":{"strong":"Leads with safety, assigns clear owners, sets a concrete decision deadline, and has a credible plan to protect or escalate the shipment.","adequate":"Covers diagnosis and the shipment but leaves ownership or the decision point vague.","weak":"Reacts emotionally, skips safety, or gives no structure for who does what next."},"delivery":{"strong":"Calm, authoritative, and clear under pressure; pacing reassures the team.","adequate":"Mostly steady with some hesitation or rushed moments.","weak":"Anxious or scattered tone that would amplify the room's stress."},"time":{"strong":"Lands the full direction within 55-65 seconds.","adequate":"Slightly over or under, omitting one minor element.","weak":"Rambles past time or finishes far too early without substance."}},"modelAnswer":{"en":"First, is everyone safe and the line locked out? Good. Priya, you and maintenance start diagnosis now on the most likely cause. Marcus, you own the clock and the customer's deadline. If we're not running in twenty minutes, we shift the order to Line 2 and I call the customer myself with a realistic time. No shortcuts on safety, ever. Keep me updated every five minutes. We've handled worse than this calmly, and we will again.","de":"Zuerst: Sind alle sicher und ist die Linie gesichert? Gut. Priya, du und die Wartung beginnt jetzt mit der Diagnose der wahrscheinlichsten Ursache. Marcus, du verantwortest die Zeit und die Kundenfrist. Laeuft sie in zwanzig Minuten nicht, verlagern wir auf Linie 2 und ich rufe den Kunden selbst an. Keine Abstriche bei der Sicherheit. Update alle fuenf Minuten. Wir haben Schlimmeres ruhig gemeistert.","es-ES":"Primero, esta todo el mundo a salvo y la linea bloqueada? Bien. Priya, tu y mantenimiento empezad ya el diagnostico de la causa mas probable. Marcus, tu controlas el reloj y el plazo del cliente. Si no arranca en veinte minutos, pasamos el pedido a la linea 2 y llamo yo al cliente con un tiempo realista. Sin atajos en seguridad. Informadme cada cinco minutos. Hemos superado cosas peores con calma."}},
  {"id":"OPS-5","type":"conflict","category":"conflict_resolution","department":"operations","difficulty":4,"media":{"scene":"exec_committee","alt":{"en":"Two VPs facing off across a table while a product roadmap is projected behind them.","de":"Zwei VPs gegenueber am Tisch, dahinter eine projizierte Produkt-Roadmap.","es-ES":"Dos VPs enfrentados en una mesa con una hoja de ruta de producto proyectada detras."}},"roleCaption":{"en":"You are Head of Product. Two VPs want opposite roadmap priorities.","de":"Sie sind Produktleiter. Zwei VPs wollen entgegengesetzte Roadmap-Prioritaeten.","es-ES":"Eres el director de producto. Dos VPs quieren prioridades de hoja de ruta opuestas."},"scenario":{"en":"In the exec committee, the VP of Sales demands the enterprise SSO feature next quarter, while the VP of Engineering insists the platform rewrite must come first or everything slows down. Both have valid points and both are watching you. Take 60 seconds to acknowledge both, name the real trade-off, and propose a path forward without simply siding with one.","de":"Im Exec-Komitee fordert der Vertriebs-VP das Enterprise-SSO-Feature naechstes Quartal, waehrend der Engineering-VP darauf besteht, dass der Plattform-Umbau zuerst kommt, sonst wird alles langsamer. Beide haben recht, beide schauen auf Sie. Nehmen Sie sich 60 Sekunden, beide anzuerkennen, den echten Zielkonflikt zu benennen und einen Weg vorzuschlagen, ohne sich einfach auf eine Seite zu schlagen.","es-ES":"En el comite ejecutivo, el VP de Ventas exige la funcion de SSO empresarial el proximo trimestre, mientras el VP de Ingenieria insiste en que la reescritura de la plataforma debe ir primero o todo se ralentiza. Ambos tienen razon y ambos te miran. Tienes 60 segundos para reconocer a los dos, nombrar el verdadero compromiso y proponer un camino sin ponerte simplemente del lado de uno."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Validate both VPs' concerns as legitimate, not political.","de":"Die Anliegen beider VPs als legitim anerkennen, nicht als politisch.","es-ES":"Valida las preocupaciones de ambos VPs como legitimas, no politicas."},{"en":"Name the real trade-off in terms of customer and business impact.","de":"Den echten Zielkonflikt anhand von Kunden- und Geschaeftsauswirkung benennen.","es-ES":"Nombra el verdadero compromiso en terminos de impacto en cliente y negocio."},{"en":"Anchor the decision in shared goals or data, not opinion.","de":"Die Entscheidung an gemeinsamen Zielen oder Daten verankern, nicht an Meinung.","es-ES":"Ancla la decision en objetivos compartidos o datos, no en opiniones."},{"en":"Propose a concrete sequence or a test that de-risks the call.","de":"Eine konkrete Reihenfolge oder einen Test vorschlagen, der die Entscheidung entrisikt.","es-ES":"Propon una secuencia concreta o una prueba que reduzca el riesgo de la decision."},{"en":"Keep ownership of the roadmap decision rather than deferring it.","de":"Die Roadmap-Entscheidung selbst verantworten, statt sie zu vertagen.","es-ES":"Asume la decision de la hoja de ruta en lugar de aplazarla."}],"rubric":{"content":{"strong":"Acknowledges both sides fairly, frames the trade-off in business terms, and offers a clear, data-anchored path that owns the decision.","adequate":"Addresses both views but the proposed path is vague or leans on one side without justification.","weak":"Picks a side reflexively, dodges the decision, or fails to name the actual trade-off."},"delivery":{"strong":"Even-handed, confident, and diplomatic; de-escalates tension in the room.","adequate":"Generally balanced but slightly tentative or one-sided in tone.","weak":"Sounds defensive, dismissive of one VP, or visibly uncomfortable."},"time":{"strong":"Delivers a complete resolution within 55-65 seconds.","adequate":"Close to time but drops one key element.","weak":"Runs long or ends abruptly without a real proposal."}},"modelAnswer":{"en":"Both of you are right, and that's the hard part. Sarah, SSO is blocking real enterprise deals this quarter. Tom, without the rewrite, every feature after it gets slower and riskier. Here's what I propose: we scope a thin SSO slice on the current platform to unblock the top three deals, then commit the rest of the quarter to the rewrite. Let's pull the actual deal pipeline and engineering estimates by Friday so we decide on numbers, not volume. I'll own that call.","de":"Ihr habt beide recht, das ist das Schwierige. Sarah, SSO blockiert dieses Quartal echte Enterprise-Deals. Tom, ohne Umbau wird jedes spaetere Feature langsamer und riskanter. Mein Vorschlag: Wir definieren ein schlankes SSO-Stueck auf der aktuellen Plattform fuer die drei groessten Deals und widmen den Rest des Quartals dem Umbau. Bis Freitag ziehen wir Pipeline und Schaetzungen, damit wir nach Zahlen entscheiden. Diese Entscheidung verantworte ich.","es-ES":"Los dos teneis razon, y eso es lo dificil. Sarah, el SSO esta bloqueando contratos empresariales reales este trimestre. Tom, sin la reescritura, cada funcion posterior sera mas lenta y arriesgada. Propongo esto: definimos una porcion minima de SSO sobre la plataforma actual para desbloquear los tres contratos principales y dedicamos el resto del trimestre a la reescritura. Saquemos el pipeline real y las estimaciones para el viernes y decidimos con numeros. Esa decision la asumo yo."}},
  {"id":"OPS-6","type":"feedback360","category":"feedback_difficult_conversations","department":"operations","difficulty":3,"media":{"scene":"feedback_report","alt":{"en":"A 360 feedback report open on a laptop with highlighted comments about communication.","de":"Ein 360-Grad-Feedback-Bericht auf einem Laptop mit hervorgehobenen Kommentaren zur Kommunikation.","es-ES":"Un informe de feedback 360 abierto en un portatil con comentarios destacados sobre comunicacion."}},"roleCaption":{"en":"Your 360 review says your team feels left out of operational decisions.","de":"Ihr 360-Feedback sagt, Ihr Team fuehlt sich aus operativen Entscheidungen ausgeschlossen.","es-ES":"Tu evaluacion 360 dice que tu equipo se siente excluido de las decisiones operativas."},"scenario":{"en":"Your 360 feedback as operations director is mostly positive, but a clear theme emerges: peers and reports say you make fast operational calls alone and they only hear about them after the fact, leaving them flat-footed. Your manager asks how you read this and what you'll change. Take 60 seconds to respond with genuine ownership, not defensiveness.","de":"Ihr 360-Feedback als Betriebsdirektor ist ueberwiegend positiv, doch ein klares Muster zeigt sich: Kollegen und Mitarbeiter sagen, Sie treffen schnelle operative Entscheidungen allein und sie erfahren erst hinterher davon. Ihr Manager fragt, wie Sie das einschaetzen und was Sie aendern. Nehmen Sie sich 60 Sekunden fuer eine Antwort mit echter Verantwortung, ohne Abwehr.","es-ES":"Tu feedback 360 como director de operaciones es mayormente positivo, pero surge un tema claro: companeros y colaboradores dicen que tomas decisiones operativas rapidas en solitario y solo se enteran despues, dejandolos descolocados. Tu jefe te pregunta como lo interpretas y que cambiaras. Tienes 60 segundos para responder asumiendolo de verdad, sin ponerte a la defensiva."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Acknowledge the feedback openly without minimizing or excusing it.","de":"Das Feedback offen anerkennen, ohne es kleinzureden oder zu entschuldigen.","es-ES":"Reconoce el feedback abiertamente sin minimizarlo ni excusarlo."},{"en":"Show you understand the impact on the team, not just the intent behind your speed.","de":"Zeigen, dass Sie die Auswirkung auf das Team verstehen, nicht nur die gute Absicht.","es-ES":"Demuestra que entiendes el impacto en el equipo, no solo tu buena intencion."},{"en":"Name one or two concrete behavior changes you will make.","de":"Ein bis zwei konkrete Verhaltensaenderungen benennen.","es-ES":"Nombra uno o dos cambios concretos de comportamiento que haras."},{"en":"Preserve the value of fast decisions while inviting earlier input.","de":"Den Wert schneller Entscheidungen wahren und frueheren Input einladen.","es-ES":"Conserva el valor de las decisiones rapidas invitando a aportar antes."},{"en":"Commit to checking back so the change is verifiable.","de":"Zusagen, nachzufassen, damit die Veraenderung ueberpruefbar ist.","es-ES":"Comprometete a hacer seguimiento para que el cambio sea verificable."}],"rubric":{"content":{"strong":"Owns the pattern, articulates its impact, and names specific, realistic changes plus a way to verify them.","adequate":"Accepts the feedback but offers only general intentions to improve.","weak":"Defends past behavior, blames the pace of operations, or dismisses the theme."},"delivery":{"strong":"Open, humble, and grounded; sounds like real reflection, not a script.","adequate":"Sincere but a little guarded or rehearsed.","weak":"Defensive, dismissive, or flat tone that undercuts the ownership."},"time":{"strong":"Reflective response complete within 55-65 seconds.","adequate":"Slightly off time, missing one element.","weak":"Trails on or wraps up before addressing the change."}},"modelAnswer":{"en":"Honestly, this one landed, and I think it's fair. I move fast because I want to unblock people, but I can see I've been deciding alone and announcing late, which leaves the team flat-footed. That's on me. Going forward I'll add a quick decision brief before I act on anything cross-team, and I'll keep a short async channel for early input. The speed stays, but the team comes along. I'll check back with them in a month to see if it's actually landing.","de":"Ehrlich gesagt hat mich das getroffen, und es ist fair. Ich entscheide schnell, um Leute zu entlasten, aber ich sehe, dass ich allein entscheide und zu spaet informiere, was das Team ueberrumpelt. Das liegt an mir. Kuenftig mache ich vor teamuebergreifenden Entscheidungen ein kurzes Briefing und halte einen Async-Kanal fuer fruehen Input offen. Das Tempo bleibt, aber das Team kommt mit. In einem Monat frage ich nach, ob es wirkt.","es-ES":"Sinceramente, esto me ha calado y me parece justo. Voy rapido porque quiero desbloquear a la gente, pero veo que decido en solitario y aviso tarde, lo que deja al equipo descolocado. Es cosa mia. A partir de ahora hare un breve resumen de decision antes de actuar en algo entre equipos y mantendre un canal asincrono para aportaciones tempranas. La velocidad se queda, pero el equipo viene conmigo. En un mes les preguntare si de verdad funciona."}},
  {"id":"OPS-7","type":"coaching","category":"self_awareness_development","department":"operations","difficulty":2,"media":{"scene":"coaching_room","alt":{"en":"A manager and a junior product manager seated for a one-on-one coaching session.","de":"Eine Fuehrungskraft und ein Junior-Produktmanager sitzen in einem Coaching-Gespraech.","es-ES":"Un manager y un jefe de producto junior sentados en una sesion de coaching individual."}},"roleCaption":{"en":"You coach a PM who keeps overpromising delivery dates to stakeholders.","de":"Sie coachen einen PM, der Stakeholdern staendig Liefertermine zu optimistisch zusagt.","es-ES":"Asesoras a un PM que sigue prometiendo fechas de entrega poco realistas a los stakeholders."},"scenario":{"en":"You manage Alex, a talented but eager product manager who keeps committing to delivery dates the team can't hit, then scrambling to explain slips. Stakeholders are starting to lose trust. Alex sits down for your coaching one-on-one. Take 60 seconds to help Alex see the pattern and build a healthier way to commit, without crushing their drive.","de":"Sie fuehren Alex, einen talentierten, aber uebereifrigen Produktmanager, der Liefertermine zusagt, die das Team nicht haelt, und dann Verzoegerungen erklaeren muss. Stakeholder verlieren das Vertrauen. Alex setzt sich zu Ihrem Coaching-Gespraech. Nehmen Sie sich 60 Sekunden, Alex das Muster zu zeigen und einen gesuenderen Umgang mit Zusagen aufzubauen, ohne den Elan zu bremsen.","es-ES":"Diriges a Alex, un jefe de producto con talento pero impaciente que se compromete con fechas que el equipo no cumple y luego corre a justificar los retrasos. Los stakeholders empiezan a perder confianza. Alex se sienta en tu sesion de coaching. Tienes 60 segundos para ayudar a Alex a ver el patron y construir una forma mas sana de comprometerse, sin aplastar su empuje."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Open with what Alex is doing well so the drive isn't discouraged.","de":"Mit Alex' Staerken beginnen, damit der Elan nicht entmutigt wird.","es-ES":"Empieza con lo que Alex hace bien para no desanimar su empuje."},{"en":"Use specifics to surface the overpromising pattern without blaming.","de":"Mit konkreten Beispielen das Muster aufzeigen, ohne Schuldzuweisung.","es-ES":"Usa ejemplos concretos para mostrar el patron sin culpabilizar."},{"en":"Connect the behavior to its cost: eroded stakeholder trust.","de":"Das Verhalten mit seinen Kosten verbinden: schwindendes Vertrauen.","es-ES":"Conecta el comportamiento con su coste: la confianza erosionada."},{"en":"Offer a concrete tool, like buffers or confidence ranges on estimates.","de":"Ein konkretes Werkzeug anbieten, etwa Puffer oder Konfidenzbereiche.","es-ES":"Ofrece una herramienta concreta, como margenes o rangos de confianza."},{"en":"Ask a question that lets Alex own the next step.","de":"Eine Frage stellen, die Alex den naechsten Schritt selbst besitzen laesst.","es-ES":"Haz una pregunta que permita a Alex apropiarse del siguiente paso."}],"rubric":{"content":{"strong":"Affirms strengths, names the pattern with specifics, links it to trust, and equips Alex with a practical tool plus ownership.","adequate":"Identifies the issue and gives advice but is light on either affirmation or a concrete tool.","weak":"Lectures, scolds, or only tells Alex to 'be more realistic' without a path."},"delivery":{"strong":"Warm, direct, and supportive; coaching tone that builds confidence.","adequate":"Caring but slightly preachy or hesitant in places.","weak":"Harsh, vague, or patronizing tone that would demotivate."},"time":{"strong":"Full coaching arc within 55-65 seconds.","adequate":"Near time but skips affirmation or the question.","weak":"Overruns or ends before offering a way forward."}},"modelAnswer":{"en":"Alex, your energy and how hard you push for stakeholders is genuinely a strength. I want to protect that. But I've noticed a pattern: the last three launches, you committed dates before the team estimated, and then we slipped. Each slip chips away at how much people trust your word. So let's try this: commit to ranges, not single dates, and build in the team's buffer before you promise anything. What's one upcoming commitment we could re-baseline that way together this week?","de":"Alex, deine Energie und dein Einsatz fuer Stakeholder sind wirklich eine Staerke. Die will ich schuetzen. Aber ich sehe ein Muster: Bei den letzten drei Launches hast du Termine zugesagt, bevor das Team geschaetzt hat, und dann kam die Verzoegerung. Jede Verzoegerung nagt am Vertrauen in dein Wort. Versuchen wir das: Sag Bereiche zu statt einzelner Termine und baue den Teampuffer ein. Welche anstehende Zusage koennen wir diese Woche gemeinsam neu aufsetzen?","es-ES":"Alex, tu energia y lo mucho que peleas por los stakeholders son una verdadera virtud. Quiero protegerla. Pero he notado un patron: en los ultimos tres lanzamientos comprometiste fechas antes de que el equipo estimara, y luego nos retrasamos. Cada retraso desgasta la confianza en tu palabra. Probemos esto: comprometete con rangos, no fechas unicas, e incluye el margen del equipo antes de prometer. Que compromiso proximo podriamos rehacer asi juntos esta semana?"}},
  {"id":"OPS-8","type":"behavioral","category":"strategic_thinking","department":"operations","difficulty":3,"media":{"scene":"client_meeting","alt":{"en":"Product manager presenting to a tense customer about a quality escalation.","de":"Produktmanager praesentiert einem angespannten Kunden zu einer Qualitaetseskalation.","es-ES":"Jefe de producto presentando a un cliente tenso sobre una escalada de calidad."}},"roleCaption":{"en":"Tell the story of a time you decided to kill a beloved feature.","de":"Erzaehlen Sie, wie Sie einmal ein beliebtes Feature eingestellt haben.","es-ES":"Cuenta una vez que decidiste eliminar una funcion muy querida."},"scenario":{"en":"In an interview for a senior operations role, you're asked: 'Tell me about a time you had to kill a product or feature that people loved, because it was the right call for the business.' Take 60 seconds to tell that story: the situation, why you decided to cut it, how you handled the backlash, and what the outcome taught you.","de":"In einem Interview fuer eine Senior-Operations-Rolle werden Sie gefragt: 'Erzaehlen Sie von einer Situation, in der Sie ein beliebtes Produkt oder Feature einstellen mussten, weil es die richtige Entscheidung fuers Geschaeft war.' Nehmen Sie sich 60 Sekunden: die Situation, warum Sie es gestrichen haben, wie Sie mit dem Widerstand umgingen und was das Ergebnis Sie lehrte.","es-ES":"En una entrevista para un puesto senior de operaciones, te preguntan: 'Cuentame una vez que tuviste que eliminar un producto o funcion que la gente adoraba, porque era lo correcto para el negocio.' Tienes 60 segundos para contar esa historia: la situacion, por que decidiste cortarla, como gestionaste el rechazo y que te enseno el resultado."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Set up the situation and why the feature was beloved.","de":"Die Situation darstellen und warum das Feature beliebt war.","es-ES":"Plantea la situacion y por que la funcion era tan querida."},{"en":"Explain the data or strategic reason that justified killing it.","de":"Den datenbasierten oder strategischen Grund fuer die Einstellung erklaeren.","es-ES":"Explica el motivo estrategico o de datos que justifico eliminarla."},{"en":"Describe how you communicated it to users and the team.","de":"Beschreiben, wie Sie es Nutzern und Team kommuniziert haben.","es-ES":"Describe como lo comunicaste a usuarios y al equipo."},{"en":"Show how you handled emotion and pushback with empathy plus resolve.","de":"Zeigen, wie Sie Emotionen und Widerstand mit Empathie und Entschlossenheit begegneten.","es-ES":"Muestra como gestionaste la emocion y el rechazo con empatia y firmeza."},{"en":"Close with a measurable outcome and the lesson learned.","de":"Mit einem messbaren Ergebnis und der Lektion abschliessen.","es-ES":"Cierra con un resultado medible y la leccion aprendida."}],"rubric":{"content":{"strong":"Clear STAR arc: situation, data-driven rationale, empathetic communication, and a concrete outcome with a real lesson.","adequate":"Tells a coherent story but is thin on rationale, outcome, or lesson.","weak":"Vague, lacks a real decision, or shows no reflection on impact."},"delivery":{"strong":"Confident, structured storytelling with authentic emotion at the hard moment.","adequate":"Reasonable narrative flow with some flat or rushed stretches.","weak":"Disorganized or detached delivery that loses the listener."},"time":{"strong":"Complete story within 55-65 seconds.","adequate":"Slightly over or under, dropping one part of the arc.","weak":"Rambles past time or ends without a resolution."}},"modelAnswer":{"en":"We had a custom-reports feature a vocal group of power users adored. But the data was brutal: it served four percent of accounts and consumed nearly a third of our maintenance load, blocking the roadmap. I made the call to sunset it. I told the team straight, then personally emailed our top advocates with a migration path and a ninety-day runway. There was real anger, and I sat with it rather than deflecting. Six months later velocity was up forty percent and churn was flat. The lesson: love isn't the same as value, and honesty buys you grace.","de":"Wir hatten ein Custom-Reports-Feature, das eine lautstarke Gruppe von Power-Usern liebte. Doch die Daten waren brutal: vier Prozent der Accounts, fast ein Drittel unserer Wartungslast, die die Roadmap blockierte. Ich entschied, es einzustellen. Ich sagte es dem Team klar und schrieb dann unseren wichtigsten Fuersprechern persoenlich mit Migrationspfad und neunzig Tagen Frist. Es gab echten Aerger, den ich aushielt statt abzuwehren. Sechs Monate spaeter war die Velocity vierzig Prozent hoeher, die Abwanderung stabil. Die Lektion: Liebe ist nicht gleich Wert, und Ehrlichkeit schafft Nachsicht.","es-ES":"Teniamos una funcion de informes personalizados que un grupo ruidoso de usuarios avanzados adoraba. Pero los datos eran brutales: servia al cuatro por ciento de las cuentas y consumia casi un tercio de nuestra carga de mantenimiento, bloqueando la hoja de ruta. Decidi retirarla. Se lo dije al equipo sin rodeos y luego escribi personalmente a nuestros principales defensores con un plan de migracion y noventa dias de margen. Hubo enfado real y lo sostuve en vez de esquivarlo. Seis meses despues la velocidad subio un cuarenta por ciento y la fuga se mantuvo estable. La leccion: amar algo no es lo mismo que su valor, y la honestidad te compra indulgencia."}},
  {"id":"OPS-9","type":"situational","category":"professional_communication","department":"operations","difficulty":4,"media":{"scene":"video_call","alt":{"en":"Product lead on a video call with the sales team delivering hard news.","de":"Produktleiter in einem Videocall mit dem Vertriebsteam, der schlechte Nachrichten ueberbringt.","es-ES":"Responsable de producto en una videollamada con el equipo de ventas dando malas noticias."}},"roleCaption":{"en":"Tell the sales team the launch must slip again, the second time.","de":"Sagen Sie dem Vertrieb, dass der Launch erneut verschoben wird, zum zweiten Mal.","es-ES":"Dile al equipo de ventas que el lanzamiento se retrasa otra vez, por segunda vez."},"scenario":{"en":"You're on a video call with the whole sales team. The launch they've already sold to customers and slipped once must slip another three weeks after a critical defect surfaced in final testing. They are frustrated and have deals riding on the original date. Take 60 seconds to deliver the news straight, own it, and give them something they can actually take back to customers.","de":"Sie sind in einem Videocall mit dem gesamten Vertriebsteam. Der Launch, den sie Kunden bereits verkauft und einmal verschoben haben, muss nach einem kritischen Fehler im Schlusstest erneut um drei Wochen verschoben werden. Sie sind frustriert und haben Deals am urspruenglichen Termin haengen. Nehmen Sie sich 60 Sekunden, die Nachricht klar zu ueberbringen, dazu zu stehen und ihnen etwas mitzugeben, das sie wirklich beim Kunden nutzen koennen.","es-ES":"Estas en una videollamada con todo el equipo de ventas. El lanzamiento que ya han vendido a clientes y que retrasaron una vez debe aplazarse otras tres semanas tras detectarse un defecto critico en las pruebas finales. Estan frustrados y tienen contratos atados a la fecha original. Tienes 60 segundos para dar la noticia con claridad, asumirla y darles algo que de verdad puedan llevar a sus clientes."},"weights":{"content":0.5,"delivery":0.3,"time":0.2},"keyPoints":[{"en":"Deliver the news clearly and early, without burying it.","de":"Die Nachricht klar und frueh ueberbringen, ohne sie zu verstecken.","es-ES":"Da la noticia con claridad y al principio, sin esconderla."},{"en":"Take ownership instead of hiding behind 'engineering' or process.","de":"Verantwortung uebernehmen, statt sich hinter 'Engineering' zu verstecken.","es-ES":"Asume la responsabilidad en vez de esconderte tras 'ingenieria'."},{"en":"Give the real reason briefly so the date is credible, not arbitrary.","de":"Den echten Grund kurz nennen, damit der Termin glaubwuerdig wirkt.","es-ES":"Da brevemente el motivo real para que la fecha sea creible, no arbitraria."},{"en":"Hand them a concrete message and any support for affected deals.","de":"Ihnen eine konkrete Botschaft und Unterstuetzung fuer betroffene Deals geben.","es-ES":"Dales un mensaje concreto y apoyo para los contratos afectados."},{"en":"Reset trust by committing to the new date with confidence.","de":"Vertrauen wiederherstellen, indem Sie den neuen Termin selbstbewusst zusagen.","es-ES":"Recupera la confianza comprometiendote con la nueva fecha con seguridad."}],"rubric":{"content":{"strong":"States the slip up front, owns it, gives a credible reason, hands sales a usable customer message, and commits firmly to the new date.","adequate":"Delivers the news and a reason but is light on ownership or what sales can use.","weak":"Buries the news, deflects blame, or leaves sales with nothing to say to customers."},"delivery":{"strong":"Direct, composed, and respectful; absorbs frustration without defensiveness.","adequate":"Mostly steady but occasionally apologetic or evasive.","weak":"Defensive, over-apologetic, or rattled tone that worsens trust."},"time":{"strong":"Complete, confident message within 55-65 seconds.","adequate":"Near time but omits the customer message or commitment.","weak":"Drags on or cuts off before giving sales a path."}},"modelAnswer":{"en":"I'll be straight with you: the launch is slipping three more weeks, to the twenty-eighth. I know you've sold this date and slipped once already, and that's on me to make right. Final testing found a defect that would corrupt customer data, so shipping on time would have hurt them worse. Here's your message: a brief, firm delay for a quality fix, with early access for our key accounts the moment it's stable. I'll join any at-risk customer call myself. The twenty-eighth is real, and I'm committing to it.","de":"Ich bin ehrlich mit euch: Der Launch verschiebt sich um drei weitere Wochen, auf den Achtundzwanzigsten. Ich weiss, ihr habt diesen Termin verkauft und schon einmal verschoben, und das wieder geradezuruecken liegt bei mir. Der Schlusstest fand einen Fehler, der Kundendaten beschaedigt haette. Eure Botschaft: eine kurze, klare Verzoegerung fuer eine Qualitaetskorrektur, mit fruehem Zugang fuer Schluesselkunden, sobald es stabil ist. Bei gefaehrdeten Kunden bin ich selbst im Call. Der Achtundzwanzigste steht, und dazu stehe ich.","es-ES":"Sere directo: el lanzamiento se retrasa tres semanas mas, al veintiocho. Se que habeis vendido esta fecha y ya la retrasamos una vez, y arreglarlo es cosa mia. Las pruebas finales encontraron un defecto que corromperia datos de los clientes, asi que lanzar a tiempo les habria perjudicado mas. Vuestro mensaje: un retraso breve y firme por una correccion de calidad, con acceso anticipado para las cuentas clave en cuanto sea estable. Me unire yo mismo a cualquier llamada con clientes en riesgo. El veintiocho es real y me comprometo a el."}},
  {"id":"CS-4","type":"situational","category":"professional_communication","department":"customer","difficulty":3,"media":{"scene":"video_call","alt":{"en":"A live video call with a frustrated enterprise customer whose onboarding has stalled.","de":"Ein Live-Videoanruf mit einem frustrierten Enterprise-Kunden, dessen Onboarding ins Stocken geraten ist.","es-ES":"Una videollamada en directo con un cliente empresarial frustrado cuyo onboarding se ha estancado."}},"roleCaption":{"en":"You are the Customer Success Manager owning the account.","de":"Du bist der Customer-Success-Manager, der das Konto betreut.","es-ES":"Eres el Customer Success Manager responsable de la cuenta."},"scenario":{"en":"Your biggest new account is six weeks into onboarding and still not live. Two integration deadlines have slipped, their team is losing patience, and the VP just joined the call asking why. In 60 seconds, own the situation, explain what went wrong without excuses, and lay out a credible plan to get them live.","de":"Dein größtes Neukunden-Konto ist seit sechs Wochen im Onboarding und immer noch nicht live. Zwei Integrationstermine sind verstrichen, das Team verliert die Geduld, und der VP ist gerade dazugekommen und fragt warum. Übernimm in 60 Sekunden Verantwortung, erkläre ohne Ausreden, was schieflief, und lege einen glaubwürdigen Plan zum Go-live vor.","es-ES":"Tu mayor cuenta nueva lleva seis semanas en onboarding y sigue sin estar operativa. Se han incumplido dos plazos de integración, su equipo pierde la paciencia y el VP acaba de unirse a la llamada preguntando por qué. En 60 segundos, asume la situación, explica qué falló sin excusas y plantea un plan creíble para ponerlos en marcha."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Take clear ownership without blaming the customer or your own team publicly.","de":"Übernimm klar die Verantwortung, ohne den Kunden oder dein eigenes Team öffentlich zu beschuldigen.","es-ES":"Asume la responsabilidad con claridad sin culpar al cliente ni a tu equipo en público."},{"en":"Name the specific root cause of the delay in one honest sentence.","de":"Benenne die konkrete Ursache der Verzögerung in einem ehrlichen Satz.","es-ES":"Nombra la causa raíz concreta del retraso en una frase honesta."},{"en":"Give a dated, sequenced plan with a named owner for each step.","de":"Gib einen datierten, sequenzierten Plan mit einem benannten Verantwortlichen je Schritt.","es-ES":"Ofrece un plan con fechas y secuencia, con un responsable nombrado para cada paso."},{"en":"Commit to a concrete go-live date and a daily check-in until then.","de":"Verpflichte dich zu einem konkreten Go-live-Datum und einem täglichen Check-in bis dahin.","es-ES":"Comprométete a una fecha concreta de puesta en marcha y a un seguimiento diario hasta entonces."},{"en":"Acknowledge the impact on their business and rebuild confidence.","de":"Erkenne die Auswirkungen auf ihr Geschäft an und stelle Vertrauen wieder her.","es-ES":"Reconoce el impacto en su negocio y reconstruye la confianza."}],"rubric":{"content":{"strong":"Owns the delay, names a real root cause, and commits to a dated, sequenced plan with owners and a go-live date.","adequate":"Acknowledges the problem and offers a plan, but the root cause or dates are vague.","weak":"Makes excuses, shifts blame, or offers reassurance with no concrete plan or date."},"delivery":{"strong":"Calm, accountable, and steady under the VP's pressure; tone projects control without defensiveness.","adequate":"Mostly composed but shows some hesitation or over-apologizing.","weak":"Defensive, flustered, or dismissive of the customer's frustration."},"time":{"strong":"Lands the full arc within 55-65 seconds at an even pace.","adequate":"Slightly over or under, or rushes the plan at the end.","weak":"Runs well over or stops far short of using the time."}},"modelAnswer":{"en":"You're right to be frustrated, and this is on us to fix. The core issue was an unmapped data field that broke the integration twice; we should have caught it in the kickoff audit. Here's the plan. Today, our lead engineer Maya rebuilds the mapping. Tomorrow we run a joint test with your team. We go live Thursday. I'll send a daily update every morning until you're live, and I'll personally be on each test. You'll be running by end of week, and I'll make sure it stays that way.","de":"Deine Frustration ist berechtigt, und es liegt an uns, das zu beheben. Der Kern war ein nicht zugeordnetes Datenfeld, das die Integration zweimal brach; das hätten wir im Kickoff-Audit erkennen müssen. Der Plan: Heute baut unsere Lead-Engineerin Maya das Mapping neu. Morgen testen wir gemeinsam mit deinem Team. Donnerstag gehen wir live. Bis dahin schicke ich dir jeden Morgen ein Update und bin bei jedem Test persönlich dabei. Ihr seid bis Ende der Woche produktiv, und ich sorge dafür, dass es so bleibt.","es-ES":"Tienes razón en estar frustrado, y nos corresponde a nosotros arreglarlo. El problema central fue un campo de datos sin mapear que rompió la integración dos veces; deberíamos haberlo detectado en la auditoría de inicio. El plan: hoy, nuestra ingeniera principal Maya rehace el mapeo. Mañana hacemos una prueba conjunta con tu equipo. El jueves salimos en vivo. Te enviaré una actualización cada mañana hasta entonces y estaré en cada prueba. Estaréis operativos a final de semana, y me aseguraré de que siga así."}},
  {"id":"CS-5","type":"conflict","category":"conflict_resolution","department":"customer","difficulty":4,"media":{"scene":"video_call","alt":{"en":"A tense call with a long-time customer reacting angrily to a price increase.","de":"Ein angespanntes Gespräch mit einem langjährigen Kunden, der wütend auf eine Preiserhöhung reagiert.","es-ES":"Una llamada tensa con un cliente de larga data que reacciona con enfado ante una subida de precios."}},"roleCaption":{"en":"You are the Customer Success Manager defending a renewal.","de":"Du bist der Customer-Success-Manager und verteidigst eine Verlängerung.","es-ES":"Eres el Customer Success Manager que defiende una renovación."},"scenario":{"en":"A loyal customer of four years just received a 22% renewal price increase and is on the call, angry and threatening to leave. The increase is real and not negotiable to zero. In 60 seconds, defuse the anger, justify the value honestly, and hold the relationship together without overpromising discounts you can't give.","de":"Ein treuer Kunde seit vier Jahren hat gerade eine Verlängerung mit 22 % Preiserhöhung erhalten und ist wütend im Gespräch und droht zu kündigen. Die Erhöhung ist real und nicht auf null verhandelbar. Entschärfe in 60 Sekunden die Wut, begründe den Wert ehrlich und halte die Beziehung zusammen, ohne Rabatte zu versprechen, die du nicht geben kannst.","es-ES":"Un cliente fiel desde hace cuatro años acaba de recibir una subida del 22% en la renovación y está en la llamada, enfadado y amenazando con marcharse. La subida es real y no negociable hasta cero. En 60 segundos, calma el enfado, justifica el valor con honestidad y mantén la relación sin prometer descuentos que no puedes dar."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Acknowledge their loyalty and the legitimacy of their reaction first.","de":"Erkenne zuerst ihre Treue und die Berechtigung ihrer Reaktion an.","es-ES":"Reconoce primero su lealtad y la legitimidad de su reacción."},{"en":"Be transparent about why the price changed without hiding behind policy.","de":"Sei transparent, warum sich der Preis geändert hat, ohne dich hinter Richtlinien zu verstecken.","es-ES":"Sé transparente sobre por qué cambió el precio sin esconderte tras la política."},{"en":"Re-anchor the conversation on value and outcomes delivered, not just cost.","de":"Lenke das Gespräch zurück auf gelieferten Wert und Ergebnisse, nicht nur auf Kosten.","es-ES":"Reorienta la conversación hacia el valor y los resultados aportados, no solo el coste."},{"en":"Offer a realistic lever (phasing, term, or added value) instead of a deep discount.","de":"Biete einen realistischen Hebel (Staffelung, Laufzeit oder Mehrwert) statt eines tiefen Rabatts.","es-ES":"Ofrece una palanca realista (escalonado, plazo o valor añadido) en lugar de un gran descuento."},{"en":"Keep the door open and propose a concrete next step.","de":"Halte die Tür offen und schlage einen konkreten nächsten Schritt vor.","es-ES":"Mantén la puerta abierta y propón un siguiente paso concreto."}],"rubric":{"content":{"strong":"Validates the customer, explains the increase honestly, re-anchors on value, and offers a realistic lever without false promises.","adequate":"Addresses the concern and value but leans on policy or hints at discounts it cannot confirm.","weak":"Gets defensive, hides behind policy, or caves to demands it cannot honor."},"delivery":{"strong":"Warm but firm; stays calm against anger and signals genuine partnership.","adequate":"Composed but either too soft or slightly rigid under pressure.","weak":"Combative, apologetic to the point of weakness, or robotic."},"time":{"strong":"Complete and unhurried within 55-65 seconds.","adequate":"Slightly off target or compresses the value argument.","weak":"Significantly over or under time."}},"modelAnswer":{"en":"Four years in, you've earned the right to be annoyed, and I'd be too. Let me be straight: the increase reflects the platform investments and the new analytics module you're already using daily. I won't pretend it's nothing. What I can do is phase it over two quarters and lock the rate for three years so you're protected from further jumps. Before you decide anything, let me pull your usage data and show you the return you're actually getting. Can we book thirty minutes Thursday to walk through it together?","de":"Nach vier Jahren hast du jedes Recht, verärgert zu sein, und das wäre ich auch. Ganz ehrlich: Die Erhöhung spiegelt die Plattforminvestitionen und das neue Analytics-Modul wider, das ihr täglich nutzt. Ich tue nicht so, als wäre es nichts. Was ich tun kann: die Erhöhung über zwei Quartale staffeln und den Preis für drei Jahre festschreiben, damit du vor weiteren Sprüngen geschützt bist. Bevor du entscheidest, hole ich deine Nutzungsdaten und zeige dir den realen Mehrwert. Buchen wir Donnerstag dreißig Minuten dafür?","es-ES":"Tras cuatro años, tienes todo el derecho a estar molesto, y yo también lo estaría. Te seré claro: la subida refleja las inversiones en la plataforma y el nuevo módulo de analítica que ya usáis a diario. No voy a fingir que no es nada. Lo que sí puedo hacer es escalonarla en dos trimestres y fijar la tarifa durante tres años para protegerte de nuevas subidas. Antes de que decidas, déjame sacar tus datos de uso y mostrarte el retorno real. ¿Reservamos treinta minutos el jueves para verlo juntos?"}},
  {"id":"CS-6","type":"behavioral","category":"self_awareness_development","department":"customer","difficulty":2,"media":{"scene":"office_1on1","alt":{"en":"A reflective one-on-one where you describe a customer you failed to save.","de":"Ein nachdenkliches Vier-Augen-Gespräch, in dem du einen Kunden beschreibst, den du nicht halten konntest.","es-ES":"Un cara a cara reflexivo en el que describes a un cliente que no lograste retener."}},"roleCaption":{"en":"You are reflecting on a churn you didn't see coming.","de":"Du reflektierst über eine Abwanderung, die du nicht kommen sahst.","es-ES":"Reflexionas sobre una baja que no viste venir."},"scenario":{"en":"In a development conversation with your manager, you're asked to tell the story of a customer who churned on your watch and what you learned. The account looked healthy until it wasn't. In 60 seconds, tell the story honestly, show the signals you missed, and explain what you do differently now.","de":"In einem Entwicklungsgespräch mit deiner Führungskraft sollst du die Geschichte eines Kunden erzählen, der unter deiner Aufsicht abgewandert ist, und was du gelernt hast. Das Konto sah gesund aus, bis es das nicht mehr war. Erzähle die Geschichte in 60 Sekunden ehrlich, zeige die übersehenen Signale und erkläre, was du heute anders machst.","es-ES":"En una conversación de desarrollo con tu responsable, te piden que cuentes la historia de un cliente que se dio de baja bajo tu gestión y qué aprendiste. La cuenta parecía sana hasta que dejó de serlo. En 60 segundos, cuenta la historia con honestidad, muestra las señales que pasaste por alto y explica qué haces distinto ahora."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Set the scene briefly: who the customer was and why it looked healthy.","de":"Skizziere kurz die Situation: wer der Kunde war und warum es gesund aussah.","es-ES":"Plantea brevemente el contexto: quién era el cliente y por qué parecía sano."},{"en":"Identify the early warning signs you missed, without excuses.","de":"Benenne die frühen Warnsignale, die du übersehen hast, ohne Ausreden.","es-ES":"Identifica las señales tempranas que pasaste por alto, sin excusas."},{"en":"Take genuine ownership of your part in the outcome.","de":"Übernimm aufrichtig Verantwortung für deinen Anteil am Ergebnis.","es-ES":"Asume con autenticidad tu parte en el resultado."},{"en":"State the concrete habit or process change you adopted afterward.","de":"Nenne die konkrete Gewohnheits- oder Prozessänderung, die du danach übernommen hast.","es-ES":"Indica el cambio concreto de hábito o proceso que adoptaste después."}],"rubric":{"content":{"strong":"Honest narrative with specific missed signals, real ownership, and a concrete behavior change.","adequate":"Tells the story and a lesson but stays general or softens own responsibility.","weak":"Blames the customer or circumstances and offers no real learning."},"delivery":{"strong":"Reflective and self-aware; vulnerable without being self-flagellating.","adequate":"Sincere but slightly rehearsed or guarded.","weak":"Defensive, glib, or detached from the lesson."},"time":{"strong":"Tells a complete arc in 55-65 seconds.","adequate":"A little over or under, or rushes the lesson.","weak":"Far over or under time."}},"modelAnswer":{"en":"Last year I lost a mid-market account I'd have sworn was safe. Logins were steady, the champion was warm, NPS was a nine. What I missed was that all the activity came from one power user, and when she left, usage quietly fell off a cliff for two months before anyone told me. I'd been watching the headline numbers, not the depth of adoption. Since then I track active-user breadth, not just totals, and I always map a second internal champion in the first ninety days. Single points of failure don't surprise me anymore.","de":"Letztes Jahr verlor ich ein Mid-Market-Konto, das ich für sicher gehalten hätte. Die Logins waren stabil, der Champion herzlich, der NPS eine Neun. Was ich übersah: Die gesamte Aktivität kam von einer Power-Userin, und als sie ging, brach die Nutzung zwei Monate lang still ein, bevor mir jemand etwas sagte. Ich beobachtete die Schlagzeilen-Zahlen, nicht die Tiefe der Adoption. Seitdem verfolge ich die Breite aktiver Nutzer, nicht nur Summen, und kartiere immer einen zweiten internen Champion in den ersten neunzig Tagen. Einzelne Schwachstellen überraschen mich nicht mehr.","es-ES":"El año pasado perdí una cuenta de mercado medio que habría jurado segura. Los inicios de sesión eran constantes, el champion cercano, el NPS un nueve. Lo que pasé por alto: toda la actividad venía de una sola usuaria avanzada, y cuando se marchó, el uso cayó en picado durante dos meses antes de que nadie me avisara. Miraba las cifras de titular, no la profundidad de la adopción. Desde entonces sigo la amplitud de usuarios activos, no solo los totales, y siempre mapeo un segundo champion interno en los primeros noventa días. Los puntos únicos de fallo ya no me sorprenden."}},
  {"id":"CS-7","type":"feedback360","category":"feedback_difficult_conversations","department":"customer","difficulty":3,"media":{"scene":"feedback_report","alt":{"en":"Reviewing 360 feedback about a support agent who over-promises to customers.","de":"Durchsicht von 360-Grad-Feedback über einen Support-Mitarbeiter, der Kunden zu viel verspricht.","es-ES":"Revisando feedback 360 sobre un agente de soporte que promete de más a los clientes."}},"roleCaption":{"en":"You are the team lead delivering 360 feedback to an agent.","de":"Du bist der Teamleiter und gibst einem Mitarbeiter 360-Grad-Feedback.","es-ES":"Eres el responsable del equipo que entrega feedback 360 a un agente."},"scenario":{"en":"Your most enthusiastic support agent gets glowing customer ratings but repeatedly promises features and timelines that don't exist, creating broken expectations the rest of the team must clean up. The 360 feedback makes this clear. In 60 seconds, deliver the feedback so it lands, protects his strengths, and changes the behavior.","de":"Dein engagiertester Support-Mitarbeiter erhält glänzende Kundenbewertungen, verspricht aber wiederholt Funktionen und Termine, die es nicht gibt, und erzeugt gebrochene Erwartungen, die der Rest des Teams ausbügeln muss. Das 360-Grad-Feedback macht das deutlich. Vermittle das Feedback in 60 Sekunden so, dass es ankommt, seine Stärken schützt und das Verhalten ändert.","es-ES":"Tu agente de soporte más entusiasta recibe valoraciones excelentes, pero promete repetidamente funciones y plazos que no existen, generando expectativas incumplidas que el resto del equipo debe resolver. El feedback 360 lo deja claro. En 60 segundos, transmite el feedback de modo que cale, proteja sus fortalezas y cambie la conducta."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Open by genuinely affirming his customer rapport and energy.","de":"Beginne damit, seine Kundenbindung und Energie aufrichtig anzuerkennen.","es-ES":"Empieza reconociendo con sinceridad su conexión con los clientes y su energía."},{"en":"Name the over-promising behavior with a specific, recent example.","de":"Benenne das Überversprechen mit einem konkreten, aktuellen Beispiel.","es-ES":"Nombra la conducta de prometer de más con un ejemplo concreto y reciente."},{"en":"Explain the downstream impact on customers and teammates clearly.","de":"Erkläre die Folgen für Kunden und Kollegen deutlich.","es-ES":"Explica con claridad el impacto posterior en clientes y compañeros."},{"en":"Reframe under-promising as a way to keep customers delighted, not less helpful.","de":"Stelle Zurückhaltung als Weg dar, Kunden zu begeistern, nicht als weniger hilfreich.","es-ES":"Replantea prometer menos como forma de mantener encantados a los clientes, no de ser menos útil."},{"en":"Agree on a clear guardrail and offer support to apply it.","de":"Vereinbart eine klare Leitplanke und biete Unterstützung bei der Umsetzung an.","es-ES":"Acordad una pauta clara y ofrece apoyo para aplicarla."}],"rubric":{"content":{"strong":"Affirms strengths, names the behavior with example and impact, reframes it, and sets a concrete guardrail.","adequate":"Covers strengths and the issue but is light on a specific example or actionable guardrail.","weak":"Either crushes his confidence or is so soft the behavior won't change."},"delivery":{"strong":"Warm, direct, and respectful; balances praise and challenge without mixed signals.","adequate":"Sincere but slightly imbalanced toward praise or criticism.","weak":"Harsh, vague, or evasive."},"time":{"strong":"Delivers the full message in 55-65 seconds.","adequate":"Slightly off or rushes the guardrail.","weak":"Well over or under time."}},"modelAnswer":{"en":"Customers love you, and the 360 shows it: you make people feel heard like nobody else here. That's a real gift. There's one pattern I want to fix with you. Last week you told a customer the bulk-export feature was coming next month; it isn't on the roadmap, and the team had to walk it back. When we promise things we can't deliver, that warmth becomes a letdown. Here's the guardrail: if it's not shipped, we say what we can do today and log the request. Keep the enthusiasm, just anchor it to what's real, and I'll help you script those moments.","de":"Kunden lieben dich, und das 360-Feedback zeigt es: Du gibst Menschen das Gefühl, gehört zu werden, wie niemand sonst hier. Das ist ein echtes Talent. Ein Muster möchte ich mit dir abstellen. Letzte Woche sagtest du einem Kunden, der Bulk-Export komme nächsten Monat; er steht nicht auf der Roadmap, und das Team musste zurückrudern. Wenn wir Unerfüllbares versprechen, wird aus Wärme Enttäuschung. Die Leitplanke: Was nicht ausgeliefert ist, dazu sagen wir, was wir heute tun können, und protokollieren den Wunsch. Behalte die Begeisterung, verankere sie nur im Realen, und ich helfe dir, diese Momente zu formulieren.","es-ES":"Los clientes te adoran, y el 360 lo demuestra: haces que la gente se sienta escuchada como nadie aquí. Es un don de verdad. Hay un patrón que quiero corregir contigo. La semana pasada le dijiste a un cliente que la exportación masiva llegaría el mes que viene; no está en la hoja de ruta y el equipo tuvo que rectificar. Cuando prometemos lo que no podemos dar, esa calidez se vuelve decepción. La pauta: si no está lanzado, decimos qué podemos hacer hoy y registramos la petición. Conserva el entusiasmo, solo ánclalo a lo real, y te ayudaré a guionizar esos momentos."}},
  {"id":"CS-8","type":"coaching","category":"leadership_decisions","department":"customer","difficulty":2,"media":{"scene":"coaching_room","alt":{"en":"A coaching session preparing a CSM to ask a happy customer for a reference.","de":"Eine Coaching-Sitzung, die einen CSM darauf vorbereitet, einen zufriedenen Kunden um eine Referenz zu bitten.","es-ES":"Una sesión de coaching para preparar a un CSM a pedir una referencia a un cliente satisfecho."}},"roleCaption":{"en":"You are coaching a nervous CSM before the ask.","de":"Du coachst einen nervösen CSM vor der Anfrage.","es-ES":"Estás haciendo coaching a un CSM nervioso antes de la petición."},"scenario":{"en":"A junior CSM has a genuinely thrilled customer but is anxious about asking them to be a public reference and case study. She's worried it will feel transactional and damage the relationship. In 60 seconds, coach her on how to make the ask naturally, confidently, and in a way that feels like a compliment, not a favor.","de":"Eine Junior-CSM hat einen wirklich begeisterten Kunden, ist aber nervös, ihn um eine öffentliche Referenz und Fallstudie zu bitten. Sie befürchtet, es wirke transaktional und schade der Beziehung. Coache sie in 60 Sekunden, wie sie die Anfrage natürlich, selbstbewusst und so stellt, dass sie sich wie ein Kompliment anfühlt, nicht wie eine Bitte.","es-ES":"Una CSM junior tiene un cliente realmente encantado, pero le da reparo pedirle que sea referencia pública y caso de estudio. Teme que parezca transaccional y dañe la relación. En 60 segundos, oriéntala para que haga la petición de forma natural, segura y que se sienta como un cumplido, no como un favor."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Reframe the ask as recognizing their success, not requesting a favor.","de":"Stelle die Anfrage als Würdigung ihres Erfolgs dar, nicht als Bitte um einen Gefallen.","es-ES":"Replantea la petición como reconocer su éxito, no como pedir un favor."},{"en":"Give her concrete language to open the conversation.","de":"Gib ihr konkrete Formulierungen, um das Gespräch zu eröffnen.","es-ES":"Dale lenguaje concreto para abrir la conversación."},{"en":"Make it easy by offering options and doing the heavy lifting.","de":"Mach es leicht, indem du Optionen anbietest und die Hauptarbeit übernimmst.","es-ES":"Pónselo fácil ofreciendo opciones y asumiendo el trabajo pesado."},{"en":"Normalize a no so the relationship stays safe either way.","de":"Normalisiere ein Nein, damit die Beziehung in jedem Fall sicher bleibt.","es-ES":"Normaliza un no para que la relación quede a salvo en cualquier caso."}],"rubric":{"content":{"strong":"Reframes the ask, gives concrete wording, makes it low-effort for the customer, and de-risks a no.","adequate":"Encourages her and offers some tips but stays general or skips the easy-out.","weak":"Generic pep talk with no usable language or framing."},"delivery":{"strong":"Encouraging and confident; models the very ease she should feel.","adequate":"Supportive but a bit flat or scripted.","weak":"Vague, anxious, or condescending."},"time":{"strong":"Complete coaching in 55-65 seconds.","adequate":"Slightly off or rushes the closing tip.","weak":"Well over or under time."}},"modelAnswer":{"en":"You've earned this ask, so don't shrink from it. You're not begging a favor; you're telling them their results are good enough to celebrate publicly. Try this: 'You've gotten such strong results that our team would love to feature your story. Would you be open to it?' Then make it effortless. Offer a quick interview where you draft everything and they just approve. Give them options: a logo, a quote, or a full case study, their call. And tell them a no is completely fine. Framed that way, most happy customers feel flattered, not pressured. You've got this.","de":"Du hast dir diese Anfrage verdient, also scheue sie nicht. Du bittest nicht um einen Gefallen; du sagst ihnen, dass ihre Ergebnisse gut genug sind, um sie öffentlich zu feiern. Versuch das: 'Ihr habt so starke Ergebnisse erzielt, dass unser Team eure Geschichte gern vorstellen würde. Wärt ihr offen dafür?' Dann mach es mühelos: ein kurzes Interview, du entwirfst alles, sie genehmigen nur. Gib ihnen Optionen: Logo, Zitat oder volle Fallstudie, ihre Wahl. Und sag, ein Nein ist völlig in Ordnung. So formuliert fühlen sich die meisten zufriedenen Kunden geschmeichelt, nicht gedrängt. Das schaffst du.","es-ES":"Te has ganado esta petición, así que no la rehúyas. No estás pidiendo un favor; les dices que sus resultados son tan buenos que merecen celebrarse en público. Prueba esto: 'Habéis logrado resultados tan sólidos que a nuestro equipo le encantaría destacar vuestra historia. ¿Estaríais abiertos?' Luego hazlo sin esfuerzo: una entrevista rápida donde tú redactas todo y ellos solo aprueban. Dales opciones: un logo, una cita o un caso completo, lo que elijan. Y diles que un no está totalmente bien. Planteado así, la mayoría de clientes felices se sienten halagados, no presionados. Tú puedes."}},
  {"id":"CS-9","type":"situational","category":"strategic_thinking","department":"customer","difficulty":4,"media":{"scene":"video_call","alt":{"en":"A high-stakes P1 outage call with your largest account during a live incident.","de":"Ein kritischer P1-Ausfall-Call mit deinem größten Kunden während eines laufenden Vorfalls.","es-ES":"Una llamada crítica de incidencia P1 con tu mayor cuenta durante una interrupción en directo."}},"roleCaption":{"en":"You are the CSM on a live outage bridge with a key account.","de":"Du bist der CSM in einer Live-Ausfall-Brücke mit einem Schlüsselkunden.","es-ES":"Eres el CSM en un puente de incidencia en vivo con una cuenta clave."},"scenario":{"en":"Your largest account's production is down. It's a P1, engineering is mid-investigation with no ETA yet, and the customer's operations leader has joined the bridge demanding answers while their business bleeds. In 60 seconds, take control of the call, communicate honestly without a fix in hand, and keep the customer confident that this is being handled.","de":"Die Produktion deines größten Kunden ist ausgefallen. Es ist ein P1, Engineering untersucht noch ohne ETA, und der Operations-Leiter des Kunden ist der Brücke beigetreten und fordert Antworten, während das Geschäft Verluste macht. Übernimm in 60 Sekunden die Kontrolle, kommuniziere ehrlich ohne Lösung in der Hand und halte den Kunden zuversichtlich, dass es bearbeitet wird.","es-ES":"La producción de tu mayor cuenta está caída. Es un P1, ingeniería sigue investigando sin ETA, y el responsable de operaciones del cliente se ha unido al puente exigiendo respuestas mientras su negocio sangra. En 60 segundos, toma el control de la llamada, comunica con honestidad sin tener la solución y mantén al cliente confiado en que esto se está gestionando."},"weights":{"content":0.4,"delivery":0.4,"time":0.2},"keyPoints":[{"en":"Take visible command of the call and state who is doing what right now.","de":"Übernimm sichtbar die Leitung und sage, wer gerade was tut.","es-ES":"Toma el mando visible de la llamada e indica quién está haciendo qué ahora mismo."},{"en":"Be honest that there's no fix yet without sounding lost.","de":"Sei ehrlich, dass es noch keine Lösung gibt, ohne ratlos zu wirken.","es-ES":"Sé honesto en que aún no hay solución sin sonar perdido."},{"en":"Commit to a concrete update cadence even before the cause is known.","de":"Verpflichte dich zu einem konkreten Update-Rhythmus, noch bevor die Ursache bekannt ist.","es-ES":"Comprométete a una cadencia concreta de actualizaciones aun antes de conocer la causa."},{"en":"Acknowledge the business impact and offer any available mitigation.","de":"Erkenne die Geschäftsauswirkung an und biete jede mögliche Zwischenlösung an.","es-ES":"Reconoce el impacto en el negocio y ofrece cualquier mitigación disponible."},{"en":"Project calm authority so the customer trusts the response.","de":"Strahle ruhige Autorität aus, damit der Kunde der Reaktion vertraut.","es-ES":"Proyecta autoridad serena para que el cliente confíe en la respuesta."}],"rubric":{"content":{"strong":"Takes command, names current actions and owners, sets an update cadence, addresses impact and mitigation honestly.","adequate":"Communicates status and a next step but is vague on cadence or mitigation.","weak":"Offers false reassurance, speculates on cause, or loses control of the call."},"delivery":{"strong":"Calm, authoritative, and steady; the voice itself reduces panic.","adequate":"Mostly composed but shows strain or over-apologizes.","weak":"Panicked, defensive, or evasive."},"time":{"strong":"Full, controlled message in 55-65 seconds.","adequate":"Slightly off or rushes the cadence commitment.","weak":"Well over or under time."}},"modelAnswer":{"en":"I'm taking point on this call, so here's exactly where we stand. Our senior engineers are on it now, working the most likely cause, and I won't guess at a fix I can't yet confirm. I know your operations are stalled and that's costing you real money; that's why this has our top priority. Here's my commitment: I'll give you a concrete update every fifteen minutes, even if the update is that we're still digging. Meanwhile, let's check whether the failover region can carry your critical workloads. Stay on the bridge with me; we will not go quiet on you.","de":"Ich übernehme die Leitung dieses Calls, also hier der genaue Stand. Unsere Senior-Engineers sind jetzt dran und arbeiten an der wahrscheinlichsten Ursache, und ich rate nicht bei einer Lösung, die ich nicht bestätigen kann. Ich weiß, dein Betrieb steht still und das kostet echtes Geld; deshalb hat das höchste Priorität. Mein Versprechen: Ich gebe dir alle fünfzehn Minuten ein konkretes Update, selbst wenn es heißt, dass wir noch suchen. In der Zwischenzeit prüfen wir, ob die Failover-Region deine kritischen Workloads tragen kann. Bleib mit mir auf der Brücke; wir verstummen nicht.","es-ES":"Yo dirijo esta llamada, así que esta es la situación exacta. Nuestros ingenieros senior están en ello ahora, trabajando la causa más probable, y no voy a especular con una solución que aún no puedo confirmar. Sé que tus operaciones están paradas y que eso cuesta dinero real; por eso esto tiene la máxima prioridad. Mi compromiso: te daré una actualización concreta cada quince minutos, aunque sea para decir que seguimos investigando. Mientras tanto, veamos si la región de failover puede asumir tus cargas críticas. Quédate conmigo en el puente; no nos vamos a quedar callados."}},
  {"id":"LEG-4","type":"situational","category":"professional_communication","department":"legal","difficulty":3,"media":{"scene":"client_meeting","alt":{"en":"A sales lead and account team sit across a conference table, contract printouts and a redline marked up in front of them.","de":"Ein Vertriebsleiter und das Kundenteam sitzen an einem Konferenztisch, Vertragsausdrucke und ein markiertes Redline-Dokument vor sich.","es-ES":"Un responsable de ventas y el equipo de cuenta están en una mesa de reuniones, con impresiones del contrato y un redline marcado delante."}},"roleCaption":{"en":"You tell sales an unlimited-liability clause is a dealbreaker","de":"Sie sagen dem Vertrieb, dass eine Klausel zur unbegrenzten Haftung ein No-Go ist","es-ES":"Le dices a ventas que una cláusula de responsabilidad ilimitada es inaceptable"},"scenario":{"en":"Sales wants to close a major deal this quarter and is pushing you to accept the customer's unlimited-liability clause. You believe it exposes the company to ruinous risk. In the next 60 seconds, explain to the sales lead why this clause is a dealbreaker, and offer a constructive path forward.","de":"Der Vertrieb will diesen Quartalsdeal abschließen und drängt Sie, die Klausel des Kunden zur unbegrenzten Haftung zu akzeptieren. Sie halten sie für ein ruinöses Risiko. Erklären Sie dem Vertriebsleiter in den nächsten 60 Sekunden, warum diese Klausel ein No-Go ist, und bieten Sie einen konstruktiven Weg an.","es-ES":"Ventas quiere cerrar un gran acuerdo este trimestre y te presiona para aceptar la cláusula de responsabilidad ilimitada del cliente. Crees que expone a la empresa a un riesgo ruinoso. En los próximos 60 segundos, explícale al responsable de ventas por qué esta cláusula es inaceptable y ofrece una vía constructiva."},"weights":{"content":0.55,"delivery":0.25,"time":0.2},"keyPoints":[{"en":"State clearly the clause is a non-negotiable dealbreaker as written","de":"Klar sagen, dass die Klausel in dieser Form ein No-Go ist","es-ES":"Decir claramente que la cláusula, tal cual, es inaceptable"},{"en":"Quantify the risk: liability could exceed the deal value many times over","de":"Risiko quantifizieren: Haftung könnte den Dealwert um ein Vielfaches übersteigen","es-ES":"Cuantificar el riesgo: la responsabilidad podría superar el valor del acuerdo muchas veces"},{"en":"Acknowledge the revenue goal and your shared interest in closing","de":"Umsatzziel und gemeinsames Interesse am Abschluss anerkennen","es-ES":"Reconocer el objetivo de ingresos y el interés común en cerrar"},{"en":"Offer a fallback: a liability cap tied to contract value with carve-outs","de":"Alternative anbieten: Haftungsobergrenze am Vertragswert mit Ausnahmen","es-ES":"Ofrecer alternativa: un tope de responsabilidad ligado al valor del contrato con excepciones"},{"en":"Propose a joint call with the customer to negotiate the cap","de":"Gemeinsamen Termin mit dem Kunden zur Verhandlung vorschlagen","es-ES":"Proponer una llamada conjunta con el cliente para negociar el tope"}],"rubric":{"content":{"strong":"Firmly names the dealbreaker, quantifies the exposure, and offers a concrete cap-based fallback plus a path to close.","adequate":"States the clause is unacceptable and gives some rationale, but the alternative or business framing is thin.","weak":"Vague objection or simply refuses without explaining risk or offering any workable alternative."},"delivery":{"strong":"Calm, firm, and collaborative; conveys conviction without antagonizing sales.","adequate":"Generally steady but occasionally defensive or hesitant.","weak":"Combative, apologetic, or wavering in a way that undercuts the position."},"time":{"strong":"Lands the message and the fallback within 55-65 seconds.","adequate":"Slightly rushed or runs long but covers the essentials.","weak":"Far too short to be persuasive or rambles well past time."}},"modelAnswer":{"en":"I hear the pressure to close this quarter, and I want this deal too. But unlimited liability as written is a dealbreaker: one incident could cost us many times the contract's value and threaten the whole company. So I'm not signing it that way. Here's the path: let's propose a cap at twelve months' fees, with carve-outs for IP and confidentiality. I'll join your next call and explain it to their counsel. Most customers accept this. Let's hold firm together.","de":"Ich verstehe den Druck, dieses Quartal abzuschließen, und ich will den Deal auch. Aber unbegrenzte Haftung so wie formuliert ist ein No-Go: Ein Vorfall könnte uns ein Vielfaches des Vertragswerts kosten und die Firma gefährden. So unterschreibe ich das nicht. Der Weg: Wir schlagen eine Obergrenze von zwölf Monatsgebühren vor, mit Ausnahmen für IP und Vertraulichkeit. Ich nehme an Ihrem nächsten Termin teil und erkläre es deren Anwälten. Die meisten Kunden akzeptieren das. Bleiben wir gemeinsam standhaft.","es-ES":"Entiendo la presión por cerrar este trimestre, y yo también quiero este acuerdo. Pero la responsabilidad ilimitada, tal como está, es inaceptable: un incidente podría costarnos muchas veces el valor del contrato y poner en riesgo la empresa. Así no lo firmo. La vía: propongamos un tope de doce meses de tarifas, con excepciones para PI y confidencialidad. Me uniré a tu próxima llamada y se lo explicaré a su abogado. La mayoría de clientes lo aceptan. Mantengámonos firmes juntos."}},
  {"id":"LEG-5","type":"behavioral","category":"leadership_decisions","department":"legal","difficulty":4,"media":{"scene":"exec_committee","alt":{"en":"An executive committee room with senior leaders around a long table, a confidential regulator letter projected on screen.","de":"Ein Sitzungssaal des Vorstands mit Führungskräften an einem langen Tisch, ein vertrauliches Aufsichtsbehörden-Schreiben auf dem Bildschirm.","es-ES":"Una sala del comité ejecutivo con altos directivos alrededor de una mesa larga y una carta confidencial del regulador proyectada."}},"roleCaption":{"en":"You brief the exec committee on a regulator inquiry","de":"Sie briefen den Vorstand zu einer Aufsichtsbehörden-Anfrage","es-ES":"Informas al comité ejecutivo sobre una indagación del regulador"},"scenario":{"en":"A regulator has opened a formal inquiry into your company's data-handling practices and requested documents within ten business days. The executive committee is anxious and wants direction. In 60 seconds, brief them on what's happening, what you're doing, and what you need from them.","de":"Eine Aufsichtsbehörde hat eine formelle Untersuchung zu den Datenverarbeitungspraktiken Ihres Unternehmens eingeleitet und Unterlagen binnen zehn Werktagen angefordert. Der Vorstand ist beunruhigt und will Orientierung. Briefen Sie ihn in 60 Sekunden: was passiert, was Sie tun und was Sie von ihm brauchen.","es-ES":"Un regulador ha abierto una investigación formal sobre las prácticas de manejo de datos de tu empresa y ha solicitado documentos en diez días hábiles. El comité ejecutivo está nervioso y quiere dirección. En 60 segundos, infórmales de qué ocurre, qué estás haciendo y qué necesitas de ellos."},"weights":{"content":0.55,"delivery":0.25,"time":0.2},"keyPoints":[{"en":"Describe the inquiry's scope and deadline plainly, without panic","de":"Umfang und Frist der Untersuchung sachlich darstellen, ohne Panik","es-ES":"Describir el alcance y el plazo con claridad, sin alarmismo"},{"en":"Confirm a litigation hold and document-preservation are already in place","de":"Bestätigen, dass Beweissicherung und Dokumentenaufbewahrung laufen","es-ES":"Confirmar que ya hay retención legal y preservación de documentos"},{"en":"Name the response team and outside counsel engaged","de":"Reaktionsteam und externe Kanzlei benennen","es-ES":"Nombrar el equipo de respuesta y el despacho externo contratado"},{"en":"Set the tone: cooperative, accurate, no off-channel discussion","de":"Ton vorgeben: kooperativ, korrekt, keine Kommunikation außerhalb der Kanäle","es-ES":"Marcar el tono: cooperación, exactitud, sin comunicaciones por canales informales"},{"en":"Ask for resource approval and a single point of contact decision","de":"Um Ressourcenfreigabe und Festlegung eines zentralen Ansprechpartners bitten","es-ES":"Pedir aprobación de recursos y designación de un único punto de contacto"}],"rubric":{"content":{"strong":"Clearly frames scope, deadline, preservation steps, team, tone, and a specific ask of the committee.","adequate":"Covers the situation and response but omits one key element such as the ask or the litigation hold.","weak":"Conveys alarm or detail without a plan, or fails to tell leaders what to do."},"delivery":{"strong":"Composed and authoritative; projects control of a tense situation.","adequate":"Mostly steady but some nervous or over-hedged moments.","weak":"Anxious, scattered, or falsely reassuring."},"time":{"strong":"Complete and controlled within 55-65 seconds.","adequate":"Slightly over or under but hits the main points.","weak":"Cut short or sprawling past the limit."}},"modelAnswer":{"en":"Here's where we stand. The regulator opened a formal inquiry into our data-handling and wants documents in ten business days. This is serious but manageable. As of this morning, I've issued a litigation hold, preserved the relevant systems, and engaged outside counsel who've handled this regulator before. We will cooperate fully and accurately. One rule for everyone: no discussion of this outside the response team, nothing in writing off-channel. I need two things from you today: approval for the review resources, and agreement that I am the single point of contact. I'll update you weekly.","de":"Der Stand: Die Behörde hat eine formelle Untersuchung unserer Datenverarbeitung eingeleitet und will Unterlagen binnen zehn Werktagen. Ernst, aber beherrschbar. Seit heute Morgen läuft eine Beweissicherung, die relevanten Systeme sind gesichert, und ich habe eine externe Kanzlei mandatiert, die diese Behörde kennt. Wir kooperieren vollständig und korrekt. Eine Regel für alle: keine Gespräche darüber außerhalb des Teams, nichts schriftlich auf Nebenwegen. Ich brauche heute zwei Dinge: Freigabe der Prüfressourcen und Ihr Einverständnis, dass ich der zentrale Ansprechpartner bin. Ich berichte wöchentlich.","es-ES":"Esta es la situación. El regulador ha abierto una investigación formal sobre nuestro manejo de datos y quiere documentos en diez días hábiles. Es serio, pero manejable. Desde esta mañana he emitido una retención legal, preservado los sistemas relevantes y contratado a un despacho externo que ya conoce a este regulador. Cooperaremos plena y fielmente. Una regla para todos: nada de hablar de esto fuera del equipo, nada por escrito en canales informales. Necesito dos cosas hoy: aprobación de los recursos de revisión y acuerdo en que yo sea el único punto de contacto. Informaré cada semana."}},
  {"id":"LEG-6","type":"conflict","category":"conflict_resolution","department":"legal","difficulty":4,"media":{"scene":"video_call","alt":{"en":"A tense video call with a vendor's executive on screen, contract clauses visible in a shared window.","de":"Ein angespannter Videocall mit einer Führungskraft des Lieferanten auf dem Bildschirm, Vertragsklauseln in einem geteilten Fenster.","es-ES":"Una videollamada tensa con un directivo del proveedor en pantalla y cláusulas del contrato visibles en una ventana compartida."}},"roleCaption":{"en":"A key vendor demands you drop the audit-rights clause","de":"Ein wichtiger Lieferant fordert die Streichung der Prüfrechtsklausel","es-ES":"Un proveedor clave exige que elimines la cláusula de derechos de auditoría"},"scenario":{"en":"A strategic vendor you depend on is refusing to sign unless you remove your right to audit their security and compliance. They imply they'll walk. You cannot give up audit rights given your regulatory obligations. In 60 seconds, hold the line with the vendor's executive while keeping the relationship intact.","de":"Ein strategischer Lieferant, von dem Sie abhängen, unterschreibt nur, wenn Sie Ihr Recht streichen, dessen Sicherheit und Compliance zu prüfen. Er droht implizit mit Abbruch. Sie können auf Prüfrechte wegen regulatorischer Pflichten nicht verzichten. Bleiben Sie in 60 Sekunden standhaft, ohne die Beziehung zu zerstören.","es-ES":"Un proveedor estratégico del que dependes se niega a firmar a menos que elimines tu derecho a auditar su seguridad y cumplimiento. Insinúa que se irá. No puedes renunciar a los derechos de auditoría por tus obligaciones regulatorias. En 60 segundos, mantén la postura con el directivo del proveedor sin romper la relación."},"weights":{"content":0.55,"delivery":0.25,"time":0.2},"keyPoints":[{"en":"Affirm the value of the partnership before stating the constraint","de":"Wert der Partnerschaft betonen, bevor die Bedingung genannt wird","es-ES":"Reafirmar el valor de la colaboración antes de plantear la restricción"},{"en":"Explain audit rights are a regulatory requirement, not a trust issue","de":"Erklären, dass Prüfrechte regulatorisch gefordert sind, kein Misstrauen","es-ES":"Explicar que los derechos de auditoría son una exigencia regulatoria, no desconfianza"},{"en":"Hold the line: the clause cannot be removed","de":"Standhaft bleiben: Die Klausel kann nicht entfallen","es-ES":"Mantener la postura: la cláusula no se puede eliminar"},{"en":"Offer flexibility on scope: notice, frequency, or accepting their SOC 2 report","de":"Flexibilität beim Umfang anbieten: Frist, Häufigkeit oder Anerkennung des SOC-2-Berichts","es-ES":"Ofrecer flexibilidad en el alcance: preaviso, frecuencia o aceptar su informe SOC 2"},{"en":"Signal willingness to escalate to find a mutual solution","de":"Bereitschaft zur Eskalation signalisieren, um eine gemeinsame Lösung zu finden","es-ES":"Mostrar disposición a escalar para hallar una solución mutua"}],"rubric":{"content":{"strong":"Holds firm on the non-removable clause, explains the regulatory basis, and offers concrete scope flexibility to preserve the deal.","adequate":"Maintains the position but with weak rationale or only a vague compromise.","weak":"Either caves on the requirement or refuses rigidly with no path to keep the partner."},"delivery":{"strong":"Warm but unyielding; de-escalates tension while staying firm.","adequate":"Steady but slightly stiff or defensive at moments.","weak":"Aggressive, placating, or visibly rattled by the threat to walk."},"time":{"strong":"Resolves the message within 55-65 seconds.","adequate":"A bit rushed or long but complete.","weak":"Too brief to persuade or runs well over."}},"modelAnswer":{"en":"I value this partnership, and I want to keep building it. But I can't remove the audit right, and I want to be honest about why. This isn't about trusting you; our regulator requires that we be able to verify our critical vendors' controls. If I drop it, I'm out of compliance, not just uncomfortable. So the clause stays. Where I can flex is how it works: thirty days' notice, no more than once a year, and we'll accept your current SOC 2 report in lieu of an on-site audit. Let's get our teams on a call and finalize wording.","de":"Ich schätze diese Partnerschaft und will sie weiter ausbauen. Aber das Prüfrecht kann ich nicht streichen, und ich sage Ihnen offen, warum. Es geht nicht um Vertrauen; unsere Aufsichtsbehörde verlangt, dass wir die Kontrollen kritischer Lieferanten überprüfen können. Streiche ich es, verstoße ich gegen Vorschriften, nicht nur gegen mein Bauchgefühl. Die Klausel bleibt also. Flexibel bin ich beim Wie: 30 Tage Vorlauf, höchstens einmal jährlich, und wir akzeptieren Ihren aktuellen SOC-2-Bericht statt einer Vor-Ort-Prüfung. Lassen Sie unsere Teams telefonieren und den Wortlaut finalisieren.","es-ES":"Valoro esta colaboración y quiero seguir construyéndola. Pero no puedo eliminar el derecho de auditoría, y quiero ser honesto sobre por qué. No es cuestión de confianza; nuestro regulador exige que podamos verificar los controles de nuestros proveedores críticos. Si lo quito, incumplo la normativa, no es solo incomodidad. Así que la cláusula se queda. Donde sí puedo flexibilizar es en el cómo: treinta días de preaviso, una vez al año como máximo, y aceptaremos vuestro informe SOC 2 actual en lugar de una auditoría in situ. Pongamos a nuestros equipos en una llamada y cerremos la redacción."}},
  {"id":"LEG-7","type":"feedback360","category":"feedback_difficult_conversations","department":"legal","difficulty":3,"media":{"scene":"feedback_report","alt":{"en":"A feedback report on screen showing peer comments about a lawyer perceived as a bottleneck and blocker.","de":"Ein Feedback-Bericht auf dem Bildschirm mit Kommentaren, die einen Juristen als Engpass und Blockierer beschreiben.","es-ES":"Un informe de feedback en pantalla con comentarios que describen a un abogado como un cuello de botella y un freno."}},"roleCaption":{"en":"Your 360 says the business sees legal as a blocker","de":"Ihr 360-Feedback: Das Business sieht die Rechtsabteilung als Blockierer","es-ES":"Tu 360 dice que el negocio ve a legal como un freno"},"scenario":{"en":"Your 360-degree feedback just landed. Several business partners describe you and your legal team as a bottleneck who says no and slows deals down. You believe you're protecting the company, but the perception is real. In 60 seconds, respond out loud as if addressing your team about this feedback and how you'll change.","de":"Ihr 360-Grad-Feedback ist da. Mehrere Geschäftspartner beschreiben Sie und Ihr Rechtsteam als Engpass, der Nein sagt und Deals verlangsamt. Sie meinen, Sie schützen das Unternehmen, aber die Wahrnehmung ist real. Antworten Sie in 60 Sekunden laut, als sprächen Sie Ihr Team auf dieses Feedback und Ihren Veränderungswillen an.","es-ES":"Acaba de llegar tu feedback de 360 grados. Varios socios de negocio te describen a ti y a tu equipo legal como un cuello de botella que dice no y ralentiza los acuerdos. Crees que proteges a la empresa, pero la percepción es real. En 60 segundos, responde en voz alta como si te dirigieras a tu equipo sobre este feedback y cómo cambiarás."},"weights":{"content":0.55,"delivery":0.25,"time":0.2},"keyPoints":[{"en":"Accept the feedback without defensiveness or blaming the business","de":"Feedback annehmen, ohne sich zu verteidigen oder das Business zu beschuldigen","es-ES":"Aceptar el feedback sin ponerse a la defensiva ni culpar al negocio"},{"en":"Distinguish protecting the company from being unhelpfully slow","de":"Schutz des Unternehmens von unnötiger Langsamkeit unterscheiden","es-ES":"Distinguir proteger a la empresa de ser innecesariamente lento"},{"en":"Commit to concrete changes: SLAs, risk tiers, default positions","de":"Konkrete Änderungen zusagen: SLAs, Risikostufen, Standardpositionen","es-ES":"Comprometer cambios concretos: SLA, niveles de riesgo, posiciones por defecto"},{"en":"Reframe legal as an enabler that helps the business say yes safely","de":"Recht als Ermöglicher positionieren, der sicheres Ja ermöglicht","es-ES":"Reposicionar legal como facilitador que ayuda al negocio a decir sí con seguridad"},{"en":"Invite the team to own the shift, not just hear an order","de":"Team einladen, den Wandel mitzutragen, nicht nur zu befolgen","es-ES":"Invitar al equipo a apropiarse del cambio, no solo a acatar una orden"}],"rubric":{"content":{"strong":"Owns the perception, separates protection from friction, and commits to specific operational changes while reframing legal as an enabler.","adequate":"Accepts the feedback and offers general intentions but few concrete changes.","weak":"Defensive, dismissive of the business, or vague self-improvement with no plan."},"delivery":{"strong":"Self-aware and motivating; models the openness it asks of the team.","adequate":"Sincere but flat or slightly defensive in spots.","weak":"Defensive, deflated, or performative."},"time":{"strong":"Delivers a complete message within 55-65 seconds.","adequate":"Slightly off-pace but covers the core.","weak":"Truncated or well over time."}},"modelAnswer":{"en":"I read our 360, and I want to own it: the business sees us as a bottleneck, and that feedback is fair. Yes, we protect the company, but protecting it doesn't mean slowing everything down. So we're changing how we work. We'll publish response SLAs, tier matters by real risk so low-risk requests fly through, and write default positions teams can self-serve. Our job is to help the business say yes safely, not just say no. I'd love your ideas on where we add friction. Let's become the team people want to call early, not avoid.","de":"Ich habe unser 360 gelesen und stehe dazu: Das Business sieht uns als Engpass, und das Feedback ist fair. Ja, wir schützen das Unternehmen, aber Schutz heißt nicht, alles auszubremsen. Also ändern wir unsere Arbeitsweise. Wir veröffentlichen Reaktions-SLAs, stufen Fälle nach echtem Risiko ein, damit risikoarme Anfragen durchlaufen, und schreiben Standardpositionen zum Selbstbedienen. Unsere Aufgabe ist, dem Business ein sicheres Ja zu ermöglichen, nicht nur Nein zu sagen. Ich will eure Ideen, wo wir bremsen. Werden wir das Team, das man früh anruft, nicht meidet.","es-ES":"He leído nuestro 360 y quiero asumirlo: el negocio nos ve como un cuello de botella, y ese feedback es justo. Sí, protegemos a la empresa, pero protegerla no significa frenarlo todo. Así que cambiamos cómo trabajamos. Publicaremos SLA de respuesta, clasificaremos los asuntos por riesgo real para que las peticiones de bajo riesgo fluyan, y escribiremos posiciones por defecto de autoservicio. Nuestra labor es ayudar al negocio a decir sí con seguridad, no solo decir no. Quiero vuestras ideas sobre dónde generamos fricción. Seamos el equipo al que llaman pronto, no al que evitan."}},
  {"id":"LEG-8","type":"coaching","category":"self_awareness_development","department":"legal","difficulty":2,"media":{"scene":"coaching_room","alt":{"en":"A quiet coaching room with two chairs, where a junior lawyer sits looking anxious after missing a filing deadline.","de":"Ein ruhiger Coaching-Raum mit zwei Stühlen, in dem eine Nachwuchsjuristin nach einer versäumten Frist nervös wirkt.","es-ES":"Una sala de coaching tranquila con dos sillas, donde un abogado junior se sienta nervioso tras incumplir un plazo de presentación."}},"roleCaption":{"en":"You coach a junior lawyer who missed a filing deadline","de":"Sie coachen eine Nachwuchsjuristin, die eine Frist verpasst hat","es-ES":"Asesoras a un abogado junior que incumplió un plazo"},"scenario":{"en":"A junior lawyer on your team missed a regulatory filing deadline. No lasting harm occurred this time, but it could have been serious. They look frightened. In 60 seconds, coach them: address the miss honestly while keeping them motivated and helping them build a system so it doesn't recur.","de":"Eine Nachwuchsjuristin in Ihrem Team hat eine behördliche Frist versäumt. Diesmal kein bleibender Schaden, aber es hätte ernst sein können. Sie wirkt verängstigt. Coachen Sie sie in 60 Sekunden: das Versäumnis ehrlich ansprechen, sie motiviert halten und ihr helfen, ein System aufzubauen, damit es nicht wieder passiert.","es-ES":"Un abogado junior de tu equipo incumplió un plazo de presentación regulatoria. Esta vez no hubo daño duradero, pero pudo ser grave. Parece asustado. En 60 segundos, asesóralo: aborda el fallo con honestidad manteniéndolo motivado y ayudándolo a crear un sistema para que no se repita."},"weights":{"content":0.55,"delivery":0.25,"time":0.2},"keyPoints":[{"en":"Name the seriousness of a missed deadline without crushing them","de":"Ernst der versäumten Frist benennen, ohne sie zu zermürben","es-ES":"Nombrar la gravedad del plazo incumplido sin hundir al junior"},{"en":"Move quickly from blame to learning and prevention","de":"Schnell von Schuld zu Lernen und Prävention übergehen","es-ES":"Pasar rápido de la culpa al aprendizaje y la prevención"},{"en":"Ask what happened so they diagnose the root cause themselves","de":"Fragen, was passiert ist, damit sie die Ursache selbst erkennt","es-ES":"Preguntar qué pasó para que diagnostique la causa raíz"},{"en":"Co-create a concrete safeguard: a tracked calendar with reminders and a backup","de":"Gemeinsam Schutzmaßnahme schaffen: Kalender mit Erinnerungen und Vertretung","es-ES":"Crear juntos una salvaguarda concreta: calendario con recordatorios y respaldo"},{"en":"Reaffirm confidence and that owning mistakes builds trust","de":"Vertrauen bekräftigen und dass Fehler einzugestehen Vertrauen schafft","es-ES":"Reafirmar la confianza y que asumir errores genera confianza"}],"rubric":{"content":{"strong":"Acknowledges seriousness, draws out the root cause, co-builds a concrete prevention system, and restores confidence.","adequate":"Addresses the miss and offers some fix but is light on root cause or on rebuilding morale.","weak":"Either harsh and demoralizing or so soft it fails to address the real problem."},"delivery":{"strong":"Steady, supportive, and direct; balances candor with care.","adequate":"Generally warm but tips toward lecturing or coddling.","weak":"Cold, harsh, or evasive about the seriousness."},"time":{"strong":"Complete and unhurried within 55-65 seconds.","adequate":"Slightly rushed or long but covers the key beats.","weak":"Too brief to coach or runs well over."}},"modelAnswer":{"en":"Let's talk about the missed filing. I won't pretend it's small: deadlines like that can carry real consequences, and we got lucky this time. But I'm not here to punish you, I'm here to make sure it never happens again. Walk me through what happened. Was it tracking, workload, or no backstop? Whatever it is, let's fix the system, not just promise harder. I want every deadline you own in a shared calendar with two reminders and a named backup. Mistakes you own and fix build my trust. Let's set that up now.","de":"Reden wir über die versäumte Frist. Ich tue nicht so, als wäre das Kleinigkeit: Solche Fristen können echte Folgen haben, und diesmal hatten wir Glück. Aber ich bin nicht hier, um zu bestrafen, sondern um sicherzustellen, dass es nie wieder passiert. Erzähl mir, was passiert ist. Lag's am Tracking, an der Last oder fehlte ein Backup? Was auch immer, wir reparieren das System, nicht nur das Versprechen. Jede Frist gehört in einen geteilten Kalender mit zwei Erinnerungen und einer benannten Vertretung. Fehler, die du einsiehst und behebst, schaffen Vertrauen. Richten wir das jetzt ein.","es-ES":"Hablemos del plazo incumplido. No voy a fingir que es menor: plazos así pueden tener consecuencias reales, y esta vez tuvimos suerte. Pero no estoy aquí para castigarte, sino para asegurar que no vuelva a pasar. Cuéntame qué ocurrió. ¿Fue el seguimiento, la carga de trabajo o la falta de respaldo? Sea lo que sea, arreglemos el sistema, no solo prometamos esforzarnos más. Quiero cada plazo tuyo en un calendario compartido con dos recordatorios y un respaldo nombrado. Los errores que asumes y corriges generan mi confianza. Configurémoslo ahora."}},
  {"id":"LEG-9","type":"situational","category":"strategic_thinking","department":"legal","difficulty":4,"media":{"scene":"boardroom","alt":{"en":"A boardroom with directors seated around a table, a litigation-risk slide and a settlement figure displayed.","de":"Ein Sitzungssaal mit Aufsichtsräten am Tisch, eine Folie zum Prozessrisiko und eine Vergleichssumme angezeigt.","es-ES":"Una sala de juntas con consejeros sentados, una diapositiva de riesgo de litigio y una cifra de acuerdo en pantalla."}},"roleCaption":{"en":"You advise the board: settle or fight the lawsuit","de":"Sie beraten den Aufsichtsrat: Vergleich oder Prozess","es-ES":"Asesoras al consejo: acuerdo o pleito"},"scenario":{"en":"The company faces a major lawsuit. The board must decide whether to settle for a costly but certain sum or fight, with higher legal cost, public exposure, and uncertain odds. The CEO wants your recommendation now. In 60 seconds, advise the board on the litigation risk and what you recommend.","de":"Das Unternehmen steht vor einer großen Klage. Der Aufsichtsrat muss entscheiden: teurer, aber sicherer Vergleich oder Prozess mit höheren Kosten, öffentlicher Aufmerksamkeit und ungewissem Ausgang. Der CEO will jetzt Ihre Empfehlung. Beraten Sie den Aufsichtsrat in 60 Sekunden zum Prozessrisiko und Ihrer Empfehlung.","es-ES":"La empresa afronta una demanda importante. El consejo debe decidir si pactar una suma costosa pero segura o litigar, con mayor coste legal, exposición pública y resultado incierto. El consejero delegado quiere tu recomendación ahora. En 60 segundos, asesora al consejo sobre el riesgo del litigio y qué recomiendas."},"weights":{"content":0.55,"delivery":0.25,"time":0.2},"keyPoints":[{"en":"State the recommendation clearly and up front","de":"Empfehlung klar und vorab aussprechen","es-ES":"Plantear la recomendación con claridad y de entrada"},{"en":"Lay out the realistic odds and exposure range of fighting","de":"Realistische Erfolgsaussichten und Risikospanne des Prozesses darlegen","es-ES":"Exponer las probabilidades realistas y el rango de exposición de litigar"},{"en":"Weigh non-financial factors: reputation, distraction, precedent","de":"Nicht-finanzielle Faktoren abwägen: Reputation, Ablenkung, Präzedenz","es-ES":"Ponderar factores no financieros: reputación, distracción, precedente"},{"en":"Be candid about uncertainty rather than overpromising","de":"Unsicherheit offen benennen statt zu viel zu versprechen","es-ES":"Ser franco sobre la incertidumbre en vez de prometer de más"},{"en":"Frame the decision as the board's, with a clear next step","de":"Entscheidung als die des Aufsichtsrats rahmen, mit klarem nächsten Schritt","es-ES":"Enmarcar la decisión como del consejo, con un siguiente paso claro"}],"rubric":{"content":{"strong":"Gives a clear recommendation backed by realistic odds, exposure, and non-financial factors, while owning the uncertainty.","adequate":"Recommends a path with partial rationale but misses odds, non-financial factors, or candor on risk.","weak":"Hedges with no recommendation or overpromises a result without basis."},"delivery":{"strong":"Confident and measured; the voice of trusted counsel under pressure.","adequate":"Mostly composed but hesitant or over-qualified in places.","weak":"Wavering, evasive, or falsely certain."},"time":{"strong":"Decisive and complete within 55-65 seconds.","adequate":"Slightly off-pace but covers the recommendation and rationale.","weak":"Too thin to advise or overruns badly."}},"modelAnswer":{"en":"My recommendation is to settle, and here's the reasoning. If we fight, I put our odds of winning at roughly fifty-fifty. A loss could cost three to four times the settlement, plus two years of legal spend and public scrutiny of our practices during discovery. The settlement is painful but certain and confidential. Strategically, fighting also risks setting a precedent that invites copycat claims. I won't pretend the outcome is knowable; it isn't. But on balance, certainty and containment beat the gamble. The decision is yours. If you agree, I'll open settlement talks this week.","de":"Meine Empfehlung ist der Vergleich, und hier die Begründung. Bei einem Prozess schätze ich unsere Gewinnchance auf etwa fünfzig zu fünfzig. Eine Niederlage könnte das Drei- bis Vierfache des Vergleichs kosten, plus zwei Jahre Anwaltskosten und öffentliche Prüfung unserer Praktiken in der Beweisaufnahme. Der Vergleich ist schmerzhaft, aber sicher und vertraulich. Strategisch riskiert ein Prozess zudem einen Präzedenzfall, der Nachahmerklagen einlädt. Ich tue nicht so, als sei der Ausgang gewiss; ist er nicht. Aber unterm Strich schlagen Sicherheit und Eindämmung das Risiko. Die Entscheidung liegt bei Ihnen. Stimmen Sie zu, beginne ich diese Woche die Vergleichsgespräche.","es-ES":"Mi recomendación es pactar, y este es el razonamiento. Si litigamos, sitúo nuestras probabilidades de ganar en torno al cincuenta por ciento. Una derrota podría costar tres o cuatro veces el acuerdo, más dos años de gasto legal y escrutinio público de nuestras prácticas durante la fase de prueba. El acuerdo es doloroso pero seguro y confidencial. Estratégicamente, litigar también arriesga sentar un precedente que invite demandas imitadoras. No fingiré que el resultado es previsible; no lo es. Pero, en conjunto, la certeza y la contención superan la apuesta. La decisión es vuestra. Si estáis de acuerdo, abro conversaciones de acuerdo esta semana."}},
];
